import Link from '../../components/Link';
const _annihilation_spectacles = {title: "Annihilation Spectacles", jsx: <><h2 id="magic-wondrous-annihilation_spectacles-annihilation-spectacles">Annihilation Spectacles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 300</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1/4 lb.</p>
<p>Creatures viewed through these darkly tinted glasses sometimes seem to flicker briefly in and out of existence. A transmuter can use these spectacles to spontaneously convert any prepared wizard <Link to="/main/spells_transmutation">transmutation spell</Link> into any other wizard transmutation spell he knows; the desired spell must be of the same level or lower than the prepared spell. Once per day, he may use the spectacles to spontaneously cast <em>disintegrate</em> in place of one of his prepared transmutation wizard spells of 6th level or higher, even if he doesn't know that spell.</p>
<h3 id="magic-wondrous-annihilation_spectacles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/disintegrate">disintegrate</Link>, creator must be a transmuter; <strong>Cost</strong> 12,500 gp</p>
</>};
const _antiquarians_monocle = {title: "Antiquarian's Monocle", jsx: <><h2 id="magic-wondrous-antiquarians_monocle-antiquarians-monocle">Antiquarian's Monocle</h2>
<p><strong>Sources</strong> <Link to="/source/gallows_of_madness">Gallows of Madness pg. 48</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 1,350 gp; <strong>Weight</strong> -</p>
<p>This lens, mounted in a round silver frame, fits snugly in the eye orbit of any Medium or Small user. Three times per day on command, the monocle allows the user to read magical inscriptions (including scrolls) as if affected by <em>read magic.</em></p>
<p>Once per day, by speaking a second command word, the user can activate a 1st-level spell from a scroll even if she doesn't have the spell on her class list or meet the other requirements. Activating a scroll with the monocle is a full-round action (or the spell's casting time, whichever is longer).</p>
<h3 id="magic-wondrous-antiquarians_monocle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Cost</strong> 675 gp</p>
</>};
const _arachnid_goggles = {title: "Arachnid Goggles", jsx: <><h2 id="magic-wondrous-arachnid_goggles-arachnid-goggles">Arachnid Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>This leather band is studded with dozens of faceted crystals of varying size, two of which fit over the eyes. When wearing these goggles, the wearer uses all the crystals as eyes, gaining <Link to="/umr/all_around_vision">all-around vision</Link>.</p>
<h3 id="magic-wondrous-arachnid_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/countless_eyes">countless eyes</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _blind_mans_fold = {title: "Blind Man's Fold", jsx: <><h2 id="magic-wondrous-blind_mans_fold-blind-mans-fold">Blind Man's Fold</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>Fashioned from a scrap of a blind beggar's clothing, a blind man's fold is often used by explorers who must traverse caves inhabited by invisible creatures, or those drawn to sources of light. A blind man's fold fully obscures normal vision while worn, but grants the effects of the Improved Blind-Fight feat. Creatures which are unable to see normally gain no benefit from wearing a blind man's fold.</p>
<h3 id="magic-wondrous-blind_mans_fold-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/improved_blind_fight">Improved Blind-Fight</Link>, <Link to="/spell/darkness">darkness</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _captains_eye_patch = {title: "Captain's Eye Patch", jsx: <><h2 id="magic-wondrous-captains_eye_patch-captains-eye-patch">Captain's Eye Patch</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 25</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 46,000 gp; <strong>Weight</strong> -</p>
<p>This black velvet eye patch is attached to an onyx chain that is worn around the head. The eye patch grants its wearer darkvision with a range of 60 feet. Additionally, as a standard action, the wearer can speak the eye patch's command word to see through powerful magical darkness, such as an area of <Link to="/spell/deeper_darkness">deeper darkness</Link>, for up to 11 minutes per day. This duration need not be used all at once, but it must be used in 1-minute increments. Ending this effect is a free action.</p>
<h3 id="magic-wondrous-captains_eye_patch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 23,000 gp</p>
</>};
const _darklands_goggles = {title: "Darklands Goggles", jsx: <><h2 id="magic-wondrous-darklands_goggles-darklands-goggles">Darklands Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>These goggles' dark lenses are made of round obsidian sheets thin enough to see through. They grant the wearer darkvision 120 ft., as well as a +4 competence bonus on <Link to="/skill/perception">Perception</Link> checks and <Link to="/skill/survival">Survival</Link> checks made to track while underground.</p>
<h3 id="magic-wondrous-darklands_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/terrain_bond">terrain bond</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _deathwatch_eyes = {title: "Deathwatch Eyes", jsx: <><h2 id="magic-wondrous-deathwatch_eyes-deathwatch-eyes">Deathwatch Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 1st<br/><strong>Slot</strong> eyes; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>These blood red crystal lenses fit snugly over the wearer's eyes. The wearer gains the constant effects of the <em>deathwatch</em> spell.</p>
<h3 id="magic-wondrous-deathwatch_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/deathwatch">deathwatch</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _discerning_goggles = {title: "Discerning Goggles", jsx: <><h2 id="magic-wondrous-discerning_goggles-discerning-goggles">Discerning Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 28</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 13,500 gp; <strong>Weight</strong> -</p>
<p>This eyewear consists of two thick, gold-rimmed glass lenses encased in a leather band. When worn over the eyes, a pair of discerning goggles allows you to determine creatures' alignments with a single look. Good creatures appear to faintly glow blue and evil creatures to faintly glow red. Neutral-aligned creatures appear normal, as do creatures under the effect of an <em>undetectable alignment</em> spell or similar effect. These goggles function only during times when you normally would possess sight; for example, they do not work in darkness unless you possess darkvision.</p>
<h3 id="magic-wondrous-discerning_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_evil">detect evil</Link>; <strong>Cost</strong> 6,750 gp</p>
</>};
const _eldritch_scholars_monocle = {title: "Eldritch Scholar's Monocle", jsx: <><h2 id="magic-wondrous-eldritch_scholars_monocle-eldritch-scholars-monocle">Eldritch Scholar's Monocle</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 220</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>This lens, mounted in a round electrum frame, fits snugly over the wearer's eye. Upon donning the monocle, the user sees a swirl of arcane sigils through the lens, but the sensation quickly fades. The monocle allows the user to decipher magical inscriptions, as per <em>read magic.</em></p>
<p>Once worn for 24 consecutive hours, an eldritch scholar's monocle also protects the user from anything dangerous to read or view. While wearing the monocle, whenever the user triggers a curse effect, an effect that causes sanity loss, or a magic trap (such as <Link to="/spell/explosive_runes">explosive runes</Link> or <Link to="/spell/sepia_snake_sigil">sepia snake sigil</Link>) simply by reading or viewing an object, the monocle's glass starts shaking, pulling the wearer's attention away from the dangerous details in the object. This allows the wearer to roll any saving throw against such an effect twice and take the better result. This effect functions only once per day. For the remainder of the day, everything viewed through the lens appears blurred and distorted, and the <em>read magic</em> effect no longer functions.</p>
<h3 id="magic-wondrous-eldritch_scholars_monocle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/augury">augury</Link>, <Link to="/spell/read_magic">read magic</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _eye_of_the_cyclops = {title: "Eye of the Cyclops", jsx: <><h2 id="magic-wondrous-eye_of_the_cyclops-eye-of-the-cyclops">Eye of the Cyclops</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_goblins_1">Pathfinder Goblins #1 pg. 29</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 32,000 gp; <strong>Weight</strong> -</p>
<p>Captured in a battle of wits with a brilliant cyclops by the goblin hero Gribbet, this handsome monocle grants a +4 enhancement bonus to Intelligence. The wearer also understands all written words read through the monocle, as <em>comprehend languages.</em> He further gains a +2 insight bonus on <Link to="/skill/knowledge">Knowledge</Link> checks, and may make Knowledge checks even if untrained.</p>
<h3 id="magic-wondrous-eye_of_the_cyclops-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/foxs_cunning">fox's cunning</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>; <strong>Cost</strong> 16,000 gp</p>
</>};
const _eye_patch_of_infamy_half_orc = {title: "Eye Patch of Infamy (Half-Orc)", jsx: <><h2 id="magic-wondrous-eye_patch_of_infamy_half_orc-eye-patch-of-infamy-half-orc">Eye Patch of Infamy (Half-Orc)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 231</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This green leather eye patch allows a half-orc wearer to use the <Link to="/skill/intimidate">Intimidate</Link> skill from 30 feet farther away. Whenever the wearer successfully intimidates a target into giving aid, the duration of the change in disposition is doubled. The wearer gains a +5 competence bonus on Intimidate checks to <Link to="/rule/generate_capital">generate capital</Link> and to coerce others into giving aid.</p>
<h3 id="magic-wondrous-eye_patch_of_infamy_half_orc-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, creator must be a half-orc; <strong>Cost</strong> 5,000 gp</p>
</>};
const _eyes_of_blindness = {title: "Eyes of Blindness", jsx: <><h2 id="magic-wondrous-eyes_of_blindness-eyes-of-blindness">Eyes of Blindness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 345</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Weight</strong> -</p>
<p>These normal-looking glasses appear harmless and nondescript. When they are worn, the wearer becomes <Link to="/misc/blinded">blinded</Link> as if subject to the <Link to="/spell/blindness_deafness">blindness/deafness</Link> spell (no saving throw).</p>
<h3 id="magic-wondrous-eyes_of_blindness-construction">Construction</h3>
<p><strong>Requirements</strong> any glasses or lenses; <strong>Cost</strong> -</p>
</>};
const _eyes_of_charming = {title: "Eyes of Charming", jsx: <><h2 id="magic-wondrous-eyes_of_charming-eyes-of-charming">Eyes of Charming</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 512</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 56,000 gp; <strong>Weight</strong> -</p>
<p>These two crystal lenses fit over the user's eyes. The wearer is able to use <em>charm person</em> (one target per round) merely by meeting a target's gaze. Those targets failing a DC 16 Will save are charmed as per the spell. Both lenses must be worn for the magic item to take effect.</p>
<h3 id="magic-wondrous-eyes_of_charming-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/charm_person">charm person</Link>; <strong>Cost</strong> 28,000 gp</p>
</>};
const _eyes_of_doom = {title: "Eyes of Doom", jsx: <><h2 id="magic-wondrous-eyes_of_doom-eyes-of-doom">Eyes of Doom</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 512</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> -</p>
<p>These crystal lenses fit over the user's eyes, enabling him to cast <em>doom</em> upon those around him (one target per round) as a <Link to="/umr/gaze">gaze</Link> attack, except that the wearer must take a standard action, and those merely looking at the wearer are not affected. Those failing a DC 11 Will save are affected as by the <em>doom</em> spell. The wearer also gains the additional power of a continual <em>deathwatch</em> effect and can use <em>fear</em> (Will DC 16 partial) as a normal gaze attack once per week. Both lenses must be worn for the magic item to take effect.</p>
<h3 id="magic-wondrous-eyes_of_doom-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/doom">doom</Link>, <Link to="/spell/deathwatch">deathwatch</Link>, <Link to="/spell/fear">fear</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _eyes_of_embersight = {title: "Eyes of Embersight", jsx: <><h2 id="magic-wondrous-eyes_of_embersight-eyes-of-embersight">Eyes of Embersight</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 93</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>These two transparent red crystal lenses fit directly over the wearer's eyes. On command, the wearer can speak a prayer to <Link to="/faith/asmodeus">Asmodeus</Link> as a standard action to be granted darkvision with a range of 60 feet; within that range, the wearer can see in darkness of any kind, including that created by <Link to="/spell/deeper_darkness">deeper darkness</Link>. While the lenses are activated, they take on the appearance of red-hot, glowing embers, making them extremely distinctive and foiling <Link to="/skill/disguise">Disguise</Link> checks unless the wearer is disguised as someone or something with glowing red eyes.</p>
<p>The eyes of embersight work for a total of 9 minutes each day. These minutes need not be consecutive, but the eyes must be used in 1-minute increments. Both lenses must be worn by the same wearer for the magic item to take effect.</p>
<h3 id="magic-wondrous-eyes_of_embersight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _eyes_of_eyebite = {title: "Eyes of Eyebite", jsx: <><h2 id="magic-wondrous-eyes_of_eyebite-eyes-of-eyebite">Eyes of Eyebite</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 224</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>These glasses look like golden teeth holding a pair of greentinted lenses. The wearer may use <em>eyebite</em> 11 times per day on command, affecting one target for each use of the spell. The wearer does not need to use these rounds consecutively, but each activation is a standard action (unlike the spell, in which targeting a new foe is a swift action). If the wearer removes the glasses, the <em>eyebite</em> effects immediately end.</p>
<h3 id="magic-wondrous-eyes_of_eyebite-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eyebite">eyebite</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _eyes_of_keen_sight = {title: "Eyes of Keen Sight", jsx: <><h2 id="magic-wondrous-eyes_of_keen_sight-eyes-of-keen-sight">Eyes of Keen Sight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> eyes; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>These clear crystals fit over the wearer's eyes. They grant the wearer a +2 competence bonus on <Link to="/skill/perception">Perception</Link> checks, and the wearer gains low-light vision. If the wearer has low-light vision already, these lenses double the distance the wearer can see with this vision.</p>
<h3 id="magic-wondrous-eyes_of_keen_sight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/keen_senses">keen senses</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _eyes_of_mind_reading_android = {title: "Eyes of Mind Reading (Android)", jsx: <><h2 id="magic-wondrous-eyes_of_mind_reading_android-eyes-of-mind-reading-android">Eyes of Mind Reading (Android)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 231</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>These large goggles feature adjustable lenses. When calibrated correctly, they sense the thoughts of a particular creature and send them into the wearer's mind. If the wearer spends 3 rounds studying a creature, spending a standard action each round to calibrate the lenses, she may scan a target's surface thoughts as if she had spent 3 rounds studying the target with <em>detect thoughts.</em> The target can attempt a DC 13 Will save to negate the effect. The wearer must spend three consecutive standard actions each time she wishes to read the mind of a new creature.</p>
<p>If the wearer is an <Link to="/race/android">android</Link>, he can spend a nanite surge to immediately detect surface thoughts instead of concentrating for 3 rounds.</p>
<h3 id="magic-wondrous-eyes_of_mind_reading_android-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, creator must be an android; <strong>Cost</strong> 5,500 gp</p>
</>};
const _eyes_of_the_damned = {title: "Eyes of the Damned", jsx: <><h2 id="magic-wondrous-eyes_of_the_damned-eyes-of-the-damned">Eyes of the Damned</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 93</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>These two clear crystal lenses fit directly over the wearer's eyes. When the wearer activates the lenses by speaking a prayer to <Link to="/faith/asmodeus">Asmodeus</Link> as a standard action, her eyes appear to be replaced by orbs of impenetrable blackness. She gains a <Link to="/umr/gaze">gaze</Link> attack until the beginning of her next turn. The wearer can choose a creature within 30 feet on which to gaze as part of the action of activating the lenses. The target creature must succeed at a DC 14 Will save or be affected as per <em>vision of Hell</em> for 5 minutes, except that the effect is a phantasm, rather than glamer, and it follows the affected creature rather than affecting an area. An affected creature continues to see the terrifying hellscape for the duration, regardless of the creature's location.</p>
<p>As with <em>vision of Hell,</em> devils and all lawful evil creatures are immune to the effect caused by this item. The eyes of the damned can be activated up to three times per day. Both lenses must be worn by the same wearer for the magic item to take effect.</p>
<h3 id="magic-wondrous-eyes_of_the_damned-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/vision_of_hell">vision of Hell</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _eyes_of_the_dragon = {title: "Eyes of the Dragon", jsx: <><h2 id="magic-wondrous-eyes_of_the_dragon-eyes-of-the-dragon">Eyes of the Dragon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 110,000 gp; <strong>Weight</strong> -</p>
<p>These tigereye gems fit over and then meld into the eyes, transforming the wearer's eyes into something slitted and draconic. These eyes grant the wearer darkvision 120 ft. and <Link to="/umr/blindsense">blindsense</Link> 60 ft. The wearer sees four times as well as a human in <Link to="/rule/dim_light">dim light</Link> and twice as well in normal light.</p>
<h3 id="magic-wondrous-eyes_of_the_dragon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/form_of_the_dragon_iii">form of the dragon III</Link>; <strong>Cost</strong> 55,000 gp</p>
</>};
const _eyes_of_the_eagle = {title: "Eyes of the Eagle", jsx: <><h2 id="magic-wondrous-eyes_of_the_eagle-eyes-of-the-eagle">Eyes of the Eagle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 512</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>These lenses are made of special crystal and fit over the eyes of the wearer. They grant a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks. Both lenses must be worn to gain the benefit. Wearing only one causes a character to become dizzy and <Link to="/misc/stunned">stunned</Link> for 1 round.</p>
<h3 id="magic-wondrous-eyes_of_the_eagle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _eyes_of_the_liar = {title: "Eyes of the Liar", jsx: <><h2 id="magic-wondrous-eyes_of_the_liar-eyes-of-the-liar">Eyes of the Liar</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>These smoked crystal lenses hide the wearer's thoughts and intents from the prying minds of others. They grant the wearer a +5 competence bonus on <Link to="/skill/bluff">Bluff</Link> checks and immunity to <Link to="/spell/detect_thoughts">detect thoughts</Link>. Both lenses must be worn for the magic item to function.</p>
<h3 id="magic-wondrous-eyes_of_the_liar-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/nondetection">nondetection</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _eyes_of_the_owl = {title: "Eyes of the Owl", jsx: <><h2 id="magic-wondrous-eyes_of_the_owl-eyes-of-the-owl">Eyes of the Owl</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 52</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>These magical goggles are decorated with owl motifs, including clusters of feathers over the eyes. The wearer gains low-light vision.</p>
<h3 id="magic-wondrous-eyes_of_the_owl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_i">beast shape I</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _goggles_of_brilliant_light = {title: "Goggles of Brilliant Light", jsx: <><h2 id="magic-wondrous-goggles_of_brilliant_light-goggles-of-brilliant-light">Goggles of Brilliant Light</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 8,800 gp; <strong>Weight</strong> -</p>
<p>These sturdy goggles have a mirror sheen on the outside of their lenses, a wrapping of leather holding them snugly in place. This tint blocks a considerable amount of natural light. Twice per day, the goggles' wearer can emit bright light on command to a range of 30 feet. Any creature within that area must succeed at a DC 13 Fortitude saving throw or be <Link to="/misc/blinded">blinded</Link> for 1 hour. In addition, the wearer also gains a +2 resistance bonus on saving throws against visual effects.</p>
<h3 id="magic-wondrous-goggles_of_brilliant_light-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/scorching_ray">scorching ray</Link>; <strong>Cost</strong> 4,400 gp</p>
</>};
const _goggles_of_elvenkind = {title: "Goggles of Elvenkind", jsx: <><h2 id="magic-wondrous-goggles_of_elvenkind-goggles-of-elvenkind">Goggles of Elvenkind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 225</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>These simple goggles, made of two emeralds attached to a twin frame, grant the wearer low-light vision and a +5 compentence bonus on <Link to="/skill/spellcraft">Spellcraft</Link> checks to identify magic auras and items. If the wearer already has low-light vision, it grants the wearer double the normal range for low-light vision.</p>
<h3 id="magic-wondrous-goggles_of_elvenkind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_ii">beast shape II</Link>, <Link to="/spell/guidance">guidance</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _goggles_of_minute_seeing = {title: "Goggles of Minute Seeing", jsx: <><h2 id="magic-wondrous-goggles_of_minute_seeing-goggles-of-minute-seeing">Goggles of Minute Seeing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 515</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>The lenses of this item are made of special crystal, its band woven with tiny patterns of metallic thread almost invisible to the naked eye. When placed over the eyes of the wearer, the lenses enable her to see much better than normal at distances of 1 foot or less, granting her a +5 competence bonus on <Link to="/skill/disable_device">Disable Device</Link> checks. Both lenses must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-goggles_of_minute_seeing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _goggles_of_night = {title: "Goggles of Night", jsx: <><h2 id="magic-wondrous-goggles_of_night-goggles-of-night">Goggles of Night</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 515</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>The lenses of this item are made of violet crystal. Even though the lenses are opaque, when placed over the eyes of the wearer, they enable him to see normally and also grant him 60-foot darkvision.</p>
<p>Both lenses must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-goggles_of_night-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkvision">darkvision</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _inquisitors_monocle = {title: "Inquisitor's Monocle", jsx: <><h2 id="magic-wondrous-inquisitors_monocle-inquisitors-monocle">Inquisitor's Monocle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 6,800 gp; <strong>Weight</strong> -</p>
<p>The thick glass lens of this golden-framed monocle is attached to the wearer by a weighty chain. This monocle helps draw out the truth of things, and was originally created to aid in the investigation of crimes and the questioning of witnesses. Twice per day on command, it can create a <em>zone of truth,</em> as per the spell. In addition, this monocle grants its wearer a +5 competence bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks. Though it fits over only one of the wearer's eyes, the item takes up the entire eyes slot.</p>
<h3 id="magic-wondrous-inquisitors_monocle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/zone_of_truth">zone of truth</Link>; <strong>Cost</strong> 3,400 gp</p>
</>};
const _kinsight_goggles = {title: "Kinsight Goggles", jsx: <><h2 id="magic-wondrous-kinsight_goggles-kinsight-goggles">Kinsight Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 2nd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>Kinsight goggles are in fact two separate crystal monocles, linked together with a simple silver clasp that allows them to both be worn at once like pince-nez spectacles. The left and right halves may be separated and worn individually, allowing two people to see through one another's eyes. When separated, the wearer of either half of the goggles may speak a command word to see through the lens of the other half, so long as the halves of the goggles remain within 500 feet of one another. When the two lenses are attached and worn as one item, they offer no magical benefit - just some minor magnification.</p>
<h3 id="magic-wondrous-kinsight_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/share_senses">share senses</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _lenses_of_darkness = {title: "Lenses of Darkness", jsx: <><h2 id="magic-wondrous-lenses_of_darkness-lenses-of-darkness">Lenses of Darkness</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 100</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>Crafted from a dark-colored crystalline material and infused with magical darkness, these lenses fit over the wearer's eyes. When worn by a creature with <Link to="/umr/light_sensitivity">light sensitivity</Link> or <Link to="/umr/light_blindness">light blindness</Link>, these lenses protect the wearer against the effect of sunlight, the <Link to="/spell/daylight">daylight</Link> spell, or similar light effects. Both lenses must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-lenses_of_darkness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkness">darkness</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _lenses_of_detection = {title: "Lenses of Detection", jsx: <><h2 id="magic-wondrous-lenses_of_detection-lenses-of-detection">Lenses of Detection</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 9th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These circular prisms let their wearer detect minute details, gaining a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks. It also aids in tracking, adding a +5 competence bonus on <Link to="/skill/survival">Survival</Link> checks when tracking.</p>
<h3 id="magic-wondrous-lenses_of_detection-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _lenses_of_figment_piercing = {title: "Lenses of Figment Piercing", jsx: <><h2 id="magic-wondrous-lenses_of_figment_piercing-lenses-of-figment-piercing">Lenses of Figment Piercing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>When the wearer first sees an illusion effect with the figment subschool with a visual element, and that figment allows a saving throw, she can immediately make any allowed saving throw to realize the image is illusory instead of waiting to interact with it. This has no effect on illusions of other subschools or on illusions that do not normally allow a saving throw. If the wearer fails to disbelieve the illusion and later interacts with it in such a way as to qualify normally for a saving throw to disbelieve, she gains a +4 competence bonus on this saving throw.</p>
<h3 id="magic-wondrous-lenses_of_figment_piercing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _lenses_of_situational_sight = {title: "Lenses of Situational Sight", jsx: <><h2 id="magic-wondrous-lenses_of_situational_sight-lenses-of-situational-sight">Lenses of Situational Sight</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 25</Link><br/><strong>Aura</strong> moderate divination and transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These wire spectacles are fitted with several ground-crystal filters on hinged arms, any combination of which can be moved in front of or away from the lenses as a standard action (one, two, or all three lenses may be positioned at the same time with one action). Each filter grants a specific sense to the wearer when it is placed before one of the lenses. Each set of filters can be used for 10 minutes in 1-minute increments before losing its magical properties. The three sets of lenses are as follows.</p>
<p><strong className="hl">Green Lenses:</strong> Grant the wearer the benefits of <Link to="/spell/detect_magic">detect magic</Link>. The wearer doesn't need to concentrate to gain the benefits of the spell as long as a source of magic remains in her line of sight for the appropriate number of rounds.</p>
<p><strong className="hl">Pink Lenses:</strong> Grant the wearer the benefits of <em>see invisibility.</em></p>
<p><strong className="hl">Purple Lenses:</strong> Grant the wearer darkvision out to a distance of 60 feet. If the wearer already has darkvision, the range of her darkvision increases by 60 feet while she uses these filters.</p>
<h3 id="magic-wondrous-lenses_of_situational_sight-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_sight">arcane sight</Link>, <Link to="/spell/darkvision">darkvision</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _lenses_of_the_bully = {title: "Lenses of the Bully", jsx: <><h2 id="magic-wondrous-lenses_of_the_bully-lenses-of-the-bully">Lenses of the Bully</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook pg. 31</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> -</p>
<p>Commonly used by thugs, these dark-tinted lenses make the wearer appear threatening. The wearer gains a +2 competence bonus on <Link to="/skill/intimidate">Intimidate</Link> checks. Intelligent creatures find the wearer hard to read; the wearer is treated as if affected by a constant <em>undetectable alignment</em> spell, making her true motives difficult to ascertain.</p>
<h3 id="magic-wondrous-lenses_of_the_bully-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/undetectable_alignment">undetectable alignment</Link>; <strong>Cost</strong> 6,250 gp</p>
</>};
const _lenses_of_the_predators_gaze = {title: "Lenses of the Predator's Gaze", jsx: <><h2 id="magic-wondrous-lenses_of_the_predators_gaze-lenses-of-the-predators-gaze">Lenses of the Predator's Gaze</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 232</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>These amber lenses are shaped to look like the eyes of a cat. As a standard action, the wearer can use these lenses to target a single creature that he can see. When he does, as long as the target is not already the subject of the wearer's studied target class feature, the wearer gains a +1 bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against that creature, along with a +1 bonus on weapon attack rolls and damage rolls against it as if he had the studied target class feature.</p>
<p>If the wearer has the <Link to="/class/slayer">studied target</Link> class feature, he can instead use the magic of these lenses as a free action when designating the subject of his studied target to increase his effective slayer level by 5 for the purposes of the studied target class feature.</p>
<p>The wearer can gain these effects for up to 10 rounds per day, but the rounds don't need to be consecutive.</p>
<h3 id="magic-wondrous-lenses_of_the_predators_gaze-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have the studied target class feature; <strong>Cost</strong> 4,000 gp</p>
</>};
const _life_reading_eyes = {title: "Life-Reading Eyes", jsx: <><h2 id="magic-wondrous-life_reading_eyes-life-reading-eyes">Life-Reading Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 29</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>Favored by doctors and torturers alike - especially the paincrafters of Nidal - these jet-black spectacles fully obscure the eyes of the wearer while granting her the ability to peer at the auras of other creatures. The wearer can read the emotion and health auras of any creature as per <em>analyze aura</em> while the spectacles are worn, but can perceive only those auras.</p>
<h3 id="magic-wondrous-life_reading_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/analyze_aura">analyze aura</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _mariners_eye_patch = {title: "Mariner's Eye Patch", jsx: <><h2 id="magic-wondrous-mariners_eye_patch-mariners-eye-patch">Mariner's Eye Patch</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_59_the_price_of_infamy">Pathfinder #59: The Price of Infamy pg. 60</Link><br/><strong>Aura</strong> faint evocation and divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> -</p>
<p>This pirate's eye patch typically features at least one jewel set into a leather patch. Upon uttering a command word as a standard action, the eye patch allows the wearer to use the following abilities once per day each: <em>comprehend languages, scorching ray,</em> and <em>see invisibility.</em></p>
<p>The mariner's eye patch originally appeared on pg. 73 of Necromancer Games' Dead Man's Chest.</p>
<h3 id="magic-wondrous-mariners_eye_patch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/scorching_ray">scorching ray</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _markers_monocle = {title: "Marker's Monocle", jsx: <><h2 id="magic-wondrous-markers_monocle-markers-monocle">Marker's Monocle</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 15</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 5,600 gp; <strong>Weight</strong> -</p>
<p>A solid gold band encircles this intricate convex glass lens. Three times per day as a standard action, the wearer can attempt an <Link to="/skill/appraise">Appraise</Link> check against a creature within 60 feet (DC = 10 + target's Hit Dice + target's Wisdom bonus). With a successful check, the wearer knows the amount of currency the creature is carrying, as well as the number of valuable objects (with a price greater than 20 gp) the target carries (though the wearer doesn't know which items qualify, or the exact value of the objects).</p>
<p>In addition, once per day, the wearer of a marker's monocle can mark one creature with a melee touch attack, allowing up to 3 allies within 30 feet to track the marked creature for 30 minutes, as if the wearer's allies had the <Link to="/umr/scent">scent</Link> ability.</p>
<h3 id="magic-wondrous-markers_monocle-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/locate_object">locate object</Link>, <Link to="/spell/scent_trail">scent trail</Link>; <strong>Cost</strong> 2,800 gp</p>
</>};
const _mask_of_stolen_identities_gillman = {title: "Mask of Stolen Identities (Gillman)", jsx: <><h2 id="magic-wondrous-mask_of_stolen_identities_gillman-mask-of-stolen-identities-gillman">Mask of Stolen Identities (Gillman)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 233</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This simple, pale porcelain mask has large, circular eye-holes. Twice per day, the wearer can speak a command word and make a touch attack against a humanoid creature as a free action. If he hits, the mask alters the wearer's appearance to match the creature touched as per <em>alter self.</em> If the touch misses, the activation is wasted. Unlike a typical polymorph effect, the disguise is a good likeness of the specific individual and grants a +10 bonus on <Link to="/skill/disguise">Disguise</Link> checks to pass as that individual. The mask melds into the wearer's face, leaving only an extremely fine seam that can be noticed with a successful <Link to="/skill/perception">Perception</Link> check opposed by the user's Disguise check. The effect lasts until the wearer removes the mask or uses it to assume a new form.</p>
<p>If the wearer is a <Link to="/race/gillman">gillman</Link>, he can concentrate on one simple question that could be answered in 25 words or fewer when he activates the mask. If he does so, he learns what the target thinks is the question's answer when the touch attack hits, unless the target succeeds at a DC 17 Will saving throw.</p>
<h3 id="magic-wondrous-mask_of_stolen_identities_gillman-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/alter_self">alter self</Link>, <Link to="/spell/detect_thoughts">detect thoughts</Link>, creator must be a gillman; <strong>Cost</strong> 10,000 gp</p>
</>};
const _mindmasters_eyes = {title: "Mindmaster's Eyes", jsx: <><h2 id="magic-wondrous-mindmasters_eyes-mindmasters-eyes">Mindmaster's Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 95,000 gp; <strong>Weight</strong> -</p>
<p>This pair of thin and faceted ruby crystals fit over the wearer's eyes. On command, the wearer can use <em>charm monster</em> (Will DC 19 to negate), or once per day the wearer can use <em>dominate person</em> (Will DC 20 to negate) instead.</p>
<h3 id="magic-wondrous-mindmasters_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_monster">charm monster</Link>, <Link to="/spell/dominate_person">dominate person</Link>; <strong>Cost</strong> 47,500 gp</p>
</>};
const _monocle_of_flawlessness = {title: "Monocle of Flawlessness", jsx: <><h2 id="magic-wondrous-monocle_of_flawlessness-monocle-of-flawlessness">Monocle of Flawlessness</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 249</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> eyes; <strong>Price</strong> 8,750 gp; <strong>Weight</strong> -</p>
<p>With a monocle of flawlessness placed over her eye, an artist or artisan is able to achieve consistent excellence, as its faceted lenses magnify and reveal imperfections that she can correct. The wearer of a monocle of flawlessness gains a +5 competence bonus on checks with any <Link to="/skill/craft">Craft</Link> skill in which she is trained. The wearer can also create masterwork components in half the normal amount of time (when crafting an item, only the time to craft the masterwork component of the item is halved). The monocle's wearer also gains a +5 competence bonus on <Link to="/skill/linguistics">Linguistics</Link> checks to spot forgeries and <Link to="/skill/perception">Perception</Link> checks to see through disguises. The monocle further grants its wearer a +2 competence bonus on saving throws to disbelieve illusions, due to her sublime attention to detail.</p>
<h3 id="magic-wondrous-monocle_of_flawlessness-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/crafters_fortune">crafter's fortune</Link>; <strong>Cost</strong> 4,375 gp</p>
</>};
const _monocle_of_the_investigator = {title: "Monocle of the Investigator", jsx: <><h2 id="magic-wondrous-monocle_of_the_investigator-monocle-of-the-investigator">Monocle of the Investigator</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 226</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 66,000 gp; <strong>Weight</strong> -</p>
<p>This crystal lens fits over a single eye but takes up the entire eyes slot. Once per day, the wearer is able to gaze at a 10-foot-by-10-foot area and see exactly what occurred in that area during the past 24 hours. The vision of what occurred in the specified area comes to the user in a single minute of observation; if that minute is interrupted, the wearer must use the monocle again to get the full observation. All the visual details of the observed events are clear and memorable to the user, no matter how obscure. The monocle does not, however, provide any insight into the observed events besides what can be visually seen. Observed conversations cannot be heard, for example.</p>
<h3 id="magic-wondrous-monocle_of_the_investigator-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/legend_lore">legend lore</Link>, <Link to="/spell/vision">vision</Link>; <strong>Cost</strong> 33,000 gp</p>
</>};
const _monocle_of_unveiled_auras = {title: "Monocle of Unveiled Auras", jsx: <><h2 id="magic-wondrous-monocle_of_unveiled_auras-monocle-of-unveiled-auras">Monocle of Unveiled Auras</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 154</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 12,700 gp; <strong>Weight</strong> -</p>
<p>The wearer of this crystal monocle gains the ability to use <em>detect chaos, detect evil, detect good, detect magic,</em> or <em>detect law,</em> each at will for as long as he concentrates, but only one at a time. Any caster level checks to penetrate magical protections receive a +5 bonus, and use the higher of the item's caster level or the wearer's character level. The wearer can expend one use of mythic power to gain the benefits of <em>arcane sight</em> and <em>see invisibility</em> for 1 hour, or until the monocle is removed.</p>
<h3 id="magic-wondrous-monocle_of_unveiled_auras-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/arcane_sight">arcane sight</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>, and any one of the following: <Link to="/spell/detect_chaos">detect chaos</Link>, <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_good">detect good</Link>, <Link to="/spell/detect_law">detect law</Link>, or <Link to="/spell/detect_magic">detect magic</Link>; <strong>Cost</strong> 6,350 gp</p>
</>};
const _patternward_spectacles = {title: "Patternward Spectacles", jsx: <><h2 id="magic-wondrous-patternward_spectacles-patternward-spectacles">Patternward Spectacles</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 62</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 750 gp; <strong>Weight</strong> 1 lb.</p>
<p>These spectacles fit firmly over eyes and are held in place by two crystalline stems. The lenses are initially clear and don't hinder the wearer's vision. When the wearer is targeted with an illusion spell or spell-like ability of the pattern subschool (such as <Link to="/spell/color_spray">color spray</Link>), the spectacles absorb the magic and darken, protecting the wearer from the pattern effect. Once the spectacles absorb a spell and become opaque, the wearer becomes <Link to="/misc/blinded">blinded</Link> until the spectacles are removed (a swift action). Patternward spectacles protect against spells or spell-like abilities of only 3rd level or lower; higher-level effects affect the wearer as normal. Once the spectacles absorb an effect, they lose their magic.</p>
<h3 id="magic-wondrous-patternward_spectacles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/lesser_globe_of_invulnerability">lesser globe of invulnerability</Link>; <strong>Cost</strong> 375 gp</p>
</>};
const _physicians_spectacles = {title: "Physician's Spectacles", jsx: <><h2 id="magic-wondrous-physicians_spectacles-physicians-spectacles">Physician's Spectacles</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 233</Link><br/><strong>Aura</strong> faint conjuration and divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 4,900 gp; <strong>Weight</strong> -</p>
<p>These nondescript, brass-rimmed spectacles have green-tinted lenses and are favored by practicing doctors and adventurers alike. When worn, they grant the wearer a constant awareness of poisons and diseases as the <em>detect poison</em> and <em>diagnose disease</em> spells. Also, once per day on command the wearer can touch a single creature to use <em>delay poison</em> on that creature.</p>
<h3 id="magic-wondrous-physicians_spectacles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/delay_poison">delay poison</Link>, <Link to="/spell/detect_poison">detect poison</Link>, <Link to="/spell/diagnose_disease">diagnose disease</Link>; <strong>Cost</strong> 2,450 gp</p>
</>};
const _pirate_lords_patch = {title: "Pirate Lord's Patch", jsx: <><h2 id="magic-wondrous-pirate_lords_patch-pirate-lords-patch">Pirate Lord's Patch</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 189</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> -</p>
<p>This eye patch is woven entirely from gold cloth and features a skull and crossbones embroidered in black stitching. A pair of small sapphires is sewn into the cloth within the skull's eye sockets, making them appear as gleaming pinpricks of blue light. The wearer can see as if the eye patch were not there.</p>
<p>The wearer gains a +2 competence bonus on Appraise and Intimidate checks. Once per day, the wearer can activate the patch in order to gain the benefits of <em>see invisibility</em> for 5 minutes. Additionally, once per day, he can activate the patch in order to see through solid objects for 1 minute, as though with a <Link to="/magic-ring/ring_of_x_ray_vision">ring of x-ray vision</Link>.</p>
<h3 id="magic-wondrous-pirate_lords_patch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/locate_object">locate object</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _pirates_eye_patch = {title: "Pirate's Eye Patch", jsx: <><h2 id="magic-wondrous-pirates_eye_patch-pirates-eye-patch">Pirate's Eye Patch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 2nd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 2,600 gp; <strong>Weight</strong> -</p>
<p>This black silk eye patch is adorned by a skull and crossbones worked in silver thread. The wearer of this patch gains a +2 competence bonus on <Link to="/skill/swim">Swim</Link> and <Link to="/skill/climb">Climb</Link> checks. In addition, once per day, the wearer of this eye patch can gain the effects of either <em>touch of the sea</em> or <em>expeditious retreat</em> on command (wearer's choice).</p>
<h3 id="magic-wondrous-pirates_eye_patch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>; <strong>Cost</strong> 1,300 gp</p>
</>};
const _rainbow_lenses = {title: "Rainbow Lenses", jsx: <><h2 id="magic-wondrous-rainbow_lenses-rainbow-lenses">Rainbow Lenses</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 21,000 gp; <strong>Weight</strong> -</p>
<p>These lenses interfere with the wearer's ability to see color, and everything appears in shades of black and white, as if the wearer were using darkvision. Once per day the wearer can use <em>color spray, hypnotic pattern,</em> and <em>rainbow pattern.</em></p>
<h3 id="magic-wondrous-rainbow_lenses-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/color_spray">color spray</Link>, <Link to="/spell/hypnotic_pattern">hypnotic pattern</Link>, <Link to="/spell/rainbow_pattern">rainbow pattern</Link>; <strong>Cost</strong> 10,500 gp</p>
</>};
const _saboteurs_goggles = {title: "Saboteur's Goggles", jsx: <><h2 id="magic-wondrous-saboteurs_goggles-saboteurs-goggles">Saboteur's Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 234</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>These goggles are fitted with crimson lenses surrounded by thick, round brass frames and secured with a leather strap. Three times per day, the wearer can use <em>murderous command</em> as a <Link to="/umr/gaze">gaze</Link> attack (Will DC 16 negates).</p>
<h3 id="magic-wondrous-saboteurs_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/heighten_spell">Heighten Spell</Link>, <Link to="/spell/murderous_command">murderous command</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _sea_tyrants_patch = {title: "Sea Tyrant's Patch", jsx: <><h2 id="magic-wondrous-sea_tyrants_patch-sea-tyrants-patch">Sea Tyrant's Patch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> strong enchantment; <strong>CL</strong> 15th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 70,000 gp; <strong>Weight</strong> -</p>
<p>This ornate silk eye patch is embroidered with gold thread and studded with pearls in a pattern representing a whirlpool. The wearer of this item, which is a favorite patch of ruthless or particularly driven pirate captains, is constantly affected as if subject to the <em>touch of the sea</em> and <em>water breathing</em> spells. Furthermore, once per day on command, the wearer can use <em>mass charm monster,</em> as per the spell.</p>
<h3 id="magic-wondrous-sea_tyrants_patch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mass_charm_monster">mass charm monster</Link>, <Link to="/spell/touch_of_the_sea">touch of the sea</Link>, <Link to="/spell/water_breathing">water breathing</Link>; <strong>Cost</strong> 35,000 gp</p>
</>};
const _sniper_goggles = {title: "Sniper Goggles", jsx: <><h2 id="magic-wondrous-sniper_goggles-sniper-goggles">Sniper Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 309</Link><br/><strong>Aura</strong> faint divination (normal), moderate divination (greater); <strong>CL</strong> 5th (normal), 8th (greater)<br/><strong>Slot</strong> eyes; <strong>Price</strong> 20,000 gp (normal), 50,000 gp (greater); <strong>Weight</strong> 1 lb. (normal), &mdash; (greater)</p>
<p>The leather strap attached to these bulbous lenses allows their wearer to fit them to his head. The wearer of these goggles can make ranged <Link to="/ability/sneak_attack">sneak attacks</Link> from any distance instead of the normal 30 feet. When making ranged sneak attacks within 30 feet, the wearer gains a +2 circumstance bonus on each sneak attack damage die.</p>
<p><strong className="hl">Greater Sniper Goggles:</strong> These goggles feature stubby periscope-like lenses that expand and retract depending on the needs of the wearer. These goggles function as <em>sniper goggles,</em> but the wearer gains the +2 circumstance bonus on each sneak attack when making a sneak attack at any range.</p>
<h3 id="magic-wondrous-sniper_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 10,000 gp (normal), 25,000 gp (greater)</p>
</>};
const _soulsight_goggles = {title: "Soulsight Goggles", jsx: <><h2 id="magic-wondrous-soulsight_goggles-soulsight-goggles">Soulsight Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_143_borne_by_the_suns_grace">Pathfinder #143: Borne by the Sun's Grace pg. 39</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 15th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This set of goggles is engraved with geometric patterns and arcane runes. The wearer can immediately see and discern magical auras within 60 feet, as <em>arcane sight.</em> In addition, the wearer is more clearly able to see the animating forces of incorporeal creatures and can therefore harm incorporeal creatures with nonmagical attacks, though these attacks deal only half damage. If the wearer uses a magic weapon to attack an incorporeal creature, the attack deals full damage instead. The goggles have no effect on attacks made with <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapons.</p>
<p>Once per day on command, the wearer can amplify the goggles' ability to sense animating forces for 1 hour. This amplification allows the wearer the ability to notice, locate, and distinguish between living and undead creatures within 30 feet, just as if she had a <Link to="/family/psychopomp">psychopomp's spiritsense ability</Link>. The goggles do not grant the wearer the ability to discern magical auras while amplified.</p>
<h3 id="magic-wondrous-soulsight_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_sight">arcane sight</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _spectacles_of_comprehension = {title: "Spectacles of Comprehension", jsx: <><h2 id="magic-wondrous-spectacles_of_comprehension-spectacles-of-comprehension">Spectacles of Comprehension</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 30</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>These spectacles bear no markings or decoration, but they are obviously sturdy and of high quality. The wearer of these spectacles gains the ability to better understand written material and unravel the language of contracts. The wearer gains a +5 bonus on <Link to="/skill/linguistics">Linguistics</Link> checks to decipher writing, detect forgeries, research in a library, research an infernal contract, or attempt similar types of examinations. Additionally, he is automatically aware if a contract he's examining has any deliberate obfuscations or loopholes, though he might not know exactly what they are.</p>
<h3 id="magic-wondrous-spectacles_of_comprehension-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/investigative_mind">investigative mind</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _spectacles_of_lip_reading = {title: "Spectacles of Lip Reading", jsx: <><h2 id="magic-wondrous-spectacles_of_lip_reading-spectacles-of-lip-reading">Spectacles of Lip Reading</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 56</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> eyes; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These eyeglasses are engraved with owl's feathers. The wearer can understand the words of anyone she can see speaking a language she understands if she succeeds at a DC 0 <Link to="/skill/perception">Perception</Link> check (modified by distance and conditions as normal).</p>
<h3 id="magic-wondrous-spectacles_of_lip_reading-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _spectacles_of_understanding = {title: "Spectacles of Understanding", jsx: <><h2 id="magic-wondrous-spectacles_of_understanding-spectacles-of-understanding">Spectacles of Understanding</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 2nd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>When worn, these innocent-looking spectacles convert any written language to one known by the wearer, as the <em>comprehend languages</em> spell. The glasses are also good at detecting falsified documents, granting their wearer a +5 bonus to <Link to="/skill/linguistics">Linguistics</Link> checks to identify forgeries and the ability make such checks untrained.</p>
<h3 id="magic-wondrous-spectacles_of_understanding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _spendthrift_spectacles = {title: "Spendthrift Spectacles", jsx: <><h2 id="magic-wondrous-spendthrift_spectacles-spendthrift-spectacles">Spendthrift Spectacles</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 17</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 8th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 6,250 gp; <strong>Weight</strong> -</p>
<p>Crafted from brass and polished quartz, these expensive bifocals grant the wearer a +5 bonus on <Link to="/skill/appraise">Appraise</Link> checks, and on <Link to="/skill/linguistics">Linguistics</Link> or <Link to="/skill/perception">Perception</Link> checks to detect a forgery. However, after they have been worn for 1 week, they begin distorting the wearer's perception of value, replacing this bonus with a -10 penalty on the same checks. This penalty persists even when a victim is not wearing the spendthrift spectacles. Whenever the wearer is making a purchase that costs more than 10 gp, he must succeed at a DC 14 Will save or be compelled to make extravagant offers and pay outrageous prices (1d10 &times; 10% more than the asking price) for the item, paying with coin and valuables if available, or bartering with other equipment if not.</p>
<h3 id="magic-wondrous-spendthrift_spectacles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beguiling_gift">beguiling gift</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 3,125 gp</p>
</>};
const _storm_goggles = {title: "Storm Goggles", jsx: <><h2 id="magic-wondrous-storm_goggles-storm-goggles">Storm Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>These goggles, made from a pair of smoky crystal lenses set in an adjustable leather strap, help the wearer see through storms of rain, snow, or even dust. A pair of storm goggles fully negates any <Link to="/skill/perception">Perception</Link> penalties imposed by a natural storm or atmospheric condition. Also, once per round when the wearer makes an attack against a target that has <Link to="/rule/concealment">concealment</Link> from him because of natural or magical fog, mist, clouds, or vapor, the wearer can choose to roll the miss chance percentile twice and take the better of the two results.</p>
<h3 id="magic-wondrous-storm_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/skill_focus">Skill Focus</Link> (Perception), <Link to="/spell/acute_senses">acute senses</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _summoner_slayer_eyes = {title: "Summoner Slayer Eyes", jsx: <><h2 id="magic-wondrous-summoner_slayer_eyes-summoner-slayer-eyes">Summoner Slayer Eyes</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 63</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Crafted by the Arclords of Nex, these golden-white lenses rest in crystal frames that fit comfortably over the eyes. Any creatures conjured by <em>summon monster</em> or a similar spell in the wearer's field of vision appear to the wearer as though they were surrounded by a shimmering, purple glow. The wearer sees non-native creatures that have been called by other forms of magic (such as <Link to="/spell/planar_ally">planar ally</Link> or <Link to="/spell/gate">gate</Link>) outlined in a blue glow. This affects only creatures of which the wearer is already aware. It doesn't bypass <Link to="/rule/concealment">concealment</Link> or stealth, nor does it work if the target is under the effect of an illusion spell that the wearer hasn't seen through.</p>
<p>Once per day when the wearer hits a summoned or called creature with a weapon, the wearer can concentrate on that target, attempting to banish it back to its place of origin. This is treated as a <em>dismissal</em> spell targeting the creature, which must succeed at a DC 16 Will save or be sent back to its home plane.</p>
<h3 id="magic-wondrous-summoner_slayer_eyes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dismissal">dismissal</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Cost</strong> 5,500 gp</p>
</>};
const _swordmasters_blindfold = {title: "Swordmaster's Blindfold", jsx: <><h2 id="magic-wondrous-swordmasters_blindfold-swordmasters-blindfold">Swordmaster's Blindfold</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> -</p>
<p>This black band of silk grants its wearer spectacular senses within a limited range. Some believe these items were made to grant lesser swordmasters the illusion of skill. When the wearer places the blindfold over her eyes, she becomes <Link to="/misc/blinded">blinded</Link>, but gains <Link to="/umr/blindsight">blindsight</Link> within the reach of her melee weapon, or 5 feet if the wearer is not wielding a melee weapon. Furthermore, the wearer is under the effect of a constant <em>locate weakness</em> spell, but only when making melee attacks.</p>
<h3 id="magic-wondrous-swordmasters_blindfold-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blindness_deafness">blindness</Link>, <Link to="/spell/locate_weakness">locate weakness</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _treasure_hunters_goggles = {title: "Treasure Hunter's Goggles", jsx: <><h2 id="magic-wondrous-treasure_hunters_goggles-treasure-hunters-goggles">Treasure Hunter's Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> eyes; <strong>Price</strong> 6,400 gp; <strong>Weight</strong> -</p>
<p>These sturdy but plain goggles help the wearer locate secret doors and coins and identify treasure. While wearing these goggles, the wearer can use <em>detect secret doors</em> at will. The goggles do not aid in determining how secret doors are opened.</p>
<p>Once per day on command, the wearer gains the ability to <em>locate object</em> as per the spell, but only to detect 100 or more coins in a small area, such as a backpack, chest, pouch, or sack.</p>
<p>Three times per day, the wearer may use <em>identify.</em></p>
<h3 id="magic-wondrous-treasure_hunters_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_secret_doors">detect secret doors</Link>, <Link to="/spell/identify">identify</Link>, <Link to="/spell/locate_object">locate object</Link>; <strong>Cost</strong> 3,200 gp</p>
</>};
const _triple_eyes_of_vivid_auras = {title: "Triple Eyes of Vivid Auras", jsx: <><h2 id="magic-wondrous-triple_eyes_of_vivid_auras-triple-eyes-of-vivid-auras">Triple Eyes of Vivid Auras</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 56</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These three-eyed goggles allow the wearer to discern subtler auras that would normally be hidden by more powerful auras when using <Link to="/spell/detect_evil">detect evil</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/identify">identify</Link>, and other detection spells, provided the auras are no more than one step different in strength.</p>
<p>If the detection would normally be automatically foiled by an illusion or abjuration but <em>arcane sight</em> (or another detection effect of 3rd level or lower) would have a chance of seeing through that effect, the wearer gets a chance to see through it even with lower-level detection effects.</p>
<p>Three times per day, the wearer of the triple eyes of vivid auras can use <em>greater detect magic</em> with a command word.</p>
<h3 id="magic-wondrous-triple_eyes_of_vivid_auras-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_sight">arcane sight</Link>, <Link to="/spell/greater_detect_magic">greater detect magic</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _truesight_goggles = {title: "Truesight Goggles", jsx: <><h2 id="magic-wondrous-truesight_goggles-truesight-goggles">Truesight Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 227</Link><br/><strong>Aura</strong> strong divination; <strong>CL</strong> 11th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 184,800 gp; <strong>Weight</strong> -</p>
<p>These goggles, constructed of a pair of perfect prisms held in place by golden frames and affixed to the head by a black leather strap, grants the wearer <em>true seeing</em> continuously. Furthermore, once per day on command, the wearer can use <em>analyze dweomer</em> as the spell.</p>
<h3 id="magic-wondrous-truesight_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/analyze_dweomer">analyze dweomer</Link>, <Link to="/spell/true_seeing">true seeing</Link>; <strong>Cost</strong> 92,400 gp</p>
</>};
const _vitreous_goggles = {title: "Vitreous Goggles", jsx: <><h2 id="magic-wondrous-vitreous_goggles-vitreous-goggles">Vitreous Goggles</h2>
<p><strong>Sources</strong> <Link to="/source/mystery_monsters_revisited">Mystery Monsters Revisited pg. 19</Link><br/><strong>Aura</strong> moderate divination and evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> eyes; <strong>Price</strong> 11,200 gp; <strong>Weight</strong> -</p>
<p>This pair of clear crystal lenses allows the wearer to see the indistinct shapes of living creatures moving below the surface of the earth. The wearer can see any Medium or larger creatures within 60 feet as long as they are moving underground. The wearer must have seen the creature aboveground within the past minute while wearing the goggles to gain this benefit. Each subsequent round after the first that the goggles are worn, the wearer has a cumulative 5% chance of immediately going <Link to="/misc/blind">blind</Link> for 1d4 rounds. Once the goggles are removed, the wearer's eyes need 1 hour to adjust before he or she can wear the goggles again.</p>
<h3 id="magic-wondrous-vitreous_goggles-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/faerie_fire">faerie fire</Link>, <Link to="/spell/locate_creature">locate creature</Link>; <strong>Cost</strong> 5,600 gp</p>
</>};
const _acrobat_slippers = {title: "Acrobat Slippers", jsx: <><h2 id="magic-wondrous-acrobat_slippers-acrobat-slippers">Acrobat Slippers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These supple gray leather slippers enable the wearer to keep his balance in precarious positions. The wearer retains his Dexterity bonus to AC when climbing, running, or using the <Link to="/skill/acrobatics">Acrobatics</Link> skill to move on narrow surfaces or uneven ground without falling. In addition, the wearer gains a +2 competence bonus to CMD against <Link to="/rule/trip">trip</Link> maneuvers and on Reflex saves to avoid falling (including falling prone).</p>
<h3 id="magic-wondrous-acrobat_slippers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _ankle_chains_of_walking = {title: "Ankle Chains of Walking", jsx: <><h2 id="magic-wondrous-ankle_chains_of_walking-ankle-chains-of-walking">Ankle Chains of Walking</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 21</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>These steel cuffs are connected with a 2-foot-long chain. The cuffs are decorated with lead inlays of broken feet. When locked around a <Link to="/misc/helpless">helpless</Link> or willing creature's ankles as a full-round action, the creature can move only half its normal speed for all its forms of movement. The creature that placed the ankle chains can remove them with a command word, any creature can remove them with a successful DC 30 <Link to="/skill/disable_device">Disable Device</Link> check, and the restrained creature can remove them with a successful DC 30 <Link to="/skill/escape_artist">Escape Artist</Link> check. Dispelling the ankle chains doesn't assist in removing them, though it does prevent the creature that placed the ankle chains from using the command word to remove them for as long as their effects are suppressed or dispelled.</p>
<h3 id="magic-wondrous-ankle_chains_of_walking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/slow">slow</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _anthill_boots = {title: "Anthill Boots", jsx: <><h2 id="magic-wondrous-anthill_boots-anthill-boots">Anthill Boots</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 30</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> feet; <strong>Price</strong> 12,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Ants occasionally crawl in and out of the numerous tiny holes dotting these sturdy, thick-soled boots. The boots' wearer receives a +4 competence bonus on Fortitude saving throws against swarms' distraction ability. Additionally, once per day, the wearer can call forth an <Link to="/monster/army_ant_swarm">army ant swarm</Link> as a standard action. This functions as the spell <Link to="/spell/vomit_swarm">vomit swarm</Link>, except the swarm crawls out from the boots instead of being vomited forth. The swarm lasts for 13 rounds before dissipating.</p>
<h3 id="magic-wondrous-anthill_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, vomit swarm; <strong>Cost</strong> 6,250 gp</p>
</>};
const _bastion_boots = {title: "Bastion Boots", jsx: <><h2 id="magic-wondrous-bastion_boots-bastion-boots">Bastion Boots</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 30</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,500 gp; <strong>Weight</strong> 4 lbs.</p>
<p>These metal boots are engraved with the imagery of <Link to="/eq-misc/harrow_deck">The Keep</Link>, and evoke the unwavering determination represented by that card. The boots can be used as an <Link to="/magic-rod/immovable_rod">immovable rod</Link>, even when worn. If the boots are moved, the wearer moves with the boots. Even while not activated, bastion boots grant the wearer a +4 bonus to her CMD against combat maneuvers to move her.</p>
<h3 id="magic-wondrous-bastion_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/levitate">levitate</Link>; <strong>Cost</strong> 5,250 gp</p>
</>};
const _battle_striders_boots = {title: "Battle Strider's Boots", jsx: <><h2 id="magic-wondrous-battle_striders_boots-battle-striders-boots">Battle Strider's Boots</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 177</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>While unattended, these rough leather boots appear to be in a slightly different place each time a creature observes them. They seem to flicker around the wearer's feet for the first 24 hours she wears them, reducing her movement speed by 5 feet and imposing a -2 penalty on Acrobatics checks.</p>
<p>After she has worn the boots for 24 hours, the flickering decreases, the penalties end, and she can activate the boots. Three times per day, she can activate the boots as a swift action to avoid provoking attacks of opportunity while moving out of a threatened square. While activated, the boots conceal the wearer's movement in such a way that her foes see only short, blurred flashes of movement. Any creature that has <Link to="/umr/blindsight">blindsight</Link> or a similar nonvisual sense or is affected by <Link to="/spell/true_seeing">true seeing</Link> can still make attacks of opportunity against the wearer as normal.</p>
<h3 id="magic-wondrous-battle_striders_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blur">blur</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _blight_kickers = {title: "Blight Kickers", jsx: <><h2 id="magic-wondrous-blight_kickers-blight-kickers">Blight Kickers</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 13,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These leather combat boots have brown or black laces and several rows of pouches near their tops. These magical boots can hide up to 5 doses of poison in the attached pouches. These boots grant a cumulative +1 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> and <Link to="/skill/stealth">Stealth</Link> checks for each dose of poison hidden in the boots, to a maximum of +5. Once per day, when drawing a poison from the blight kickers, the wearer can speak the command word to augment a single dose of poison in order to hasten the onset of the poison, causing its effects to begin immediately.</p>
<h3 id="magic-wondrous-blight_kickers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/accelerate_poison">accelerate poison</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 6,750 gp</p>
</>};
const _bog_boots = {title: "Bog Boots", jsx: <><h2 id="magic-wondrous-bog_boots-bog-boots">Bog Boots</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 56</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These boots are well worn and caked with mud, but still sturdy, comfortable, and dry on the inside.</p>
<p>Three times per day, the wearer can activate the boots to cause up to 9 5-foot squares of nearby terrain to become a <Link to="/rule/marsh_terrain">shallow bog</Link>. All affected squares are instantly filled with 1 foot of water, mud, and plant life. The wearer can move through these squares at her normal speed, but other creatures treat the squares as a shallow bog, costing 2 squares of movement to move into each affected square.</p>
<p>The initial affected square must be adjacent to the wearer. Each additional affected square must be adjacent to another affected square, but otherwise the effect can take any shape the wearer desires.</p>
<p>As a standard action, the wearer can rearrange the affected squares. Multiple uses of the boots can create larger areas of bog. The effect lasts until dismissed by the wearer (a free action), the wearer moves more than 5 feet beyond the affected area, the wearer becomes unconscious, or the boots are removed.</p>
<p>Additionally, once per day, the wearer can travel as per <em>dimension door</em> from one affected square to another.</p>
<h3 id="magic-wondrous-bog_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _bogstrider_boots = {title: "Bogstrider Boots", jsx: <><h2 id="magic-wondrous-bogstrider_boots-bogstrider-boots">Bogstrider Boots</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 28</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft leather boots smell strongly of marsh gas, and leave faint wet prints behind even when they're dry. Despite these aesthetic flaws, bogstrider boots are of great use in areas of swampy terrain. They provide the wearer the ability to move without penalty in squares of shallow or deep bog, and the DCs of Acrobatics checks attempted by the boots' wearer are unchanged in squares of shallow bog. In addition, three times per day when the wearer takes a <Link to="/rule/charge">charge</Link> or <Link to="/rule/withdraw">withdraw</Link> action, she can increase her speed by 60 feet for 1 round.</p>
<h3 id="magic-wondrous-bogstrider_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _bondbreakers_boots = {title: "Bondbreaker's Boots", jsx: <><h2 id="magic-wondrous-bondbreakers_boots-bondbreakers-boots">Bondbreaker's Boots</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 30</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>These leather boots bear a knife motif worked into their durable blue leather. Three times per day, the wearer can speak a command word as a swift action, causing a serrated knife to fly from the boots and instantly slice through any nonmagical bond currently restraining the wearer. The knife conjured from bondbreaker's boots can cut through brambles, ropes, <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bags</Link>, vines, webs, or any other similar nonmagical item restraining the wearer, but cannot help when the owner is actively restrained by a creature. Bondbreaker's boots also cannot free the wearer if manacles or chains restrain her.</p>
<h3 id="magic-wondrous-bondbreakers_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/unseen_servant">unseen servant</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _boots_of_dancing = {title: "Boots of Dancing", jsx: <><h2 id="magic-wondrous-boots_of_dancing-boots-of-dancing">Boots of Dancing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 343</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 539</Link></p>
<p><strong>Aura</strong> strong enchantment; <strong>CL</strong> 16th<br/><strong>Slot</strong> feet; <strong>Weight</strong> 1 lb.</p>
<p>These boots appear and initially function as one of the other kinds of magic boots. When the wearer is in (or fleeing from) melee combat, boots of dancing impede movement, making him behave as if <Link to="/spell/irresistible_dance">irresistible dance</Link> had been cast upon him. Only a <Link to="/spell/remove_curse">remove curse</Link> spell enables the wearer to be rid of the boots once their true nature is revealed.</p>
<h3 id="magic-wondrous-boots_of_dancing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/boots_of_elvenkind">boots of elvenkind</Link>, <Link to="/magic-wondrous/boots_of_levitation">boots of levitation</Link>, <Link to="/magic-wondrous/boots_of_speed">boots of speed</Link>, <Link to="/magic-wondrous/boots_of_striding_and_springing">boots of striding and springing</Link>, <Link to="/magic-wondrous/boots_of_teleportation">boots of teleportation</Link>, <Link to="/magic-wondrous/boots_of_the_winterlands">boots of the winterlands</Link>, <Link to="/magic-wondrous/winged_boots">winged boots</Link>; <strong>Cost</strong> -</p>
</>};
const _boots_of_earth_and_wind = {title: "Boots of Earth and Wind", jsx: <><h2 id="magic-wondrous-boots_of_earth_and_wind-boots-of-earth-and-wind">Boots of Earth and Wind</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 147</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These strange, heavy, leather-and-steel boots feature a pair of ever-fluttering wings on each side. These boots function like <Link to="/magic-wondrous/winged_boots">winged boots</Link>, but also grant a +5 bonus to CMD against <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/overrun">overrun</Link>, and <Link to="/rule/reposition">reposition</Link> combat maneuvers as long as the wearer is standing on solid ground. A mythic creature can expend one use of mythic power when commanding the boots to fly to gain the bonus to CMD for as long as she uses the boots to fly.</p>
<h3 id="magic-wondrous-boots_of_earth_and_wind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/entangle">entangle</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _boots_of_elvenkind = {title: "Boots of Elvenkind", jsx: <><h2 id="magic-wondrous-boots_of_elvenkind-boots-of-elvenkind">Boots of Elvenkind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 503</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft boots are partially made out of living leaves and other natural materials. They enable the wearer to move nimbly about in virtually any surroundings, granting a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks.</p>
<h3 id="magic-wondrous-boots_of_elvenkind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be an <Link to="/race/elf">elf</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _boots_of_escape = {title: "Boots of Escape", jsx: <><h2 id="magic-wondrous-boots_of_escape-boots-of-escape">Boots of Escape</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 38</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These sturdy leather-soled cloth boots have straps at the ankles and calves to ensure a snug fit. Once per day, when the wearer of the boots is <Link to="/rule/grappled">grappled, pinned</Link>, or <Link to="/rule/entangled">entangled</Link>, she may transfer herself to any spot within 30 feet as if using a <em>dimension door</em> spell. A <Link to="/race/gnome">gnome</Link> wearing these boots may instead transfer herself up to 400 feet away.</p>
<h3 id="magic-wondrous-boots_of_escape-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>, creator must be a gnome or a wizard specialized in the school of conjuration; <strong>Cost</strong> 4,000 gp</p>
</>};
const _boots_of_fiendish_escape_tiefling = {title: "Boots of Fiendish Escape (Tiefling)", jsx: <><h2 id="magic-wondrous-boots_of_fiendish_escape_tiefling-boots-of-fiendish-escape-tiefling">Boots of Fiendish Escape (Tiefling)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 229</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> feet; <strong>Price</strong> 45,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This pair of supple, leather-heeled boots can be worn comfortably whether the wearer has feet or hooves. The wearer can use <em>fog cloud</em> once per day by clicking the boot's heels together as a swift action. If the wearer is a <Link to="/race/tiefling">tiefling</Link>, he can simultaneously teleport up to 1,000 feet as per <em>dimension door.</em></p>
<h3 id="magic-wondrous-boots_of_fiendish_escape_tiefling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/quicken_spell">Quicken Spell</Link>, <Link to="/spell/dimension_door">dimension door</Link>, <Link to="/spell/fog_cloud">fog cloud</Link>, creator must be a tiefling; <strong>Cost</strong> 22,500 gp</p>
</>};
const _boots_of_flawless_resolve = {title: "Boots of Flawless Resolve", jsx: <><h2 id="magic-wondrous-boots_of_flawless_resolve-boots-of-flawless-resolve">Boots of Flawless Resolve</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 18</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These knee-high white leather boots are covered in delicate lines of gemstones and precious metals that are almost imperceptible to the average human eye. Three times per day as a move action, the wearer can declare a single creature within 30 feet as his target. The wearer gains a +2 insight bonus to AC against the target's attacks and a +4 bonus to CMD against combat maneuvers the target attempts against him. This effect lasts for up to 7 rounds, but it ends immediately if the wearer takes any move action that would move him out of his square (not including a 5-foot step, but including movement such as flying) or if he is moved out of his square involuntarily, such as by a successful <Link to="/rule/bull_rush">bull rush</Link> combat maneuver that pushes him backward. If the target dies, the effect immediately ends, and declaring a new target requires expending another use. If the wearer declares a new target before the effect on the previous target ends, the effect on the previous target ends immediately, and declaring the new target expends another use.</p>
<h3 id="magic-wondrous-boots_of_flawless_resolve-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/anticipate_thoughts">anticipate thoughts</Link>; <strong>Cost</strong> 3,250 gp</p>
</>};
const _boots_of_friendly_terrain = {title: "Boots of Friendly Terrain", jsx: <><h2 id="magic-wondrous-boots_of_friendly_terrain-boots-of-friendly-terrain">Boots of Friendly Terrain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 3300</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>Boots of friendly terrain turn inhospitable territory into a perfect hunting grounds for any ranger who wears them, so much so that his footprints vanish behind him with each step he takes. Each pair of these supple leather boots corresponds to a specific sort of environment as defined by the ranger's <Link to="/ability/favored_terrain">favored terrain</Link> class feature (jungles, plains, and so on). A <Link to="/class/ranger">ranger</Link> wearing the boots can treat the corresponding environment of the boots as one of his favored terrains, granting him a +2 bonus. If he already has that particular environment as one of his favored terrains, that terrain's bonus increases by 2.</p>
<h3 id="magic-wondrous-boots_of_friendly_terrain-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, creator must be a ranger; <strong>Cost</strong> 1,200 gp</p>
</>};
const _boots_of_gusto = {title: "Boots of Gusto", jsx: <><h2 id="magic-wondrous-boots_of_gusto-boots-of-gusto">Boots of Gusto</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 227</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These boots are made of fine red leather, and are decorated with stitched designs featuring humanoids wielding rapiers and other light weapons suited for <Link to="/class/swashbuckler">swashbucklers</Link>. Up to three times per day, the wearer can perform the <Link to="/swashdeed/derring_do">derring-do</Link> 1st-level swashbuckler deed.</p>
<h3 id="magic-wondrous-boots_of_gusto-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, creator must be a panache user; <strong>Cost</strong> 1,000 gp</p>
</>};
const _boots_of_levitation = {title: "Boots of Levitation", jsx: <><h2 id="magic-wondrous-boots_of_levitation-boots-of-levitation">Boots of Levitation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 503</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft leather boots are incredibly light and comfortable, with thin soles reinforced by strips of tough hide that provide an unexpected amount of support and protection to the foot. On command, these boots allow the wearer to levitate as if she had cast <em>levitate</em> on herself.</p>
<h3 id="magic-wondrous-boots_of_levitation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/levitate">levitate</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _boots_of_planar_grounding = {title: "Boots of Planar Grounding", jsx: <><h2 id="magic-wondrous-boots_of_planar_grounding-boots-of-planar-grounding">Boots of Planar Grounding</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 53</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> -</p>
<p>These heavy, iron-soled boots link the wearer with the plane she is on. The wearer always counts as being on her home plane, regardless of the plane she is on, and she never gains the extraplanar subtype.</p>
<h3 id="magic-wondrous-boots_of_planar_grounding-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _boots_of_speed = {title: "Boots of Speed", jsx: <><h2 id="magic-wondrous-boots_of_speed-boots-of-speed">Boots of Speed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 503</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> feet; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>As a free action, the wearer of boots of speed can click her heels together, letting her act as though affected by a <em>haste</em> spell for up to 10 rounds each day. The <em>haste</em> effect's duration need not be consecutive rounds.</p>
<h3 id="magic-wondrous-boots_of_speed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _boots_of_striding_and_springing = {title: "Boots of Striding and Springing", jsx: <><h2 id="magic-wondrous-boots_of_striding_and_springing-boots-of-striding-and-springing">Boots of Striding and Springing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 503</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 5,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These boots increase the wearer's base land speed by 10 feet. In addition to this striding ability (considered an enhancement bonus), these boots allow the wearer to make great leaps. She can jump with a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks.</p>
<h3 id="magic-wondrous-boots_of_striding_and_springing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/longstrider">longstrider</Link>, creator must have 5 ranks in the Acrobatics skill; <strong>Cost</strong> 2,750 gp</p>
</>};
const _boots_of_swift_fury = {title: "Boots of Swift Fury", jsx: <><h2 id="magic-wondrous-boots_of_swift_fury-boots-of-swift-fury">Boots of Swift Fury</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 227</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> feet; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These boots of heavy, furred hide rise to the wearer's calf, and are held in place with rough hide straps secured by thick iron buckles. They increase the wearer's base land speed by 10 feet (considered an enhancement bonus). When the wearer is in a rage, the boots also grant him a +4 deflection bonus to AC against attacks of opportunity provoked by moving through or out of a threatened area or by casting a spell.</p>
<h3 id="magic-wondrous-boots_of_swift_fury-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/rage">rage</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _boots_of_teleportation = {title: "Boots of Teleportation", jsx: <><h2 id="magic-wondrous-boots_of_teleportation-boots-of-teleportation">Boots of Teleportation</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 228</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 49,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>When scrutinized closely, parts of these light gray boots appear to fade in and out of existence. Any character wearing this footwear may teleport three times per day, exactly as if she had cast the <em>teleport</em> spell.</p>
<h3 id="magic-wondrous-boots_of_teleportation-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/teleport">teleport</Link>; <strong>Cost</strong> 24,500 gp</p>
</>};
const _boots_of_the_battle_herald = {title: "Boots of the Battle Herald", jsx: <><h2 id="magic-wondrous-boots_of_the_battle_herald-boots-of-the-battle-herald">Boots of the Battle Herald</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 227</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 11th<br/><strong>Slot</strong> feet; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These boots are made of fine white leather tooled with scenes of epic battles. Once per day as a move action, the wearer can affect himself with <em>greater heroism</em> for 11 minutes.</p>
<h3 id="magic-wondrous-boots_of_the_battle_herald-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_heroism">greater heroism</Link>, <Link to="/spell/remove_fear">remove fear</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _boots_of_the_cat = {title: "Boots of the Cat", jsx: <><h2 id="magic-wondrous-boots_of_the_cat-boots-of-the-cat">Boots of the Cat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 229</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These high-soled blue boots provide a great deal of comfort and arch support while also making the wearer appear a little bit taller than normal. The boot's wearer always takes the minimum possible damage from <Link to="/rule/falling">falls</Link> (as if the GM had rolled a 1 on each die of damage incurred by the fall) and at the end of a fall always lands on his feet.</p>
<h3 id="magic-wondrous-boots_of_the_cat-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_fall">feather fall</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _boots_of_the_earth = {title: "Boots of the Earth", jsx: <><h2 id="magic-wondrous-boots_of_the_earth-boots-of-the-earth">Boots of the Earth</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 261</Link><br/><strong>Aura</strong> faint conjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>These sturdy leather dwarven boots have soles made of thick gray marble. As a move action, the wearer can plant her feet and draw strength from the earth, gaining <Link to="/umr/fast_healing">fast healing</Link> 1 and a +4 bonus to CMD to resist <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/reposition">reposition</Link>, and <Link to="/rule/trip">trip</Link> combat maneuver attempts. These effects end if the wearer moves or is moved, knocked prone, or rendered unconscious.</p>
<h3 id="magic-wondrous-boots_of_the_earth-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _boots_of_the_enduring_march = {title: "Boots of the Enduring March", jsx: <><h2 id="magic-wondrous-boots_of_the_enduring_march-boots-of-the-enduring-march">Boots of the Enduring March</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 229</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 2nd<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These travel-stained boots of stout brown leather enable the wearer to traverse great distances without tiring. When making a <Link to="/rule/forced_march">forced march</Link>, for each hour of marching beyond 8 hours, the wearer needs only to make a Constitution check (DC 10, +1 per extra hour) instead of the normal check. Furthermore, if the wearer fails the check, she only takes 1d4 points of nonlethal damage and does not become <Link to="/misc/fatigued">fatigued</Link> the first time she takes nonlethal damage in this way.</p>
<h3 id="magic-wondrous-boots_of_the_enduring_march-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/endurance">Endurance</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _boots_of_the_eternal_rose = {title: "Boots of the Eternal Rose", jsx: <><h2 id="magic-wondrous-boots_of_the_eternal_rose-boots-of-the-eternal-rose">Boots of the Eternal Rose</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 261</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These leather boots are found in a variety of styles but always have a prominent engraving of a rose. The wearer gains a +2 competence bonus on <Link to="/skill/perform">Perform (dance)</Link> and <Link to="/skill/stealth">Stealth</Link> checks. The wearer may move through areas of flowers (whether wild-growing or a garden) at normal speed and without suffering any impairment or taking damage from thorns, brambles, or similar hazards; areas of flowers that have been magically manipulated to impede motion still affect the wearer.</p>
<p>If <Link to="/faith/shelyn">Shelyn</Link> is the wearer's patron, the wearer may use <em>daze monster</em> once per day; if the wearer is dancing, singing, or using some other Perform skill as part of a performance lasting at least 1 minute, he may activate <em>daze monster</em> as a free action during his performance. As a free action once per round, the wearer may conjure a beautiful, nonmagical, common flower (such as a daisy, pansy, rose, sunflower, or the like) that lasts for 1 day before crumbling into perfume and dust.</p>
<h3 id="magic-wondrous-boots_of_the_eternal_rose-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/daze_monster">daze monster</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, creator must have 5 ranks in Perform (dance) and Stealth; <strong>Cost</strong> 2,000 gp</p>
</>};
const _boots_of_the_mastodon = {title: "Boots of the Mastodon", jsx: <><h2 id="magic-wondrous-boots_of_the_mastodon-boots-of-the-mastodon">Boots of the Mastodon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 229</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These massive boots are made from <Link to="/monster/mastodon">mastodon</Link> hide. The boots are so large and cumbersome that their wearer takes a -2 penalty on <Link to="/skill/stealth">Stealth</Link> checks, but gains a +2 enhancement bonus on <Link to="/rule/overrun">overrun</Link> attempts and a +2 dodge bonus to AC while attempting an overrun combat maneuver. In addition, once per day the wearer can make a <Link to="/umr/trample">trample</Link> attack. Regardless of his actual size, the creature wearing the boots can trample creatures of size Large or smaller in his path. The trample attack deals 2d8+18 points of damage (Reflex DC 29 halves).</p>
<h3 id="magic-wondrous-boots_of_the_mastodon-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iii">beast shape III</Link>; <strong>Cost</strong> 5,250 gp</p>
</>};
const _boots_of_the_mire = {title: "Boots of the Mire", jsx: <><h2 id="magic-wondrous-boots_of_the_mire-boots-of-the-mire">Boots of the Mire</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 229</Link>, <Link to="/source/pathfinder_3_the_hook_mountain_massacre">Pathfinder #3: The Hook Mountain Massacre pg. 33</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 420</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft leather boots confer several powers upon the wearer. First, he is granted the power to walk on water in swampy environments, provided the water is no deeper than 5 feet - this effectively lets him move through swampy terrain and mud at no cost to his speed. He leaves no tracks or other signs of his passage as long as he's in swampy terrain, and never becomes uncomfortable or wet from rain, fog, or other forms of non-freezing precipitation. Finally, the boots grant him a +2 resistance bonus on all Fortitude saves made against poison and disease.</p>
<h3 id="magic-wondrous-boots_of_the_mire-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _boots_of_the_vengeful_behir = {title: "Boots of the Vengeful Behir", jsx: <><h2 id="magic-wondrous-boots_of_the_vengeful_behir-boots-of-the-vengeful-behir">Boots of the Vengeful Behir</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 30</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>These heavy boots are made of blue leather. Three times per day, when the wearer speaks the command word, he can attempt a <Link to="/rule/bull_rush">bull rush</Link> the following round as if one size category larger than normal. If the target of the bull rush is a dragon, the wearer is treated as if two size categories larger than normal. This bull rush attempt does not provoke attacks of opportunity.</p>
<h3 id="magic-wondrous-boots_of_the_vengeful_behir-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _boots_of_the_winter_jarl = {title: "Boots of the Winter Jarl", jsx: <><h2 id="magic-wondrous-boots_of_the_winter_jarl-boots-of-the-winter-jarl">Boots of the Winter Jarl</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_69_maiden_mother_crone">Pathfinder #69: Maiden, Mother, Crone pg. 60</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> feet; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>Crafted of stout, wax-treated leather and wrapped with warm fur reminiscent of a <Link to="/monster/frost_giant">frost giant's</Link> beard, these boots are sometimes given as gifts by the frost giant tribes of the north to their smaller allies. In addition to functioning as <Link to="/magic-wondrous/boots_of_the_winterlands">boots of the winterlands</Link>, the boots of the winter jarl enable their wearer to take the form of a frost giant once per day, as with the <em>giant form I</em> spell. While in giant form, the wearer gains a +6 size bonus to Strength, a -2 penalty to Dexterity, a +4 size bonus to Constitution, a +4 natural armor bonus, low-light vision, <Link to="/umr/rock_catching">rock catching</Link>, <Link to="/umr/rock_throwing">rock throwing</Link>, and resist cold 20, but also gains vulnerability to fire. The wearer can remain in giant form for up to 10 minutes.</p>
<h3 id="magic-wondrous-boots_of_the_winter_jarl-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/giant_form_i">giant form I</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _boots_of_the_winterlands = {title: "Boots of the Winterlands", jsx: <><h2 id="magic-wondrous-boots_of_the_winterlands-boots-of-the-winterlands">Boots of the Winterlands</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these boots is able to travel across snow at her normal speed, leaving no tracks. Additionally, the boots enable her to travel at normal speed across the slipperiest ice (horizontal surfaces only, not vertical or sharply slanted ones) without falling or slipping. Finally, boots of the winterlands warm the wearer, as if she were affected by an <em>endure elements</em> spell.</p>
<h3 id="magic-wondrous-boots_of_the_winterlands-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/endure_elements">endure elements</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _boots_of_vaulting = {title: "Boots of Vaulting", jsx: <><h2 id="magic-wondrous-boots_of_vaulting-boots-of-vaulting">Boots of Vaulting</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 227</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these suede boots ignores an additional 10 feet of falling distance when she successfully uses <Link to="/skill/acrobatics">Acrobatics</Link> to soften a fall. Once per round as a free action, the wearer can use the boots to gain a +10 competence bonus on an Acrobatics check to jump, treating such jump as though she had a running start. The wearer also receives this +10 competence bonus on Acrobatics checks to avoid attacks of opportunity during the jump or to balance after landing.</p>
<p>Using the boots in this fashion strains the lower body. If the wearer attempts a second such jump before at least 1 minute has passed, she must succeed at a Fortitude save with a DC equal to the DC of her second jump attempt or injure her legs. This injury reduces her speed by half for 24 hours, or until she is successfully treated with a DC 15 <Link to="/skill/heal">Heal</Link> check or at least 1 point of magical healing. The DC of the Fortitude save increases by 5 for each additional jump attempted until at least 1 minute passes between jumps.</p>
<h3 id="magic-wondrous-boots_of_vaulting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/jump">jump</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _burglar_boots_minor = {title: "Burglar Boots (Minor)", jsx: <><h2 id="magic-wondrous-burglar_boots_minor-burglar-boots">Burglar Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link><br/><strong>Aura</strong> faint (minor) or moderate (major) divination; <strong>CL</strong> 1st (minor), 10th (major)<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,000 gp (minor), 46,000 gp (major); <strong>Weight</strong> 1/2 lb.</p>
<p><strong className="hl">Minor:</strong> These form-fitting, calfskin boots are dyed black and lightly decorated with raven feathers. They grant their wearer a +5 competence bonus on <Link to="/skill/perception">Perception</Link> checks to spot or locate traps and devices on the floor with 10 feet. This includes pits, pressure plates, and other mechanical and magical devices located on or attached to the floor. This bonus also applies to AC and on any Reflex saving throws against such traps.</p>
<p><strong className="hl">Major:</strong> These boots look and act as the <em>minor burglar boots,</em> but grant a +10 competence bonus on Perception checks and to AC and on Reflex saves. Also, once per day on command, these boots grant the wearer the ability to use <em>find traps</em> as the spell.</p>
<h3 id="magic-wondrous-burglar_boots_minor-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/find_traps">find traps</Link> (major only), creator must have 4 (minor) or 12 (major) ranks in Perception; <strong>Cost</strong> 2,000 gp (minor), 23,000 gp (major)</p>
</>};
const _caltrop_boots = {title: "Caltrop Boots", jsx: <><h2 id="magic-wondrous-caltrop_boots-caltrop-boots">Caltrop Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These knee-high black leather boots have prominent and irregularly shaped heels which seem to bulge from the rest of the shoe. As a swift action, the boots' wearer can cause the boots to let loose a spray of <Link to="/eq-misc/caltrops">caltrops</Link> through the back of the heels as he moves during the remainder of his round. These caltrops fill each square the wearer moves into during that round. Any creature, including the wearer, occupying or who steps into one of these squares suffers the normal effects of coming into contact with caltrops. Once produced, these caltrops remain in existence until removed from their square, at which point they immediately disappear. The shoes can be used for 10 rounds per day. These rounds need not be consecutive.</p>
<h3 id="magic-wondrous-caltrop_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spike_growth">spike growth</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _cat_burglars_boots = {title: "Cat Burglar's Boots", jsx: <><h2 id="magic-wondrous-cat_burglars_boots-cat-burglars-boots">Cat Burglar's Boots</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_61_shards_of_sin">Pathfinder #61: Shards of Sin pg. 64</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft-soled boots provide their wearer with a +2 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link>, <Link to="/skill/climb">Climb</Link>, and <Link to="/skill/stealth">Stealth</Link> checks. Once per day as an immediate action, the wearer of cat burglar's boots can reroll any one failed Acrobatics, Climb, or Stealth check, taking the result of that check in place of the first failed check (even if the second result is worse). In addition, a secret pocket in the boots is built to hold a fully functional set of <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves' tools</Link>. A DC 22 Perception check is required to notice this pocket. Any other object in the pocket causes it to bulge and become obvious to even casual observation.</p>
<h3 id="magic-wondrous-cat_burglars_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _clandestine_horseshoes = {title: "Clandestine Horseshoes", jsx: <><h2 id="magic-wondrous-clandestine_horseshoes-clandestine-horseshoes">Clandestine Horseshoes</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 27</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>If a creature wearing these dull gray horseshoes remains stationary for 1 round, the creature and its rider, if any, gain a +10 bonus on <Link to="/skill/stealth">Stealth</Link> checks for 1 round. In addition, once per day, the rider of a mount wearing clandestine horseshoes can turn both herself and her mount invisible, as <em>invisibility.</em> All four shoes must be worn by the same creature for the magic to be effective.</p>
<h3 id="magic-wondrous-clandestine_horseshoes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _combat_sandals = {title: "Combat Sandals", jsx: <><h2 id="magic-wondrous-combat_sandals-combat-sandals">Combat Sandals</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 14</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Worked brown leather straps run up the backs and around the soles of this sturdy set of footwear. The wearer of a pair of combat sandals can <Link to="/rule/charge">charge</Link> through allies' squares without difficulty, and allies adjacent to the wearer don't provide <Link to="/rule/cover">cover</Link> to targets the wearer attacks with reach or ranged weapons.</p>
<h3 id="magic-wondrous-combat_sandals-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>, <Link to="/spell/true_strike">true strike</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _crashing_boots = {title: "Crashing Boots", jsx: <><h2 id="magic-wondrous-crashing_boots-crashing-boots">Crashing Boots</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 165</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,800 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These thick, stout boots, crafted from the hide of a <Link to="/monster/gorthek">gorthek</Link>, grant their wearer a +2 enhancement bonus on attack rolls when <Link to="/rule/charging">charging</Link>. In addition, once per day when the wearer hits a Large or smaller creature with an attack, he can send his foe flying 10 feet. The foe must be thrown in a straight line away from the wearer, and lands <Link to="/rule/prone">prone</Link> at the end of the movement. If an obstacle prevents the completion of the opponent's move, the opponent and the obstacle each take 1d6 points of damage, and the opponent is knocked prone in the space adjacent to the obstacle.</p>
<h3 id="magic-wondrous-crashing_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>; <strong>Cost</strong> 4,400 gp</p>
</>};
const _daredevil_boots = {title: "Daredevil Boots", jsx: <><h2 id="magic-wondrous-daredevil_boots-daredevil-boots">Daredevil Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This pair of magical boots shimmers in vibrant shades of blazing red and burning orange when they are held up to the light. These boots allow the wearer to gain extra maneuverability while moving through hazardous areas. As a free action, the wearer can click her heels together to grant herself a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks made to move through threatened squares or to move through an enemy's space without provoking attacks of opportunity for up to 10 rounds per day. The rounds do not need to be consecutive. Furthermore, anytime the wearer of the boots successfully moves though the space of an enemy without provoking an attack of opportunity, she gains a +1 bonus on attack rolls against that enemy until the end of her turn.</p>
<h3 id="magic-wondrous-daredevil_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 700 gp</p>
</>};
const _daredevil_softpaws = {title: "Daredevil Softpaws", jsx: <><h2 id="magic-wondrous-daredevil_softpaws-daredevil-softpaws">Daredevil Softpaws</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 95</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>This pair of magical <Link to="/eq-misc/softpaw_boots">softpaw boots</Link> allows the <Link to="/race/catfolk">catfolk</Link> wearing them to gain extra maneuverability while moving through hazardous areas. As a free action, the wearer can click her heels together to grant herself a +5 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks made to move through threatened squares or to move through an enemy's space without provoking attacks of opportunity for up to 10 rounds per day. The rounds need not be consecutive. Furthermore, anytime the wearer of the boots successfully moves though the space of an enemy without provoking an attack of opportunity, she gains a +2 bonus on attack rolls against that enemy until the end of her turn.</p>
<h3 id="magic-wondrous-daredevil_softpaws-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 700 gp</p>
</>};
const _daring_dancers = {title: "Daring Dancers", jsx: <><h2 id="magic-wondrous-daring_dancers-daring-dancers">Daring Dancers</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 58</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> feet; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> -</p>
<p>These glittering anklets or spurs are favorites of Varisians, both for their showy addition to performances and their more practical uses. Normally made of metal and leather and adorned with glass beads or small gemstones, they make the wearer's feet light and agile, granting a +5 competence bonus to <Link to="/skill/perform">Perform (dance)</Link> checks. The wearer's footfalls become so light that she can dance gracefully on any surface and make a 5-foot step even in difficult terrain.</p>
<p>If the wearer has 5 or more ranks in Perform (dance), daring dancers allow her to cast <em>dimension door</em> on herself once per day to travel up to 700 feet.</p>
<h3 id="magic-wondrous-daring_dancers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/dimension_door">dimension door</Link>, creator must have 10 ranks in Perform (dance); <strong>Cost</strong> 8,000 gp</p>
</>};
const _dryad_sandals = {title: "Dryad Sandals", jsx: <><h2 id="magic-wondrous-dryad_sandals-dryad-sandals">Dryad Sandals</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These sandals are woven from grass, lengths of pliant vine, living leaves, and supple bark. In forest terrain, the wearer leaves no tracks or scent and gains a +2 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. The wearer can move through natural undergrowth without impediment or harm as a druid using <Link to="/ability/woodland_stride">woodland stride</Link>, and once per day she may step inside a tree and remain there for up to 9 hours, or teleport to a similar tree within range, as <em>tree stride</em> but allowing only a single teleport.</p>
<h3 id="magic-wondrous-dryad_sandals-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, <Link to="/spell/tree_stride">tree stride</Link>, creator must be a druid; <strong>Cost</strong> 12,000 gp</p>
</>};
const _earth_root_boots = {title: "Earth Root Boots", jsx: <><h2 id="magic-wondrous-earth_root_boots-earth-root-boots">Earth Root Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 230</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The longer the wearer of these boots stays in one place - as long as that place is on solid ground - the harder it is to move her from that place. The wearer gains a cumulative +1 circumstance bonus to her CMD (maximum of +10) for each round she does not move from her space.</p>
<h3 id="magic-wondrous-earth_root_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/elemental_body_i">elemental body I</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _earthquake_boots = {title: "Earthquake Boots", jsx: <><h2 id="magic-wondrous-earthquake_boots-earthquake-boots">Earthquake Boots</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 30</Link><br/><strong>Aura</strong> strong evocation; <strong>CL</strong> 15th<br/><strong>Slot</strong> feet; <strong>Price</strong> 67,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These thick hide boots allow the wearer to detect unseen enemies, and they provide a final line of defense against overwhelming foes. The wearer gains <Link to="/umr/tremorsense">tremorsense</Link> with a range of up to 60 feet as long as she is standing on solid ground. Additionally, once per day, by stomping repeatedly on an earthen or stone surface as a full-round action that provokes attacks of opportunity, the wearer can cast <em>earthquake</em> as a spell-like ability.</p>
<h3 id="magic-wondrous-earthquake_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/earthquake">earthquake</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 33,750 gp</p>
</>};
const _feather_step_slippers = {title: "Feather Step Slippers", jsx: <><h2 id="magic-wondrous-feather_step_slippers-feather-step-slippers">Feather Step Slippers</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Once per day for 10 minutes, these fine silken slippers allow their wearer to ignore the adverse movement effects of <Link to="/rule/difficult_terrain">difficult terrain</Link> as if subject to the <em>feather step</em> spell, including granting the ability to take 5-foot steps in difficult terrain.</p>
<h3 id="magic-wondrous-feather_step_slippers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_step">feather step</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _fungal_slippers = {title: "Fungal Slippers", jsx: <><h2 id="magic-wondrous-fungal_slippers-fungal-slippers">Fungal Slippers</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 141</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>As a swift action up to three times per day, the wearer can create fungi in every square through which she walks during her turn. The fungi in these squares count as <Link to="/rule/difficult_terrain">difficult terrain</Link>. After 1 minute, most of the fungi disappear; those that remain provide no impediment.</p>
<h3 id="magic-wondrous-fungal_slippers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/entangle">entangle</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _getaway_boots = {title: "Getaway Boots", jsx: <><h2 id="magic-wondrous-getaway_boots-getaway-boots">Getaway Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 11th<br/><strong>Slot</strong> feet; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These rather nondescript boots can, once per day, be attuned to a location their wearer is standing upon. Once the boots are attuned to a location, once per day as a full-round action, the wearer, along with anything she is wearing or carrying, teleports back to the attuned location as the <em>getaway</em> spell, except that no allies are teleported when the boots are activated even if they were in the area when the boots were attuned to their location. Once the boots are attuned to a location, they continue to be attuned to the same location until they are attuned to a new location.</p>
<h3 id="magic-wondrous-getaway_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/getaway">getaway</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _ghungroos_of_entrancement = {title: "Ghungroos of Entrancement", jsx: <><h2 id="magic-wondrous-ghungroos_of_entrancement-ghungroos-of-entrancement">Ghungroos of Entrancement</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 225</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,750 gp; <strong>Weight</strong> -</p>
<p>Each of these musical anklets bears rows of tiny bells that accentuate the rhythmic elements of a trained dancer's performances and enhance an accompanying musical performance, fascinating her audiences. When using a <Link to="/performance/distraction">distraction</Link> bardic performance, the wearer gains a +5 competence bonus on <Link to="/skill/perform">Perform (dance)</Link> checks; when using a <Link to="/performance/fascinate">fascinate</Link> bardic performance, the wearer gains a +1 competence bonus to the saving throw DC. In addition, the wearer can use Perform (dance) with a <Link to="/performance/countersong">countersong</Link> bardic performance, and gains a +2 competence bonus on the Perform (dance) check.</p>
<p>The wearer takes a -2 penalty on <Link to="/skill/stealth">Stealth</Link> checks while wearing the ghungroos.</p>
<h3 id="magic-wondrous-ghungroos_of_entrancement-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hypnotism">hypnotism</Link>, creator must have bardic performance and 5 ranks in Perform (dance); <strong>Cost</strong> 1,875 gp</p>
</>};
const _gladiators_sandals = {title: "Gladiator's Sandals", jsx: <><h2 id="magic-wondrous-gladiators_sandals-gladiators-sandals">Gladiator's Sandals</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These sand-worn leather sandals are designed to lace around the calf and are favored by pit fighters and those who make careers out of performing in the ring. When the wearer acts during a surprise round and attempts any combat maneuver check, she gains a +4 circumstance bonus on that check. If the check is successful, the wearer can also attempt a <Link to="/rule/performance_combat">performance combat</Link> check with a +10 circumstance bonus to affect the crowd's attitude.</p>
<h3 id="magic-wondrous-gladiators_sandals-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _haunted_shoes = {title: "Haunted Shoes", jsx: <><h2 id="magic-wondrous-haunted_shoes-haunted-shoes">Haunted Shoes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link><br/><strong>Aura</strong> faint conjuration and illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,480 gp; <strong>Weight</strong> 1 lb.</p>
<p>Two times per day, the wearer of these shoes can call forth 1d4 spirit servants to aid her. The spirit servants are invisible, mindless, shapeless beings that act as servants summoned by the <em>unseen servant</em> spell. The spirits return to the shoes after 3 hours have passed. The wearer can choose to dismiss one or more of the spirit servants early.</p>
<p>Once per day, the wearer can command the ghostly spirits inside her haunted shoes to emerge and swirl around her, making her difficult to target in combat. The wearer gains <Link to="/rule/concealment">concealment</Link> (20% miss chance) for 3 minutes. The spirits cannot be harmed, but a <Link to="/spell/true_seeing">true seeing</Link> spell ignores the concealment effect. The concealment effect cannot be activated while any of the spirits are currently being used as unseen servants.</p>
<h3 id="magic-wondrous-haunted_shoes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/blur">blur</Link>, <Link to="/spell/unseen_servant">unseen servant</Link>; <strong>Cost</strong> 3,240 gp</p>
</>};
const _horseshoes_of_a_zephyr = {title: "Horseshoes of a Zephyr", jsx: <><h2 id="magic-wondrous-horseshoes_of_a_zephyr-horseshoes-of-a-zephyr">Horseshoes of a Zephyr</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 520</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>These shining, silvery horseshoes bear designs of swift-moving clouds and anthropomorphized images of the wind. When affixed to a horse, these horseshoes allow the horse to travel without actually touching the ground. The horse must still run above (always around 4 inches above) a roughly horizontal surface. This means that the horse can cross non-solid or unstable surfaces such as water, and that it can move without leaving tracks on any sort of ground. The horse moves at its normal base land speed. All four shoes must be worn by the same animal for the magic to be effective.</p>
<h3 id="magic-wondrous-horseshoes_of_a_zephyr-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/levitate">levitate</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _horseshoes_of_crushing_blows = {title: "Horseshoes of Crushing Blows", jsx: <><h2 id="magic-wondrous-horseshoes_of_crushing_blows-horseshoes-of-crushing-blows">Horseshoes of Crushing Blows</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 125</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,000 gp (+1), 16,000 gp (+2), 36,000 gp (+3), 64,000 gp (+4), 100,000 gp (+5); <strong>Weight</strong> 4 lbs.</p>
<p>Horseshoes of crushing blows grant an enhancement bonus on attack and damage rolls made with hoof attacks; this bonus varies based on the item's price. Alternatively, as described for the <Link to="/magic-wondrous/amulet_of_mighty_fists">amulet of mighty fists</Link>, they can grant hooves melee weapon special abilities so long as they can be applied to unarmed attacks. Horseshoes of crushing blows cannot have a modified bonus (enhancement bonus plus special ability bonus equivalents) higher than +5. Horseshoes of crushing blows are crafted as sets of four, with each shoe in the set bearing the same enhancements. All four shoes must be worn by the same animal to be effective.</p>
<p>Horseshoes of crushing blows may be crafted out of special materials, gaining the usual benefits. For purposes of pricing, they count as a single one-handed weapon weighing 4 pounds (for example, <Link to="/eq-material/adamantine">adamantine</Link> horseshoes of crushing blows would cost an additional 3,000 gp). The materials needed to make <Link to="/eq-material/cold_iron">cold iron</Link> horseshoes of crushing blows add no extra costs in and of themselves, but enhancing cold iron horseshoes of crushing blows increases the price by the usual 2,000 gp.</p>
<h3 id="magic-wondrous-horseshoes_of_crushing_blows-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator's caster level must be at least three times the horseshoes' bonus, plus any requirements of the melee weapon special abilities; <strong>Cost</strong> 2,000 gp (+1), 8,000 gp (+2), 18,000 gp (+3), 32,000 gp (+4), 50,000 gp (+5)</p>
</>};
const _horseshoes_of_desert_fury_keleshite = {title: "Horseshoes of Desert Fury (Keleshite)", jsx: <><h2 id="magic-wondrous-horseshoes_of_desert_fury_keleshite-horseshoes-of-desert-fury-keleshite">Horseshoes of Desert Fury (Keleshite)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 232</Link><br/><strong>Aura</strong> moderate conjuration and evocation; <strong>CL</strong> 8th<br/><strong>Slot</strong> feet; <strong>Price</strong> 88,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>The following wondrous item is generally available only to members of the indicated race or ethnicity.</p>
<p>This set of horseshoes is inscribed with binding runes to contain the essence of a minor spirit of fire. With a command word from the wearer or the wearer's rider, the horseshoes burst into flames which do not harm the wearer, but cause the wearer's hooves to function as +1 <Link to="/magic-enh/flaming">flaming</Link> weapons for the duration of the effect. The flames can remain active for up to 80 minutes. The duration need not be consecutive, but must be spent in 10-minute increments.</p>
<p>Three times per day, a Keleshite wearer or rider can speak another command word to cause the horseshoes to kick up a cloud of choking sand similar to <em>solid fog</em> centered on the wearer's current position; the sand builds up gradually and doesn't impede movement until the wearer exits the affected area, at which point it immediately takes effect. Creatures that begin their turn in the area of the sand must succeed at a DC 16 Fortitude save or be <Link to="/misc/sickened">sickened</Link> for as long as they remain in the area and for 1d4 minutes thereafter.</p>
<h3 id="magic-wondrous-horseshoes_of_desert_fury_keleshite-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/flame_blade">flame blade</Link>, <Link to="/spell/magic_fang">magic fang</Link>, <Link to="/spell/solid_fog">solid fog</Link>, creator must be a Keleshite; <strong>Cost</strong> 44,000 gp</p>
</>};
const _horseshoes_of_glory = {title: "Horseshoes of Glory", jsx: <><h2 id="magic-wondrous-horseshoes_of_glory-horseshoes-of-glory">Horseshoes of Glory</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 231</Link><br/><strong>Aura</strong> moderate abjuration and transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> feet; <strong>Price</strong> 39,600 gp; <strong>Weight</strong> 12 lbs.</p>
<p>These massive horseshoes sport deadly spikes that jut from their front. Once per day on command, the rider of a mount wearing these shoes may choose to either increase the mount's size by one size increment (maximum Huge), or change its type to magical beast, as <em>beast shape IV.</em> In addition, while the mount is augmented in either of these two ways, it gains DR/5 chaos, evil, good, or law (selected by the rider). These horseshoes are part of a set and require all four to be worn by the same animal to properly function.</p>
<h3 id="magic-wondrous-horseshoes_of_glory-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/beast_shape_iv">beast shape IV</Link>, <Link to="/spell/magic_circle_against_chaos_evil_good_law">magic circle against chaos/evil/good/law</Link>; <strong>Cost</strong> 19,800 gp</p>
</>};
const _horseshoes_of_great_burden = {title: "Horseshoes of Great Burden", jsx: <><h2 id="magic-wondrous-horseshoes_of_great_burden-horseshoes-of-great-burden">Horseshoes of Great Burden</h2>
<p><strong>Sources</strong> <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 55</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 24 lbs. (for four)</p>
<p>These sturdy iron horseshoes come in sets of four like ordinary horseshoes, but are much heavier. When affixed to an animal's hooves, they double the animal's carrying capacity. All four shoes must be worn by the same animal for the magic to be effective.</p>
<h3 id="magic-wondrous-horseshoes_of_great_burden-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _horseshoes_of_mist = {title: "Horseshoes of Mist", jsx: <><h2 id="magic-wondrous-horseshoes_of_mist-horseshoes-of-mist">Horseshoes of Mist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>When a horse is shod with these horseshoes, they give off a puff of mist each time a hoof strikes the earth. On the rider's command, the mount and the rider are both affected as if subject to a <em>gaseous form</em> spell. If for some reason the rider and the mount become separated from one another while in <em>gaseous form,</em> the effect automatically ends for both. The horseshoes can be used for 10 minutes per day. The duration need not be consecutive, but it must be spent in 1-minute increments.</p>
<h3 id="magic-wondrous-horseshoes_of_mist-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gaseous_form">gaseous form</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _horseshoes_of_sacred_silver = {title: "Horseshoes of Sacred Silver", jsx: <><h2 id="magic-wondrous-horseshoes_of_sacred_silver-horseshoes-of-sacred-silver">Horseshoes of Sacred Silver</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 26</Link><br/><strong>Aura</strong> moderate evocation [good]; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 4 lbs.</p>
<p>These <Link to="/eq-material/mithral">mithral</Link> horseshoes are imbued with heavenly power. They grant the <Link to="/magic-enh/holy">holy</Link> weapon special ability to the wearer's hoof attacks, and if the wearer hits an evil-aligned target with both hooves in the same round, the target is <Link to="/misc/staggered">staggered</Link> for 1 round (Fortitude DC 16 negates). In addition, the wearer gains a +2 sacred bonus on <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/drag">drag</Link>, and <Link to="/rule/overrun">overrun</Link> combat maneuvers. If the wearer is a mount and the rider uses the <Link to="/feat/trample">Trample</Link> feat, add 2 to the rider's overrun combat maneuver check. If the wearer uses the <Link to="/umr/trample">trample</Link> special ability, increase the trample DC by 2; if the target fails its save against the trample attempt, add the damage from the holy weapon special ability to the trample damage.</p>
<h3 id="magic-wondrous-horseshoes_of_sacred_silver-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/holy_smite">holy smite</Link>, creator must be good; <strong>Cost</strong> 10,000 gp</p>
</>};
const _horseshoes_of_speed = {title: "Horseshoes of Speed", jsx: <><h2 id="magic-wondrous-horseshoes_of_speed-horseshoes-of-speed">Horseshoes of Speed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 519</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>When affixed to an animal's hooves, these iron horseshoes increase the animal's base land speed by 30 feet; this counts as an enhancement bonus. As with other effects that increase speed, <Link to="/skill/acrobatics">jumping</Link> distances increase proportionally. All four shoes must be worn by the same animal for the magic to be effective.</p>
<h3 id="magic-wondrous-horseshoes_of_speed-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _jaunt_boots = {title: "Jaunt Boots", jsx: <><h2 id="magic-wondrous-jaunt_boots-jaunt-boots">Jaunt Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These stylish black leather boots are stitched with images of winding roads and trails through peaceful orchards. They can be worn up to mid-thigh, or have their cuffs turned down to make knee-high boots. Three times per day, as a move action, the wearer can move up to 15 feet (or her movement speed if it's less than 15 feet). This movement does not provoke attacks of opportunity.</p>
<h3 id="magic-wondrous-jaunt_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/jesters_jaunt">jester's jaunt</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _jungle_boots = {title: "Jungle Boots", jsx: <><h2 id="magic-wondrous-jungle_boots-jungle-boots">Jungle Boots</h2>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft leather boots grant the wearer the ability to move through normal undergrowth without hindrance as if she had the <Link to="/ability/woodland_stride">woodland stride</Link> ability.</p>
<h3 id="magic-wondrous-jungle_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/longstrider">longstrider</Link>, woodland stride ability; <strong>Cost</strong> 3,000 gp</p>
</>};
const _nightmare_boots = {title: "Nightmare Boots", jsx: <><h2 id="magic-wondrous-nightmare_boots-nightmare-boots">Nightmare Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link><br/><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 3 lbs.</p>
<p>Prized by evil warriors, these boots are made of inky black leather trimmed with a crimson mane of fiendish horsehair. Some bear the hair of actual <Link to="/monster/nightmare">nightmares</Link> along their rims, causing them to occasionally flare and crackle with flames reminiscent of the foul equines. When the wearer <Link to="/rule/run">runs</Link> or <Link to="/rule/charge">charges</Link>, smoke issues up from the boots, acting as <Link to="/rule/concealment">concealment</Link> (20% miss chance) when the wearer provokes attacks of opportunity while making those actions. Secondly, three times per day, as a swift action, the wearer can make the boots smoke, which grants her concealment until the end of her turn. Lastly, once per day, when the wearer hits a creature with a melee attack, she can command the boots to ignite. When the boots ignite, all creatures within a 5-foot radius take 2d6 points of fire damage. A DC 13 Reflex saving throw halves the damage.</p>
<h3 id="magic-wondrous-nightmare_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/burning_hands">burning hands</Link>, <Link to="/spell/pyrotechnics">pyrotechnics</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _nightmare_horseshoes = {title: "Nightmare Horseshoes", jsx: <><h2 id="magic-wondrous-nightmare_horseshoes-nightmare-horseshoes">Nightmare Horseshoes</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link><br/><strong>Aura</strong> moderate conjuration and transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 12 lbs.</p>
<p>These horseshoes are made of blackened steel and are typically stamped with infernal symbols or, less subtly, horrific images of terrified and tortured steeds of the darkest hues. They typically give off a slight smell of brimstone, as though they had been crafted in some hellish forge. On command, the mount's rider may grant it the <em>smoke</em> supernatural ability of a <Link to="/monster/nightmare">nightmare</Link> (see below). The horseshoes can be used for 10 rounds per day, split up as the mount's rider chooses (minimum 1 round per use). While this power is activated, the mount's eyes, hooves, mane, and tail burst into flame, and its hooves deal an extra 1d4 points of fire damage.</p>
<blockquote>
<p><strong>Smoke (Su)</strong> In battle, a nightmare exhales smoke that chokes and blinds foes, filling a 15-foot cone each round as a free action. Anyone in the cone must succeed on a DC 16 Fortitude save or become <Link to="/misc/sickened">sickened</Link> until 1d6 minutes after leaving the area. This smoke acts as <Link to="/spell/obscuring_mist">obscuring mist</Link> for the purposes of <Link to="/rule/concealment">concealment</Link>. The smoke persists for 1 round. The save DC is Constitution-based.</p>
</blockquote>
<h3 id="magic-wondrous-nightmare_horseshoes-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/burning_hands">burning hands</Link>, <Link to="/spell/obscuring_mist">obscuring mist</Link>, <Link to="/spell/stinking_cloud">stinking cloud</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _quick_action_slippers = {title: "Quick Action Slippers", jsx: <><h2 id="magic-wondrous-quick_action_slippers-quick-action-slippers">Quick Action Slippers</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 25</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of a pair of quick action slippers may stand up from <Link to="/rule/prone">prone</Link> as a free action. Such movement still provokes attacks of opportunity as normal. If the wearer has the <Link to="/talent/stand_up">stand up</Link> rogue talent, the act of standing up from prone no longer provokes attacks of opportunity.</p>
<h3 id="magic-wondrous-quick_action_slippers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, creator must have the stand up rogue talent; <strong>Cost</strong> 5,000 gp</p>
</>};
const _rat_tread_boots = {title: "Rat-Tread Boots", jsx: <><h2 id="magic-wondrous-rat_tread_boots-rat-tread-boots">Rat-Tread Boots</h2>
<p><strong>Sources</strong> <Link to="/source/tears_at_bitter_manor">Tears at Bitter Manor pg. 55</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>On command, these rat-fur boots summon a <Link to="/monster/rat_swarm">rat swarm</Link> underneath the wearer that moves with her and acts as a living carpet. As a move action, the wearer can travel on the backs of the rats as they swim, moving up to 15 feet across the surface of calm waters. If surface conditions become worse than calm, the rats disperse and the wearer falls. On land, the swarm allows the wearer to ignore difficult terrain's effects on her movement for up to 15 feet of movement per round. The swarm can be used for up to 10 minutes per day. This duration doesn't need to be continuous, but must be used in 1-minute increments.</p>
<p>If the wearer falls unconscious while rat-tread boots are active, on the wearer's next turn the swarm tries to move her away from the nearest foe, moving 5 feet before dispersing. This movement doesn't provoke attacks of opportunity. If such movement is impossible, the swarm disperses.</p>
<p>The swarm is a normal rat swarm, except its area doesn't exceed that of the wearer and it can't move out of the wearer's space. The swarm disperses when the effect's duration ends or when the swarm is reduced to 0 hit points or fewer. Rat-tread boots grant the wearer immunity from the attacks of rat swarms, including their special attacks.</p>
<h3 id="magic-wondrous-rat_tread_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/charm_animal">charm animal</Link>, <Link to="/spell/summon_swarm">summon swarm</Link>; <strong>Cost</strong> 4,250 gp</p>
</>};
const _rebuilders_boots = {title: "Rebuilder's Boots", jsx: <><h2 id="magic-wondrous-rebuilders_boots-rebuilders-boots">Rebuilder's Boots</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 7</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> feet; <strong>Price</strong> 14,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>Long ago, engineers in Anuli wore pairs of these sturdy brown leather boots to navigate the city after the Paroxsys tore apart the land. The wearer of these boots gains a +5 competence bonus on <Link to="/skill/craft">Craft</Link> checks to repair items. Additionally, as a move action, the wearer of a pair of rebuilder's boots can activate them to move up to her land speed and ignore any adverse movement effects of <Link to="/rule/difficult_terrain">difficult terrain</Link>, as per the effects of the <em>feather step</em> spell. This effect lasts for 40 minutes per day or until the wearer ends it as a free action. The wearer need not spend this duration all at once, but she must spend it in 1-minute increments.</p>
<h3 id="magic-wondrous-rebuilders_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/crafters_fortune">crafter's fortune</Link>, <Link to="/spell/feather_step">feather step</Link>; <strong>Cost</strong> 7,250 gp</p>
</>};
const _rime_stride_boots = {title: "Rime-Stride Boots", jsx: <><h2 id="magic-wondrous-rime_stride_boots-rime-stride-boots">Rime-Stride Boots</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 27</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> feet; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> -</p>
<p>These fur-lined boots grant the wearer the ability to glide easily across icy surfaces. While doing so, the wearer adds 15 feet to her speed, and she does not need to make <Link to="/skill/acrobatics">Acrobatics</Link> checks to run or charge on ice. While fighting on ice, the wearer gains a +2 circumstance bonus on combat maneuver checks and to CMD.</p>
<p>Once per day, the wearer may cause all surfaces within a 30-foot radius of himself to become covered in a thin sheet of ice for 10 rounds. A creature can walk within or through this icy area at half normal speed with a successful DC 10 Acrobatics check. Failure means it can't move in that round, while failure by 5 or more means it falls. A creature using Acrobatics in this way is considered <Link to="/rule/flat_footed">flat-footed</Link> and loses its Dexterity bonus to AC.</p>
<h3 id="magic-wondrous-rime_stride_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>, <Link to="/spell/sleet_storm">sleet storm</Link>; <strong>Cost</strong> 13,500 gp</p>
</>};
const _rootsense_boots = {title: "Rootsense Boots", jsx: <><h2 id="magic-wondrous-rootsense_boots-rootsense-boots">Rootsense Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 251</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Twigs sprout from these tall brown boots. On command, while the wearer is on the ground, ghostly roots grow from the boots' soles into the ground, granting their wearer <Link to="/umr/tremorsense">tremorsense</Link> 30 feet for as long the wearer remains on the ground in the same space.</p>
<p>While the roots are active, the boots provide two additional benefits. When the wearer is the target of a <Link to="/rule/bull_rush">bull rush</Link> or <Link to="/rule/trip">trip</Link> attempt, living roots momentarily sprout from the boots into the earth, granting the wearer a +4 bonus to CMD to resist the attempt. The wearer also benefits from the flexibility of a living willow branch, gaining a +4 circumstance bonus on combat maneuver or <Link to="/skill/escape_artist">Escape Artist</Link> checks to escape a grapple or slip bonds.</p>
<h3 id="magic-wondrous-rootsense_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/entangle">entangle</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _sandals_of_interception = {title: "Sandals of Interception", jsx: <><h2 id="magic-wondrous-sandals_of_interception-sandals-of-interception">Sandals of Interception</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These simple wooden sandals allow their wearer to step in the way of danger to protect her allies. Three times per day as an immediate action, the wearer can take a 5-foot step to move into the path of a ranged attack and treat herself as the target of the ranged attack that passes through her square for the purposes of <Link to="/feat/deflect_arrows">Deflect Arrows</Link>, <Link to="/feat/snatch_arrows">Snatch Arrows</Link>, <Link to="/feat/missile_shield">Missile Shield</Link>, and other feats and abilities that allow her to deflect ranged attacks. If she lacks a feat or ability that would allow her to deflect the ranged attack, the wearer is instead simply struck by the attack regardless of the attack roll's result or her AC. The wearer can't take a 5-foot step during the turn after using this ability.</p>
<h3 id="magic-wondrous-sandals_of_interception-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Deflect Arrows, <Link to="/spell/deflection">deflection</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _sandals_of_quick_reaction = {title: "Sandals of Quick Reaction", jsx: <><h2 id="magic-wondrous-sandals_of_quick_reaction-sandals-of-quick-reaction">Sandals of Quick Reaction</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These supple leather sandals grant a burst of speed during times of duress. When the wearer acts during a surprise round, he can take a standard and a move action during the surprise round. If the wearer already has the ability to take a standard and a move action during the surprise round, he instead gains a +10 circumstance bonus to speed when acting during a surprise round.</p>
<h3 id="magic-wondrous-sandals_of_quick_reaction-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/anticipate_peril">anticipate peril</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _sandals_of_the_lightest_step = {title: "Sandals of the Lightest Step", jsx: <><h2 id="magic-wondrous-sandals_of_the_lightest_step-sandals-of-the-lightest-step">Sandals of the Lightest Step</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 232</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 54</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These soft leather sandals have soles that consist of a layer of purple velvet decorated with intricate gold stitching. When slipped onto the feet, they feel as weightless as air. In any round when the wearer has already moved at least 10 feet along the ground or another surface (not counting travel on a mount or vehicle), these boots can be activated as a swift action to give the wearer the ability to walk on air (as the <em>air walk</em> spell) until the end of the round. If the wearer hasn't reached a solid surface by the end of the round, she immediately falls back to the ground, taking any applicable <Link to="/rule/falling">falling</Link> damage. These sandals can be used up to 5 times per day, but no more often than once per minute.</p>
<h3 id="magic-wondrous-sandals_of_the_lightest_step-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/air_walk">air walk</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _sandstorm_sandals = {title: "Sandstorm Sandals", jsx: <><h2 id="magic-wondrous-sandstorm_sandals-sandstorm-sandals">Sandstorm Sandals</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 63</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These sandals are made of cloth and animal hide stitched to wood blocks that elevate them an inch off the ground. <Link to="/class/monk">Monks</Link> often wear them as they roam across the deserts of northern Garund, traveling with no food or water to perfect their physical forms. The wearer of sandstorm sandals leaves no trace while traveling in desert environments.</p>
<p>If the wearer possesses the flurry of blows class feature, anytime he makes an unarmed flurry of blows while standing on sand or dirt, a minor storm appears around him for 1 round. Any creature that ends its movement within 5 feet of the wearer during this time takes 1 point of nonlethal damage. While the storm is active, the sandals' wearer gains <Link to="/rule/concealment">concealment</Link> (20% miss chance).</p>
<h3 id="magic-wondrous-sandstorm_sandals-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _seafarers_waders = {title: "Seafarer's Waders", jsx: <><h2 id="magic-wondrous-seafarers_waders-seafarers-waders">Seafarer's Waders</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 25</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,350 gp; <strong>Weight</strong> 1 lb.</p>
<p>These slightly discolored leather boots come up to the wearer's knees and are covered with small barnacles. When they are worn, the boots grant their wearer a +2 competence bonus on <Link to="/skill/acrobatics">Acrobatics</Link>, <Link to="/skill/climb">Climb</Link>, and <Link to="/skill/swim">Swim</Link> checks. In addition, once per day, the wearer can say a command word to gain the effects of <em>spider climb</em> for up to 30 minutes. This effect can be dismissed as a free action.</p>
<h3 id="magic-wondrous-seafarers_waders-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/jump">jump</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 1,675 gp</p>
</>};
const _seven_league_boots = {title: "Seven-League Boots", jsx: <><h2 id="magic-wondrous-seven_league_boots-seven-league-boots">Seven-League Boots</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 156</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 10th<br/><strong>Slot</strong> feet; <strong>Price</strong> 80,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These well-worn boots act as <Link to="/magic-wondrous/boots_of_speed">boots of speed</Link> combined with <Link to="/magic-wondrous/boots_of_striding_and_springing">boots of striding and springing</Link>. The wearer can expend one use of mythic power as a move action to take a 7-league step. The steps functions as teleportation with a 21-mile range, except the wearer must have an uninterrupted path to her intended destination, though this path doesn't have to follow a straight line. Harmful environments between the wearer and the destination cause her no harm.</p>
<p>If the wearer's path is blocked, her travel ends just short of the obstacle blocking her. If she tries to step too far, she appears in the closest available space to her destination without going beyond 21 miles of where she started.</p>
<h3 id="magic-wondrous-seven_league_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 40,000 gp</p>
</>};
const _shoes_of_lightning_leaping = {title: "Shoes of Lightning Leaping", jsx: <><h2 id="magic-wondrous-shoes_of_lightning_leaping-shoes-of-lightning-leaping">Shoes of Lightning Leaping</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These short black shoes fit tightly around the wearer's feet and bear designs of leaping arcs of lightning and wild winds. Once per day on command, a creature wearing these boots can transform into lightning and move up to 50 feet in a straight line, re-materializing at the far end of the lightning bolt. Creatures in the path of the lightning take 6d6 points of electricity damage and objects take damage as per the <em>lightning bolt</em> spell. If the lightning strikes an object or barrier and fails to burst through it, the creature wearing the boots appears next to the impacted object and is <Link to="/misc/staggered">staggered</Link> for 1 round. Movement while in lightning form does not provoke attacks of opportunity.</p>
<h3 id="magic-wondrous-shoes_of_lightning_leaping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_retreat">expeditious retreat</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>; <strong>Cost</strong> 5,250 gp</p>
</>};
const _shoes_of_the_firewalker = {title: "Shoes of the Firewalker", jsx: <><h2 id="magic-wondrous-shoes_of_the_firewalker-shoes-of-the-firewalker">Shoes of the Firewalker</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 6th<br/><strong>Slot</strong> feet; <strong>Price</strong> 21,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These low-cut shoes of polished red leather feature golden eyelets and stitching in a fiery pattern. They grant the wearer fire resistance 10 and allow the wearer to walk atop lava and magma as if subject to the <em>water walk</em> spell.</p>
<h3 id="magic-wondrous-shoes_of_the_firewalker-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/water_walk">water walk</Link>; <strong>Cost</strong> 10,500 gp</p>
</>};
const _slippers_of_cloudwalking = {title: "Slippers of Cloudwalking", jsx: <><h2 id="magic-wondrous-slippers_of_cloudwalking-slippers-of-cloudwalking">Slippers of Cloudwalking</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 11th<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,400 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these slippers may walk on air (as the spell <Link to="/spell/air_walk">air walk</Link>) for up to 10 minutes per day, which may be used in 1-minute increments and requires no action to activate. However, she may only walk on air within or on top of natural or magical mist or fog, including fog-like gases such as those created by <Link to="/spell/acid_fog">acid fog</Link>, <Link to="/spell/cloudkill">cloudkill</Link>, <Link to="/spell/incendiary_cloud">incendiary cloud</Link>, or <Link to="/spell/stinking_cloud">stinking cloud</Link>. Walking on top of such clouds carries no danger for the wearer, but walking through the cloud has its normal effect.</p>
<h3 id="magic-wondrous-slippers_of_cloudwalking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/wind_walk">wind walk</Link>; <strong>Cost</strong> 2,200 gp</p>
</>};
const _slippers_of_scampering = {title: "Slippers of Scampering", jsx: <><h2 id="magic-wondrous-slippers_of_scampering-slippers-of-scampering">Slippers of Scampering</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 237</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> feet; <strong>Price</strong> 1,200 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>Slippers of scampering function in almost every way like <Link to="/magic-wondrous/slippers_of_spider_climbing">slippers of spider climbing</Link>, except the slippers can be used for 10 rounds per day, split up as the wearer chooses (minimum 1 round per use).</p>
<h3 id="magic-wondrous-slippers_of_scampering-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 600 gp</p>
</>};
const _slippers_of_spider_climbing = {title: "Slippers of Spider Climbing", jsx: <><h2 id="magic-wondrous-slippers_of_spider_climbing-slippers-of-spider-climbing">Slippers of Spider Climbing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 530</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,800 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>When worn, a pair of these slippers enables movement on vertical surfaces or even upside down along ceilings, leaving the wearer's hands free. Her climb speed is 20 feet. Severely slippery surfaces - icy, oiled, or greased surfaces - make these slippers useless. The slippers can be used for 10 minutes per day, split up as the wearer chooses (minimum 1 minute per use).</p>
<h3 id="magic-wondrous-slippers_of_spider_climbing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 2,400 gp</p>
</>};
const _slippers_of_the_primordial_wilds = {title: "Slippers of the Primordial Wilds", jsx: <><h2 id="magic-wondrous-slippers_of_the_primordial_wilds-slippers-of-the-primordial-wilds">Slippers of the Primordial Wilds</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 14</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 24,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These fine, supple slippers are made from giant cowslip petals. The wearer cannot be tracked or otherwise detected by <Link to="/umr/scent">scent</Link>. When standing with one foot in one terrain and the other in another terrain (such as at a cave mouth, a shore, or a forest's edge), a <Link to="/race/gathlain">gathlain</Link> wearer can speak a command word to move to either the Material Plane or the First World, as per <em>plane shift,</em> twice per day.</p>
<h3 id="magic-wondrous-slippers_of_the_primordial_wilds-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plane_shift">plane shift</Link>; <strong>Cost</strong> 12,000 gp</p>
</>};
const _slippers_of_the_triton = {title: "Slippers of the Triton", jsx: <><h2 id="magic-wondrous-slippers_of_the_triton-slippers-of-the-triton">Slippers of the Triton</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link>, <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 178</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 56,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These slippers allow the wearer to breathe water. Additionally, if the wearer has no swim speed, she gains a 30 foot swim speed. If the wearer has a swim speed, she gains a +10 foot enhancement bonus to her swim speed.</p>
<h3 id="magic-wondrous-slippers_of_the_triton-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ride_the_waves">ride the waves</Link>; <strong>Cost</strong> 28,000 gp</p>
</>};
const _snowshoes_of_northern_pursuit = {title: "Snowshoes of Northern Pursuit", jsx: <><h2 id="magic-wondrous-snowshoes_of_northern_pursuit-snowshoes-of-northern-pursuit">Snowshoes of Northern Pursuit</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_67_the_snows_of_summer">Pathfinder #67: The Snows of Summer pg. 61</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 4,300 gp; <strong>Weight</strong> 4 lbs.</p>
<p>These masterwork snowshoes provide greater stability and weight distribution in snow. The snowshoes completely negate the effects of normal snow on movement, and reduce the movement penalties in <Link to="/rule/rain_snow_sleet_and_hail">heavy snow</Link> by half (i.e., it only costs 2 squares of movement to enter a square covered with heavy snow instead of 4 squares of movement). In addition, the wearer can increase her land speed in snowy terrain by 10 feet for up to 10 rounds per day. This is considered an enhancement bonus and the duration need not be spent in consecutive rounds. Finally, as a standard action once per day, the snowshoes can generate a ripple effect that removes all trace of tracks left in the snow in a 60-foot radius.</p>
<h3 id="magic-wondrous-snowshoes_of_northern_pursuit-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/feather_step">feather step</Link>, <Link to="/spell/longstrider">longstrider</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>; <strong>Cost</strong> 2,150 gp</p>
</>};
const _soles_of_the_silent_stride = {title: "Soles of the Silent Stride", jsx: <><h2 id="magic-wondrous-soles_of_the_silent_stride-soles-of-the-silent-stride">Soles of the Silent Stride</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 27</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> feet; <strong>Price</strong> 8,250 gp; <strong>Weight</strong> -</p>
<p>These simple leather shoes are the color of a moonless night and instantly adjust to the wearer's foot shape, becoming skintight while providing magical cushioning and support. The wearer gains a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks and can attempt Stealth checks while running at a -20 penalty.</p>
<h3 id="magic-wondrous-soles_of_the_silent_stride-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/silence">silence</Link>; <strong>Cost</strong> 4,125 gp</p>
</>};
const _stagger_proof_boots = {title: "Stagger-Proof Boots", jsx: <><h2 id="magic-wondrous-stagger_proof_boots-stagger-proof-boots">Stagger-Proof Boots</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 270</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These calf-high leather boots are inscribed with <Link to="/faith/cayden_cailean">Cayden Cailean's</Link> holy symbol. The wearer can stand up from <Link to="/rule/prone">prone</Link> without provoking attacks of opportunity and gains a +4 bonus to CMD against <Link to="/rule/bull_rush">bull rush</Link> and <Link to="/rule/trip">trip</Link> combat maneuvers. Once per day as an immediate action, the wearer can move up to 30 feet; this movement provokes attacks of opportunity as normal.</p>
<h3 id="magic-wondrous-stagger_proof_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _stonemeld_boots = {title: "Stonemeld Boots", jsx: <><h2 id="magic-wondrous-stonemeld_boots-stonemeld-boots">Stonemeld Boots</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 8</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> feet; <strong>Price</strong> 3,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of a pair of stonemeld boots gains a +4 bonus to CMD against <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/drag">drag</Link>, <Link to="/rule/reposition">reposition</Link>, and <Link to="/rule/trip">trip</Link> combat maneuvers. Additionally, once per day as a swift action, the boots can be activated to grant the wearer a climb speed of 10 feet on any natural stone surface (but not manufactured stone surfaces like brick walls) for 30 minutes. A creature using stonemeld boots to climb in this fashion leaves obvious deformities in the rock surface. Anyone attempting to <Link to="/skill/survival">track</Link> a wearer of stonemeld boots moving in this fashion treats the base DC as though the tracks were left in soft earth, and takes no penalties for time elapsed since the tracks were made.</p>
<h3 id="magic-wondrous-stonemeld_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link>; <strong>Cost</strong> 1,750 gp</p>
</>};
const _subtle_slippers = {title: "Subtle Slippers", jsx: <><h2 id="magic-wondrous-subtle_slippers-subtle-slippers">Subtle Slippers</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 45</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 5,500 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These worn, shapeless leather slippers magically shrink or enlarge to fit any foot placed within, and are as comfortable as a well-broken-in pair of boots. When worn by a <Link to="/race/halfling">halfling</Link>, the slippers fade from view almost entirely, manifesting as strips of soft leather wound around the ankles so as to allow the halfling to enjoy the comforts of being barefoot while still wearing them.</p>
<p>A pair of subtle slippers conceal their wearer's passage, leaving no footprints or scent trail, as per the spell <em>pass without trace,</em> regardless of terrain. They also grant the wearer a +5 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. Once per day as a standard action, a character wearing subtle slippers can select up to four other creatures within 30 feet to gain a +5 competence bonus on Stealth checks. This bonus lasts for 1 hour, but is suppressed for any creature who moves more than 30 feet away from the character wearing the slippers. If that creature returns to a position within 30 feet of the wearer of the slippers before the effect's duration expires, the bonus reactivates for that character. The effect ends at once for all affected if the wearer of the slippers removes the footwear, is knocked unconscious, or is killed.</p>
<h3 id="magic-wondrous-subtle_slippers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/pass_without_trace">pass without trace</Link>; <strong>Cost</strong> 2,750 gp</p>
</>};
const _tremor_boots = {title: "Tremor Boots", jsx: <><h2 id="magic-wondrous-tremor_boots-tremor-boots">Tremor Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These brown leather boots have a reinforced toe of steel with grooves along the soles, crafted to help the wearer pick up vibrations from the surrounding environment. These boots grant the wearer <Link to="/umr/tremorsense">tremorsense</Link> 5 feet as long as he is standing on solid ground.</p>
<h3 id="magic-wondrous-tremor_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/see_invisibility">see invisibility</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _unctuous_waders = {title: "Unctuous Waders", jsx: <><h2 id="magic-wondrous-unctuous_waders-unctuous-waders">Unctuous Waders</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_122_into_the_shattered_continent">Pathfinder #122: Into the Shattered Continent pg. 78</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 67,200 gp; <strong>Weight</strong> 6 lbs.</p>
<p>Created by a race of unknown undersea creatures only passingly familiar with humanoid physiology, these tall, uncomfortable boots are made of slimy skin that wriggles slightly. The boots function as <Link to="/magic-wondrous/slippers_of_the_triton">slippers of the triton</Link>, allowing the wearer to breathe and swim underwater. The boots constantly murmur telepathically to the wearer, alternating between sycophantic praise of the wearer's prowess and smug assurance that the boots will ensure that the wearer comes to no harm while underwater. The unctuous waders urge the wearer to explore beneath the waves, hoping to find some clues as to their creators and purpose, which the boots have long ago forgotten. If the wearer goes for more than a week without submerging herself in the ocean, the unctuous waders become less obsequious and more demanding. The unctuous waders can remove the ability to allow the wielder to breathe underwater, which they might do as a threat to compel obedience, or out of mere petulance.</p>
<p>Three times per day as a standard action, the unctuous waders can exude slimy water from the heels to propel the user, as the <em>slipstream</em> spell.</p>
<h3 id="magic-wondrous-unctuous_waders-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/ride_the_waves">ride the waves</Link>, <Link to="/spell/slipstream">slipstream</Link>; <strong>Cost</strong> 36,600 gp</p>
</>};
const _uplifting_boots = {title: "Uplifting Boots", jsx: <><h2 id="magic-wondrous-uplifting_boots-uplifting-boots">Uplifting Boots</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 23</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> feet; <strong>Price</strong> 11,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These worn, leather traveling boots respond to the wearer's holy power. The wearer can sacrifice one use of <Link to="/ability/channel_energy">channel energy</Link>, <Link to="/ability/lay_on_hands">lay on hands</Link>, or <Link to="/class/fervor">fervor</Link> as a standard action to instead walk on air (as per the <em>air walk</em> spell) for the next minute.</p>
<h3 id="magic-wondrous-uplifting_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>; <Link to="/spell/air_walk">air walk</Link>; creator must have the channel energy, lay on hands, or fervor class ability; <strong>Cost</strong> 5,500 gp</p>
</>};
const _verdant_boots = {title: "Verdant Boots", jsx: <><h2 id="magic-wondrous-verdant_boots-verdant-boots">Verdant Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> feet; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>The wearer of these boots can, on command three times per day, cause her current square to sprout a thick canopy of fruit-bearing or otherwise edible plants. These plants count as <Link to="/rule/difficult_terrain">difficult terrain</Link> and grant <Link to="/rule/cover">cover</Link> to any Medium or smaller creature within the square. They also provide enough food to sustain two Medium creatures for 1 full day. While the plants can grow on surfaces that would not normally support vegetation such as a wooden floor or cave stone, they cannot sprout on surfaces explicitly hostile to vegetation. The plants are usually of a sort common to the terrain or climate of the area in which they were produced. They disappear after 24 hours or when completely harvested, whichever comes first.</p>
<h3 id="magic-wondrous-verdant_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/plant_growth">plant growth</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _winged_boots = {title: "Winged Boots", jsx: <><h2 id="magic-wondrous-winged_boots-winged-boots">Winged Boots</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 233</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 504</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> feet; <strong>Price</strong> 16,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These boots appear to be ordinary footgear. On command, they sprout wings at the heel and let the wearer fly, without having to maintain concentration, as if affected by a <em>fly</em> spell (including a +4 bonus on <Link to="/skill/fly">Fly</Link> skill checks). The wearer can fly three times per day for up to 5 minutes per flight.</p>
<h3 id="magic-wondrous-winged_boots-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fly">fly</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _apprentices_cheating_gloves = {title: "Apprentice's Cheating Gloves", jsx: <><h2 id="magic-wondrous-apprentices_cheating_gloves-apprentices-cheating-gloves">Apprentice's Cheating Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,200 gp; <strong>Weight</strong> -</p>
<p>These nondescript white gloves are a boon to minor spellcasters and fakes who are limited or lacking in magical ability or versatility. The wearer of these gloves can employ <em>mage hand</em> and <em>prestidigitation</em> at will.</p>
<h3 id="magic-wondrous-apprentices_cheating_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/prestidigitation">prestidigitation</Link>; <strong>Cost</strong> 1,100 gp</p>
</>};
const _armguards_of_waning_hope = {title: "Armguards of Waning Hope", jsx: <><h2 id="magic-wondrous-armguards_of_waning_hope-armguards-of-waning-hope">Armguards of Waning Hope</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 14</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Runes spiral and skitter across these leather bracers, which are adorned with small spikes. Twice per day, as a swift action after making a successful attack against a creature, the wearer can say the command word to steal all morale bonuses from which the creature is benefiting (this includes morale bonuses on attack rolls, on checks, to AC, or to any other statistics). These bonuses affect the wearer instead of the creature for 9 rounds. After this duration, if the morale bonuses' durations haven't elapsed, the bonuses cease affecting the wearer and resume affecting the original creature as normal. If the wearer attempts to activate this effect against a creature not benefiting from any morale bonuses, a daily use of the item is wasted.</p>
<h3 id="magic-wondrous-armguards_of_waning_hope-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/siphon_magic">siphon magic</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _assisting_gloves = {title: "Assisting Gloves", jsx: <><h2 id="magic-wondrous-assisting_gloves-assisting-gloves">Assisting Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 300</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 180 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these simple gloves can speak a command word create a glowing disembodied hand. As a swift action, the wearer can have the hand assist him with a task as if using the <Link to="/rule/aid_another">aid another</Link> action. The hand uses the wearer's base attack bonus or skill ranks when making the check to see if aid another is successful (it does not gain the benefit of the wearer's ability scores or other bonuses). The hand remains until it has attempted one action or until 1 minute passes, whichever comes first, at which time the gloves become nonmagical.</p>
<h3 id="magic-wondrous-assisting_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/unseen_servant">unseen servant</Link>; <strong>Cost</strong> 90 gp</p>
</>};
const _beast_wrestlers_gauntlets = {title: "Beast Wrestler's Gauntlets", jsx: <><h2 id="magic-wondrous-beast_wrestlers_gauntlets-beast-wrestlers-gauntlets">Beast Wrestler's Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 28</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These gauntlets grant a +1 enhancement bonus on <Link to="/rule/grapple">grapple</Link> checks. Each pair of gauntlets is created to fight a specific type or subtype of creature from the list of creature types in the <Link to="/magic-enh/bane">bane</Link> weapon special ability. While the wearer is grappling a creature of the designated type, the gauntlets' enhancement bonus increases by 2 and the wearer deals an additional 2d6 points of nonlethal damage when dealing damage as part of a successful grapple check.</p>
<h3 id="magic-wondrous-beast_wrestlers_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Cost</strong> 3,750 gp</p>
</>};
const _bloodstained_gloves = {title: "Bloodstained Gloves", jsx: <><h2 id="magic-wondrous-bloodstained_gloves-bloodstained-gloves">Bloodstained Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 226</Link><br/><strong>Aura</strong> moderate divination; <strong>CL</strong> 6th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>The original color of these supple, calfskin gloves is obfuscated by layers of brown bloodstains that persist through any amount of cleaning. If the gloves are soaked in the blood of a recently killed creature, the wearer gains a +1 insight bonus on attack rolls and damage rolls against creatures of the same type (or subtype for humanoids or outsiders, per the ranger's <Link to="/ability/favored_enemy">favored enemy</Link> class feature) for 1 hour. If the gloves are worn by a <Link to="/class/slayer">slayer</Link>, the bonus on damage rolls is equal the slayer's studied target bonus. Creatures that lack blood, such as skeletons, golems, or clockwork creatures, cannot activate the gloves' ability.</p>
<h3 id="magic-wondrous-bloodstained_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/instant_enemy">instant enemy</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _bonebreaker_gauntlets = {title: "Bonebreaker Gauntlets", jsx: <><h2 id="magic-wondrous-bonebreaker_gauntlets-bonebreaker-gauntlets">Bonebreaker Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 142</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These thick brass and leather gauntlets allow the wearer to tear through bone and muscle like paper. Once per day, as part of a melee attack, the wearer can activate the gauntlets to inflict a horrific injury on an opponent. If the attack hits, the target must make a DC 14 Will save. If the save fails, the gauntlets reduce the target's Strength, Dexterity, or Constitution (wearer's choice) by -6. This penalty cannot reduce the target's ability score below 1. The injury heals over time, reducing the penalty by 1 for each day that passes since the time of the injury, and is immediately removed by <Link to="/spell/heal">heal</Link>, <Link to="/spell/regenerate">regenerate</Link>, <Link to="/spell/restoration">restoration</Link>, or any magic that can break a curse.</p>
<h3 id="magic-wondrous-bonebreaker_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _challengers_gloves = {title: "Challenger's Gloves", jsx: <><h2 id="magic-wondrous-challengers_gloves-challengers-gloves">Challenger's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link><br/><strong>Aura</strong> faint enchantment; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,200 gp; <strong>Weight</strong> -</p>
<p>These supple, velvet gloves are the sort that might be thrown down in challenge for a <Link to="/rule/duels">duel</Link> or other single combat. By removing a glove and using it to make a melee or ranged touch attack against an opponent, the wearer of the other glove gains a +1 morale bonus on attack rolls against the target, and the target gains a -1 penalty on attack rolls against the wearer. Both of these effects last for 1 minute, but immediately end if anyone but the glove's wearer attacks the challenged opponent. Both gloves must be worn by the same creature.</p>
<h3 id="magic-wondrous-challengers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bane">bane</Link>, <Link to="/spell/bless">bless</Link>; <strong>Cost</strong> 1,100 gp</p>
</>};
const _claws_of_the_ice_bear = {title: "Claws of the Ice Bear", jsx: <><h2 id="magic-wondrous-claws_of_the_ice_bear-claws-of-the-ice-bear">Claws of the Ice Bear</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link>, <Link to="/source/pathfinder_51_the_hungry_storm">Pathfinder #51: The Hungry Storm pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,300 gp; <strong>Weight</strong> 1 lb.</p>
<p>Strapped to the hands, these spiked climbing claws grant a +2 competence bonus on <Link to="/skill/climb">Climb</Link> checks and <Link to="/skill/acrobatics">Acrobatics</Link> checks made when using both hands to aid in movement, and allow the wearer to ignore the normal penalties on those skills for slippery or icy surfaces. In addition, up to 3 times per day, the wearer can activate the claws as a swift action to gain the benefits of <em>spider climb</em> for 1 round. The wearer cannot hold anything else in her hands while using claws of the ice bear. If used as a weapon, claws of the ice bear function as <Link to="/eq-weapon/spiked_gauntlet">spiked gauntlets</Link>.</p>
<h3 id="magic-wondrous-claws_of_the_ice_bear-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/spider_climb">spider climb</Link>; <strong>Cost</strong> 750 gp</p>
</>};
const _deaths_will = {title: "Death's Will", jsx: <><h2 id="magic-wondrous-deaths_will-deaths-will">Death's Will</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 28</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>This black leather fingerless glove is etched with delicate patterns and extends up to the wearer's midforearm, fitting snugly without being so tight as to keep the skin from breathing. Situated subtly in the underside of the glove is a hidden needle. Wearing this glove grants the wearer a +4 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal poisons or toxins on her body. As a swift action, the wearer can fire poison from the needle in the glove, delivering a stream of poison to a target within 30 feet as a ranged touch attack. The needle can hold a single dose of poison at any time. Refilling the glove requires a full-round action that provokes attacks of opportunity.</p>
<h3 id="magic-wondrous-deaths_will-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/spit_venom">spit venom</Link>; <strong>Cost</strong> 1,800 gp</p>
</>};
const _deliquescent_gloves = {title: "Deliquescent Gloves", jsx: <><h2 id="magic-wondrous-deliquescent_gloves-deliquescent-gloves">Deliquescent Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These heavy leather gloves ripple and flows at the wearer's command, reshaping to fit any hand, claw, tentacle, or alien limb. The wearer's melee touch attacks with that hand deal 1d6 points of acid damage. If the wearer uses that hand to wield a weapon or make an attack with an unarmed strike or natural weapon, that attack gains the <Link to="/magic-enh/corrosive">corrosive</Link> weapon special ability.</p>
<p>The wearer's gloved hand is protected from the acid ability of oozes, allowing him to use that hand to attack oozes with unarmed strikes or natural attacks without risk of harm from contact with the ooze. These unarmed strikes and natural attacks never cause an ooze to split.</p>
<h3 id="magic-wondrous-deliquescent_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/acid_arrow">acid arrow</Link>, <Link to="/spell/summon_monster_v">summon monster V</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _demonic_smiths_gloves = {title: "Demonic Smith's Gloves", jsx: <><h2 id="magic-wondrous-demonic_smiths_gloves-demonic-smiths-gloves">Demonic Smith's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 58</Link><br/><strong>Aura</strong> moderate evocation and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Used by the drow smiths of house Caldrana, these worked black leather gloves are stitched with red symbols dedicated to <Link to="/faith/flauros">Flauros</Link>, the demon lord of fire and volcanoes. Whenever the wearer makes a melee touch attack, she deals 1d6 points of fire damage. If the wearer wields a weapon or makes an attack with an unarmed strike, that attack gains the <Link to="/magic-enh/flaming">flaming</Link> weapon special ability.</p>
<p>When demonic smith's gloves are used during the construction of armor or weapons, they grant their wearer a +4 competence bonus on the relevant <Link to="/skill/craft">Craft</Link> checks. If the wearer rolls a natural 1 while benefiting from this bonus, she draws the ire of Flauros, causing the gloves to become nonmagical until the wearer crafts at least five masterwork items and then destroys them in the name of the demon lord.</p>
<h3 id="magic-wondrous-demonic_smiths_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fabricate">fabricate</Link>, <Link to="/spell/fireball">fireball</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _dianxue_gloves = {title: "Dianxue Gloves", jsx: <><h2 id="magic-wondrous-dianxue_gloves-dianxue-gloves">Dianxue Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 10</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>Thought to have been developed by disciples of Soong Bai, the famous promulgator of acupuncture, these gloves grant their wearer powerful skills in the arts of healing - and harming - living beings. The wearer of a pair of dianxue gloves gains a +4 competence bonus on <Link to="/skill/heal">Heal</Link> checks to provide first aid, long-term care, and to treat deadly wounds for living, humanoid creatures. In addition, the wearer gains a +2 competence bonus on rolls to confirm critical hits with unarmed strikes or with natural weapons against living humanoid creatures.</p>
<h3 id="magic-wondrous-dianxue_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/status">status</Link>, <Link to="/spell/true_strike">true strike</Link>, creator must have 5 ranks in Heal; <strong>Cost</strong> 1,500 gp</p>
</>};
const _dissidents_gloves = {title: "Dissident's Gloves", jsx: <><h2 id="magic-wondrous-dissidents_gloves-dissidents-gloves">Dissident's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 23</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>The inside of these fingerless leather gloves contains minute stitching forming the holy symbol of a specific deity or religion. As a standard action, the wearer can imprint a palm-sized image of the holy symbol onto any object (as if using <em>arcane mark</em>) simply by pressing the palm of one of a pair of dissident's gloves against it. The icon is invisible for 1d4 rounds after the imprinting; it then appears and glows with light equivalent to a candle. While the image is visible, any worshiper of the appropriate faith can use it as a holy symbol by touching it. The image fades after 1 day, but can be prematurely removed by <Link to="/spell/dispel_magic">dispel magic</Link> or <Link to="/spell/erase">erase</Link>.</p>
<h3 id="magic-wondrous-dissidents_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 600 gp</p>
</>};
const _engineers_workgloves = {title: "Engineer's Workgloves", jsx: <><h2 id="magic-wondrous-engineers_workgloves-engineers-workgloves">Engineer's Workgloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> -</p>
<p>These durable canvas and leather gloves imbue the wearer with an instinctive knowledge of mechanical devices. The wearer also gains a +5 competence bonus on <Link to="/skill/craft">Craft</Link> and <Link to="/skill/knowledge">Knowledge</Link> checks made to repair or understand mechanical devices.</p>
<p>Once per day, the wearer may touch a device and instantly analyze it, learning its purpose and general method of operation, as well as diagnosing any acute malfunctions of the device, but not its magical powers or additional non-mechanical effects. For example, she could touch a pressure plate and understand that stepping on it would trigger a wall scythe trap attacking that square and that the trap resets automatically, but not that the trap includes a +1 <Link to="/magic-enh/flaming">flaming</Link> <Link to="/eq-weapon/scythe">scythe</Link> coated in poison.</p>
<h3 id="magic-wondrous-engineers_workgloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have 5 ranks in Knowledge (engineering); <strong>Cost</strong> 1,500 gp</p>
</>};
const _extractors_gloves = {title: "Extractor's Gloves", jsx: <><h2 id="magic-wondrous-extractors_gloves-extractors-gloves">Extractor's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 33</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>These black leather fingerless gloves are shot through with strands of giant spider webbing. They allow their wearer to steal the special abilities of an opponent's weapon and augment the wearer's unarmed strikes with the abilities instead.</p>
<p>Once per day, the wearer can activate the gloves by succeeding at an unarmed disarm combat maneuver against an opponent's magic weapon. Instead of disarming the weapon, the wearer can negate the weapon's special abilities (<Link to="/magic-enh/bane">bane</Link>, <Link to="/magic-enh/flaming">flaming</Link>, and so on) for 1d4 rounds and apply these abilities to her own unarmed strikes (the weapon's enhancement bonus is unaffected). Any weapon special abilities that couldn't be applied to unarmed strikes (such as <Link to="/magic-enh/returning">returning</Link> or <Link to="/magic-enh/vorpal">vorpal</Link>) are still suspended on the weapon but are not applied to the wearer's unarmed attacks.</p>
<p>If the wearer's unarmed strikes already have magical weapon special abilities (such as from an <Link to="/magic-wondrous/amulet_of_mighty_fists">amulet of mighty fists</Link>), the enhancement bonus and special ability bonus equivalents on the wearer's unarmed strikes can't total more than +10; stolen special abilities are discarded at random until the total is +10 or less (discarded abilities are still suspended in the opponent's weapon for the normal duration).</p>
<h3 id="magic-wondrous-extractors_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _fervent_searchers_gloves = {title: "Fervent Searcher's Gloves", jsx: <><h2 id="magic-wondrous-fervent_searchers_gloves-fervent-searchers-gloves">Fervent Searcher's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 15</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 7,400 gp; <strong>Weight</strong> -</p>
<p>These dark blue, silken gloves are fingerless. Twice per day as a move action, the wearer can touch the ground or any other solid surface and say the command word to visibly reveal all footprints within 20 feet. When the gloves reveal footprints in this way, the wearer gains a +5 bonus on <Link to="/skill/survival">Survival</Link> checks to follow those tracks.</p>
<h3 id="magic-wondrous-fervent_searchers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/residual_tracking">residual tracking</Link>; <strong>Cost</strong> 3,700 gp</p>
</>};
const _first_aid_gloves = {title: "First Aid Gloves", jsx: <><h2 id="magic-wondrous-first_aid_gloves-first-aid-gloves">First Aid Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 147</Link>, <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 24</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These gloves have a sapphire decorating each finger, bearing 10 in all. While wearing a pair of first aid gloves, as a standard action the wearer can cast any of the following spells (caster level 9th), permanently expending a number of sapphires equal to the spell's level (as denoted in parentheses after each spell): <em>breath of life</em> (5), <em>cure critical wounds</em> (4), <em>cure light wounds</em> (1), <em>cure moderate wounds</em> (2), <em>cure serious wounds</em> (3), and <em>mass cure light wounds</em> (5). When casting a spell from the gloves, the wearer can't expend sapphires on different hands; thus only a full hand's worth of gems can be used to cast <em>breath of life</em> or <em>mass cure light wounds.</em> Regardless, both gloves must be worn to function. Once all of the sapphires are expended, a pair of first aid gloves becomes nonmagical.</p>
<h3 id="magic-wondrous-first_aid_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/cure_critical_wounds">cure critical wounds</Link>, <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/cure_serious_wounds">cure serious wounds</Link>, <Link to="/spell/mass_cure_light_wounds">mass cure light wounds</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _form_fixing_gauntlets = {title: "Form-Fixing Gauntlets", jsx: <><h2 id="magic-wondrous-form_fixing_gauntlets-form-fixing-gauntlets">Form-Fixing Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 234</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 15th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These leather gauntlets grant the wearer a +2 morale bonus on unarmed strikes, natural attacks, and combat maneuver checks versus creatures with the <Link to="/umr/change_shape">change shape</Link> special ability or similar abilities that allow it to change shape at will. While the wearer has such a creature <Link to="/rule/grappled">grappled or pinned</Link>, it cannot use any shape-changing spells or abilities unless it succeeds at a <Link to="/rule/concentration">concentration</Link> check; the DC of this check is 4 + the DC of casting the spell while grappled. If the wearer has such a creature pinned, a successful grapple check allows him to force the target into a specific shape it can take naturally (without the use of a spell). this involuntary transformation only forces the creature into a shape it is normally capable of and does not cost the creature an action.</p>
<h3 id="magic-wondrous-form_fixing_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph_any_object">polymorph any object</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _gauntlet_of_rust = {title: "Gauntlet of Rust", jsx: <><h2 id="magic-wondrous-gauntlet_of_rust-gauntlet-of-rust">Gauntlet of Rust</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 235</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 514</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 11,500 gp (normal), 34,500 gp (greater); <strong>Weight</strong> 2 lbs. (normal), 1 lb. (greater)</p>
<p>This single metal gauntlet looks rusted and pitted but is actually quite powerful. Once per day, it can affect an object as with the <em>rusting grasp</em> spell. It also completely protects the wearer and her gear from rust (magical or otherwise), including the attack of a <Link to="/monster/rust_monster">rust monster</Link>.</p>
<h3 id="magic-wondrous-gauntlet_of_rust-gauntlet-of-rust-greater">Gauntlet of Rust (Greater)</h3>
<p>This item is identical to a gauntlet of rust, except the wearer can use <em>rusting grasp</em> 3 times per day.</p>
<h3 id="magic-wondrous-gauntlet_of_rust-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/rusting_grasp">rusting grasp</Link>; <strong>Cost</strong> 5,750 gp (normal), 17,250 gp (greater)</p>
</>};
const _gauntlets_of_catching = {title: "Gauntlets of Catching", jsx: <><h2 id="magic-wondrous-gauntlets_of_catching-gauntlets-of-catching">Gauntlets of Catching</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_91_battle_of_bloodmarch_hills">Pathfinder #91: Battle of Bloodmarch Hills pg. 73</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 4th<br/><strong>Slot</strong> hands; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> 20 lbs.</p>
<p>Only Large or larger creatures can wear these sturdy leather gauntlets. If the wearer has the <Link to="/umr/rock_catching">rock catching</Link> ability, the Reflex DC to catch rocks is reduced by 5 while she's wearing the gauntlets. Furthermore, the wearer can attempt to catch a thrown rock of which she's unaware, but doesn't benefit from the DC reduction granted by the primary function of the gauntlets. If the wearer does not have the rock catching ability, these gauntlets bestow that ability on the wearer instead of their normal effects.</p>
<h3 id="magic-wondrous-gauntlets_of_catching-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _gauntlets_of_fumbling = {title: "Gauntlets of Fumbling", jsx: <><h2 id="magic-wondrous-gauntlets_of_fumbling-gauntlets-of-fumbling">Gauntlets of Fumbling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 346</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 540</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Weight</strong> 2 lbs.</p>
<p>These gauntlets perform according to their appearance until the wearer finds herself under attack or in a life and death situation. At that time, the curse is activated. The wearer becomes fumble-fingered, with a 50% chance each round of dropping anything held in either hand. The gauntlets also lower the wearer's Dexterity score by 2 points. Once the curse is activated, the gloves can be removed only by means of a <Link to="/spell/remove_curse">remove curse</Link> spell, a <Link to="/spell/wish">wish</Link>, or a <Link to="/spell/miracle">miracle</Link>.</p>
<h3 id="magic-wondrous-gauntlets_of_fumbling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/gauntlet_of_rust">gauntlet of rust</Link>, <Link to="/magic-wondrous/gloves_of_arrow_snaring">gloves of arrow snaring</Link>, <Link to="/magic-wondrous/glove_of_storing">glove of storing</Link>, <Link to="/magic-wondrous/gloves_of_swimming_and_climbing">gloves of swimming and climbing</Link>; <strong>Cost</strong> -</p>
</>};
const _gauntlets_of_the_deep = {title: "Gauntlets of the Deep", jsx: <><h2 id="magic-wondrous-gauntlets_of_the_deep-gauntlets-of-the-deep">Gauntlets of the Deep</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_124_city_in_the_deep">Pathfinder #124: City in the Deep pg. 81</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These gloves are covered in fish scales and always feel cold and wet to the touch. While wearing these gauntlets, after a 24-hour attunement period, the wearer can throw a weapon that deals piercing damage underwater without penalty, using the weapon's normal range increment. When the wielder attacks a target in water from land, regardless of the weapon the wielder is using, the target doesn't benefit from <Link to="/rule/cover">cover</Link> or total cover for being in water.</p>
<blockquote>
<p><em>Also see <Link to="/rule/physical_attacks_underwater">Physical Attacks Underwater</Link> for optional alternate rules on underwater combat.</em></p>
</blockquote>
<h3 id="magic-wondrous-gauntlets_of_the_deep-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/freedom_of_movement">freedom of movement</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _gauntlets_of_the_skilled_maneuver = {title: "Gauntlets of the Skilled Maneuver", jsx: <><h2 id="magic-wondrous-gauntlets_of_the_skilled_maneuver-gauntlets-of-the-skilled-maneuver">Gauntlets of the Skilled Maneuver</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 235</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The wearer of these gauntlets gains a +2 bonus on one type of combat maneuver check (such as <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/disarm">disarm</Link>, or <Link to="/rule/steal">steal</Link>) chosen by the creator when the item is created.</p>
<h3 id="magic-wondrous-gauntlets_of_the_skilled_maneuver-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have the appropriate Improved combat maneuver feat; <strong>Cost</strong> 2,000 gp</p>
</>};
const _gauntlets_of_the_unchained = {title: "Gauntlets of the Unchained", jsx: <><h2 id="magic-wondrous-gauntlets_of_the_unchained-gauntlets-of-the-unchained">Gauntlets of the Unchained</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 28</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 13,200 gp; <strong>Weight</strong> 6 lbs.</p>
<p>Said to have first been forged centuries ago by a human master blacksmith who escaped from drow slavers in Sekamina, these shimmering silver gauntlets remind the wearer that she is always shackled to the deeds of her past, but remains unfettered with the promise of a freer future. The wearer of a pair of gauntlets of the unchained may only wield weapons two-handed - the magical chain that binds the gauntlets makes it effectively impossible to wield or hold more than one item at a time.</p>
<p>By tapping the gauntlets' manacles together as a swift action, the wearer can cause damage dealt by her wielded weapon to become lawful-aligned and thus overcome the corresponding damage reduction. This effect lasts for up to 7 rounds per day. This duration need not be consecutive, but it must be spent in 1-round increments. By breaking the magical chain that connects the gauntlets as a standard action, the wearer can cause her wielded weapon to gain the <Link to="/magic-enh/anarchic">anarchic</Link> weapon special ability for 7 minutes. Once broken, the chain between the gauntlets is shattered forever, and the gauntlets become nonmagical.</p>
<h3 id="magic-wondrous-gauntlets_of_the_unchained-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/chaos_hammer">chaos hammer</Link>, <Link to="/spell/orders_wrath">order's wrath</Link>, creator must be neutral; <strong>Cost</strong> 6,600 gp</p>
</>};
const _gauntlets_of_the_weaponmaster = {title: "Gauntlets of the Weaponmaster", jsx: <><h2 id="magic-wondrous-gauntlets_of_the_weaponmaster-gauntlets-of-the-weaponmaster">Gauntlets of the Weaponmaster</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 235</Link><br/><strong>Aura</strong> strong conjuration; <strong>CL</strong> 10th<br/><strong>Slot</strong> hands; <strong>Price</strong> 110,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>These gauntlets come in a variety of forms. Some are mostly leather with small steel plates, and are suited for fine swordplay. Others are fully articulated plate favored by knights in full plate. On command, the wearer of the gauntlet can store a single weapon he is holding in the gauntlets. When he does so, a graven image of the weapon appears on the gauntlet's plates. The wearer can store up to 10 weapons in the gauntlets in this manner. Retrieving a weapon requires the wearer to touch the image of the weapon he wants. Doing so is a swift action. When a weapon is retrieved, it appears in the hands of the wearer and any weapons the wearer had in his hands is stored in the gauntlets. If there is no room in the gauntlet for the weapons the wearer is holding, those weapons are dropped. The gauntlets can only store weapons; other items cannot be placed in the gauntlet.</p>
<p>Furthermore, three times per day on command, the gloves affect the wearer as the <Link to="/spell/greater_heroism">greater heroism</Link> spell.</p>
<h3 id="magic-wondrous-gauntlets_of_the_weaponmaster-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/heroism">heroism</Link>, <Link to="/spell/rope_trick">rope trick</Link>; <strong>Cost</strong> 55,000 gp</p>
</>};
const _gauntlets_of_twisting_vines = {title: "Gauntlets of Twisting Vines", jsx: <><h2 id="magic-wondrous-gauntlets_of_twisting_vines-gauntlets-of-twisting-vines">Gauntlets of Twisting Vines</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 28</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These wrist wraps are actually dark, thorny vines that constantly move and twist around the wearer's hands of their own accord. The wearer gains a +2 circumstance bonus on combat maneuver checks to <Link to="/rule/disarm">disarm</Link>, <Link to="/rule/grapple">grapple</Link>, and <Link to="/rule/steal">steal</Link>. Once per day when the wearer successfully pins a foe with a grapple check, the vines can move off the wearer (ending the circumstance bonus on combat maneuver checks), envelop the target, and tie it up. A tied-up victim can escape the vines by succeeding at a combat maneuver or <Link to="/skill/escape_artist">Escape Artist</Link> check with a DC equal to the result of the combat maneuver check that pinned the victim. The character who was wearing the gauntlets when they were used to envelop a target can remove them from the target as a move action. Any other creature must succeed at a combat maneuver or Strength check at the same DC to pry the gauntlets loose of an enveloped target.</p>
<h3 id="magic-wondrous-gauntlets_of_twisting_vines-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/spell/entangle">entangle</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _ghostvision_gloves = {title: "Ghostvision Gloves", jsx: <><h2 id="magic-wondrous-ghostvision_gloves-ghostvision-gloves">Ghostvision Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link><br/><strong>Aura</strong> faint divination and evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>These gloves are made of pale gray silk; each is adorned with an embroidered silver eye on the back. Once per day the wearer may activate them, as a standard action, by bowing her head and pressing her hands to her eyes. The embroidered silver eyes flare and open, and when the wearer lowers her hands, deep pools of swirling gray mist hide her own eyes and allow her to more clearly see the restless dead for the next 10 rounds. While active, ghostvision gloves grant the following effects.</p>
<ul>
<li>The wearer can see all undead within 60 feet clearly, including ethereal undead and incorporeal undead hiding in objects or walls to a depth of 5 feet.</li>
<li>If the wearer has the <Link to="/ability/channel_positive_energy">channel positive energy</Link> class ability, she may expend one use of channeled positive energy to make a ranged touch attack against one undead creature within channel range. If the ranged touch attack hits, she rolls channel energy damage against that target (affecting no other creatures), except she rolls d12s instead of d6s.</li>
<li>While the gloves are active, constructs and living opponents treat the wearer as <Link to="/misc/blind">blind</Link>.</li>
</ul>
<h3 id="magic-wondrous-ghostvision_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/searing_light">searing light</Link>, channel positive energy class ability; <strong>Cost</strong> 2,000 gp</p>
</>};
const _giant_fist_gauntlets = {title: "Giant Fist Gauntlets", jsx: <><h2 id="magic-wondrous-giant_fist_gauntlets-giant-fist-gauntlets">Giant Fist Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> hands; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>As a swift action, the wearer of these rough leather gauntlets can expand her hands to twice normal size and harden to the consistency of hardwood. This transformation lasts for up to 20 rounds per day, though they need not be consecutive rounds. If the wearer hits with an unarmed strike or natural attack using her enlarged hands, she may attempt to <Link to="/rule/bull_rush">bull rush</Link> her opponent as a free action.</p>
<h3 id="magic-wondrous-giant_fist_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _glove_of_familiars_touch = {title: "Glove of Familiar's Touch", jsx: <><h2 id="magic-wondrous-glove_of_familiars_touch-glove-of-familiars-touch">Glove of Familiar's Touch</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 21</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 23,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>A glove of familiar's touch features a large, brightly colored gem fastened to its palm, and comes with an additional gem attuned to the glove. As long as his familiar is touching the attuned gem, the wearer of this glove can designate his familiar as the source for any touch spell he casts, even if he and his familiar are not in contact when the spell is cast. A glove of familiar's touch takes up the wearer's entire hands slot; the wearer can't gain the benefits of another magic item (even another glove of familiar's touch) that also uses the hands slot.</p>
<h3 id="magic-wondrous-glove_of_familiars_touch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/imbue_with_spell_ability">imbue with spell ability</Link>; <strong>Cost</strong> 11,500 gp</p>
</>};
const _glove_of_storing = {title: "Glove of Storing", jsx: <><h2 id="magic-wondrous-glove_of_storing-glove-of-storing">Glove of Storing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 515</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 6th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>This device is a single leather glove. On command, one item held in the hand wearing the glove disappears. The item can weigh no more than 20 pounds and must be able to be held in one hand. While stored, the item has negligible weight. With a snap of the fingers wearing the glove, the item reappears. A glove can only store one item at a time. Storing or retrieving the item is a free action. The item is shrunk down so small within the palm of the glove that it cannot be seen. Spell durations are not suppressed, but continue to expire. If the glove's effect is suppressed or dispelled, the stored item appears instantly. A glove of storing uses up the wearer's entire hands slot. The wearer may not use another item (even another glove of storing) that also uses the hands slot.</p>
<h3 id="magic-wondrous-glove_of_storing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _gloves_of_arcane_striking = {title: "Gloves of Arcane Striking", jsx: <><h2 id="magic-wondrous-gloves_of_arcane_striking-gloves-of-arcane-striking">Gloves of Arcane Striking</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These soft leather gloves are decorated with even rows of <Link to="/eq-material/mithral">mithral</Link> rivets. Only a spellcaster with the <Link to="/feat/arcane_strike">Arcane Strike</Link> feat can activate their abilities. These abilities are as follows.</p>
<ul>
<li>When the wearer uses the <Link to="/rule/aid_another_2">aid another</Link> action to improve an ally's attack roll, the ally adds the wearer's Arcane Strike damage bonus to its damage roll for that attack.</li>
<li>When the wearer makes an attack using Arcane Strike and hits, enemies adjacent to the target take damage equal to the wearer's Arcane Strike damage bonus. This damage is of the same type as the weapon's damage (bludgeoning, piercing, and so on).</li>
<li>When the wearer uses the aid another action to improve an ally's Armor Class, the ally also adds the wearer's Arcane Strike damage bonus to his AC against the opponent.</li>
</ul>
<h3 id="magic-wondrous-gloves_of_arcane_striking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, Arcane Strike, <Link to="/spell/magic_weapon">magic weapon</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _gloves_of_arrow_snaring = {title: "Gloves of Arrow Snaring", jsx: <><h2 id="magic-wondrous-gloves_of_arrow_snaring-gloves-of-arrow-snaring">Gloves of Arrow Snaring</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 514</Link><br/><strong>Aura</strong> faint abjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> -</p>
<p>Once worn, these snug gloves seem to meld with the hands, becoming almost invisible to casual observation. Twice per day, the wearer can act as if he had the <Link to="/feat/snatch_arrows">Snatch Arrows</Link> feat, even if he does not meet the prerequisites for the feat. Both gloves must be worn for the magic to be effective, and at least one hand must be free to take advantage of the magic.</p>
<h3 id="magic-wondrous-gloves_of_arrow_snaring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shield">shield</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _gloves_of_bony_power = {title: "Gloves of Bony Power", jsx: <><h2 id="magic-wondrous-gloves_of_bony_power-gloves-of-bony-power">Gloves of Bony Power</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 264</Link><br/><strong>Aura</strong> faint conjuration and necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> -</p>
<p>These black gloves are decorated with images of white bones, as if revealing the bones within the wearer's hands. The left glove can be used once per day to create a <em>spectral hand,</em> which makes the bony hand image on that glove slide off and manifest as a ghostly skeletal hand for the duration of the effect. The right glove can be used once per day to deliver an <em>inflict moderate wounds</em> spell, which gives that hand's bones a pale, sickly glow until the touch is delivered or discharged. If the wearer is a living creature, he can also use the right glove on himself to cast <em>cure moderate wounds</em> instead of inflict moderate wounds.</p>
<h3 id="magic-wondrous-gloves_of_bony_power-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, <Link to="/spell/inflict_moderate_wounds">inflict moderate wounds</Link>, <Link to="/spell/spectral_hand">spectral hand</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _gloves_of_distant_action = {title: "Gloves of Distant Action", jsx: <><h2 id="magic-wondrous-gloves_of_distant_action-gloves-of-distant-action">Gloves of Distant Action</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 151</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 20,000 gp; <strong>Weight</strong> -</p>
<p>As a move action, the wearer of these fine leather gloves can pick up an unattended object (weighing no more than 20 pounds) that is up to 30 feet away, and move it up to 30 feet. The object falls to the ground at the end of the movement unless the wearer of the gloves moves it into his hand. This action doesn't provoke attacks of opportunity.</p>
<p>By expending one use of mythic power as a free action on his turn, the wearer can focus the power of the gloves, allowing him to make unarmed strikes and combat maneuvers to <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/disarm">disarm</Link>, or <Link to="/rule/trip">trip</Link> against foes up to 30 feet away until the end of his turn. Treat these attacks as though the wearer had 30 feet of reach. When attacking a non-adjacent target in this manner, the wearer can't be affected by feats and abilities like <Link to="/feat/strike_back">Strike Back</Link> or <Link to="/spell/fire_shield">fire shield</Link> that require touching or coming near the target. The gloves don't increase the wearer's threatened area.</p>
<h3 id="magic-wondrous-gloves_of_distant_action-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/mage_hand">mage hand</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 10,000 gp</p>
</>};
const _gloves_of_dueling = {title: "Gloves of Dueling", jsx: <><h2 id="magic-wondrous-gloves_of_dueling-gloves-of-dueling">Gloves of Dueling</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 236</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 305</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 15,000 gp; <strong>Weight</strong> -</p>
<p>These supple gloves grant the wearer a +4 bonus to her CMD against <Link to="/rule/disarm">disarm</Link> attacks, attempts to sunder her wielded weapons, and effects that cause her to lose her grip on her weapons (such as <Link to="/spell/grease">grease</Link>). The wearer doesn't drop held weapons when <Link to="/misc/panicked">panicked</Link> or <Link to="/misc/stunned">stunned</Link>. If the wearer has the weapon training class feature and is using an appropriate weapon, her weapon training bonus increases by +2.</p>
<h3 id="magic-wondrous-gloves_of_dueling-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_magic_weapon">greater magic weapon</Link>; <strong>Cost</strong> 7,500 gp</p>
</>};
const _gloves_of_elvenkind = {title: "Gloves of Elvenkind", jsx: <><h2 id="magic-wondrous-gloves_of_elvenkind-gloves-of-elvenkind">Gloves of Elvenkind</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 29</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> hands; <strong>Price</strong> 7,500 gp; <strong>Weight</strong> -</p>
<p>These plain gray leather gloves grant a +5 competence bonus on <Link to="/skill/spellcraft">Spellcraft</Link> checks and <Link to="/rule/concentration">concentration</Link> checks made to cast a spell defensively. Both gloves must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-gloves_of_elvenkind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/combat_casting">Combat Casting</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be an elf; <strong>Cost</strong> 3,500 gp</p>
</>};
const _gloves_of_feasting = {title: "Gloves of Feasting", jsx: <><h2 id="magic-wondrous-gloves_of_feasting-gloves-of-feasting">Gloves of Feasting</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 220</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,400 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>Each of these leather gloves has a large, ragged hole in the palm. Upon donning the gloves, the wearer is <Link to="/misc/nauseated">nauseated</Link> with pain for 1 round as the skin on his palms rips open, revealing terrible gashes that each sprout fangs, lips, and a tongue. While the wearer's hands are empty, he can breathe, eat, drink, and speak through the mouths on his hands (though this doesn't allow him to drink more potions in a round, speak with more than one voice at a time, or otherwise take more actions than normal). The wearer retains the use of his hands; the mouths remain shut while the wearer is holding items in his hands.</p>
<p>The wearer receives a +2 enhancement bonus on combat maneuver checks to <Link to="/rule/grapple">grapple</Link> a foe with his hands. If he begins his turn grappling with his hands, the wearer can make a free bite attack with one of the mouths on his hands. The bite is treated as a <Link to="/rule/natural_weapon">natural weapon</Link> and deals an amount of damage equal to 1d4 + his Strength modifier for a Medium wearer (1d3 + his Strength modifier if he's Small).</p>
<h3 id="magic-wondrous-gloves_of_feasting-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/polymorph">polymorph</Link>; <strong>Cost</strong> 4,200 gp</p>
</>};
const _gloves_of_improvised_might = {title: "Gloves of Improvised Might", jsx: <><h2 id="magic-wondrous-gloves_of_improvised_might-gloves-of-improvised-might">Gloves of Improvised Might</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 23</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp (+1), 16,000 gp (+2), 36,000 gp (+3), 64,000 gp (+4), 100,000 gp (+5); <strong>Weight</strong> 1 lb.</p>
<p>These rough leather gloves grant an enhancement bonus of +1 to +5 on attack and damage rolls with <Link to="/misc/improvised_weapon">improvised weapons</Link>. Alternatively, the gloves can grant <Link to="/main/magic_enhancements">melee weapon special abilities</Link>, so long as they can be applied to melee or thrown weapons. Special abilities count as additional bonuses for determining the market value of the item, but do not modify attack or damage bonuses. Gloves of improvised might cannot have a modified bonus (enhancement bonus plus special ability bonus equivalents) higher than +5. Unlike an <Link to="/magic-wondrous/amulet_of_mighty_fists">amulet of mighty fists</Link>, gloves of improvised might must have a +1 enhancement bonus to grant a melee weapon special ability.</p>
<p>Normal weapons are unaffected by gloves of improvised might except when used as an improvised weapon in a way specifically permitted by the weapon description, such as using an arrow or bolt as a melee weapon (or if the user has an ability that allows the use of normal weapons as improvised weapons). The wearer still takes a -4 nonproficiency penalty on attack rolls with improvised weapons, as normal, unless he has the <Link to="/feat/catch_off_guard">Catch Off-Guard</Link> feat or a similar ability.</p>
<h3 id="magic-wondrous-gloves_of_improvised_might-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_magic_weapon">greater magic weapon</Link>, creator's caster level must be at least three times the gloves' bonus, plus any requirements of the melee weapon special abilities; <strong>Cost</strong> 2,000 gp (+1), 8,000 gp (+2), 18,000 gp (+3), 32,000 gp (+4), 50,000 gp (+5)</p>
</>};
const _gloves_of_larceny = {title: "Gloves of Larceny", jsx: <><h2 id="magic-wondrous-gloves_of_larceny-gloves-of-larceny">Gloves of Larceny</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These supple beige calfskin gloves greatly enhance a thief's talents. The wearer gains a +5 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks.</p>
<h3 id="magic-wondrous-gloves_of_larceny-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have 5 ranks in Sleight of Hand; <strong>Cost</strong> 1,250 gp</p>
</>};
const _gloves_of_marking = {title: "Gloves of Marking", jsx: <><h2 id="magic-wondrous-gloves_of_marking-gloves-of-marking">Gloves of Marking</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 230</Link><br/><strong>Aura</strong> faint necromancy and transmutation; <strong>CL</strong> 4th<br/><strong>Slot</strong> hands; <strong>Price</strong> 7,200 gp; <strong>Weight</strong> 1 lb.</p>
<p>These ruddy leather gloves enhance the precision of the wearer. When wielding a piercing or slashing weapon and using <Link to="/feat/weapon_finesse">Weapon Finesse</Link>, the wearer can mark a creature when confirming a critical hit instead of dealing additional damage. The mark consists of a simple symbol, such as a single letter.</p>
<p>The wielder and her allies gain a +2 morale bonus on attack rolls and melee damage rolls against the marked creature for 1 minute. In addition, the marked creature must succeed at a Will saving throw (DC 10 + one-half the wielder's level + the wielder's Dexterity modifier) or be <Link to="/misc/shaken">shaken</Link> for 1 minute. The bonuses and condition persist even if the damage caused by the mark is healed.</p>
<h3 id="magic-wondrous-gloves_of_marking-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cause_fear">cause fear</Link>, <Link to="/spell/heroism">heroism</Link>; <strong>Cost</strong> 3,600 gp</p>
</>};
const _gloves_of_personal_purity = {title: "Gloves of Personal Purity", jsx: <><h2 id="magic-wondrous-gloves_of_personal_purity-gloves-of-personal-purity">Gloves of Personal Purity</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 30</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> -</p>
<p>These long, white, elbow-length gloves are typical of those Kalistocrats wear to avoid making direct contact with the unenlightened. The wearer gains a +2 insight bonus on saving throws against disease and poison spread by contact, and against effects that occur when the wearer touches another creature (such as the effects of a <Link to="/monster/babau">babau's</Link> protective slime ability).</p>
<h3 id="magic-wondrous-gloves_of_personal_purity-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/anticipate_peril">anticipate peril</Link>, <Link to="/spell/resistance">resistance</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _gloves_of_pulverizing_disruption = {title: "Gloves of Pulverizing Disruption", jsx: <><h2 id="magic-wondrous-gloves_of_pulverizing_disruption-gloves-of-pulverizing-disruption">Gloves of Pulverizing Disruption</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 26</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,400 gp; <strong>Weight</strong> -</p>
<p>Three times per day, the wearer can use these thick leather gloves to make a melee touch attack against an undead creature, a construct, or a nonmagical object and deal 3d4 points of damage to it. When the wearer deals damage in this way, the gloves absorb part of the matter that makes up the target. This creates dust that is stored within the gloves for 24 hours. The next time the wearer attempts a <Link to="/rule/dirty_trick">dirty trick</Link> combat maneuver, the dust flies from the gloves, providing a +2 bonus on that attempt. If the wearer does not attempt a dirty trick combat maneuver before 24 hours elapses, the dust disappears.</p>
<h3 id="magic-wondrous-gloves_of_pulverizing_disruption-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/corrosive_touch">corrosive touch</Link>; <strong>Cost</strong> 4,700 gp</p>
</>};
const _gloves_of_reconnaissance = {title: "Gloves of Reconnaissance", jsx: <><h2 id="magic-wondrous-gloves_of_reconnaissance-gloves-of-reconnaissance">Gloves of Reconnaissance</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>Each of these fingerless worked leather gloves look as though they have seen heavy use, and often bear the stains or scent of grass or wet mud. On command, the wearer can use the gloves to see and hear though solid material no more than 5 feet thick by placing both hands on that material. The wearer can use the gloves once per day for up to 1 minute. The wearer must wear the gloves continuously for 24 hours before activating his ability.</p>
<h3 id="magic-wondrous-gloves_of_reconnaissance-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/clairaudience_clairvoyance">clairaudience/clairvoyance</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _gloves_of_restrained_death = {title: "Gloves of Restrained Death", jsx: <><h2 id="magic-wondrous-gloves_of_restrained_death-gloves-of-restrained-death">Gloves of Restrained Death</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 30</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,250 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These supple black leather gloves have dramatic white stitching running along their seams. Four small sapphires, two sewn onto the thumb of each hand, pulse gently when the gloves are worn. The wearer gains a +2 competence bonus on <Link to="/skill/stealth">Stealth</Link> checks. Anytime the wearer becomes poisoned while wearing the gloves, she can tap on any number of the sapphires to reduce the frequency of the poison by 1 increment per sapphire. The poison's frequency cannot be reduced to lower than 1 increment. For example, if a poison's frequency was 1/round for 6 rounds and three sapphires were tapped, the frequency would be reduced to 1/round for 3 rounds. Tapping each sapphire is a free action that causes the touched gem to become inert for 24 hours.</p>
<h3 id="magic-wondrous-gloves_of_restrained_death-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/restoration">restoration</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>; <strong>Cost</strong> 4,625 gp</p>
</>};
const _gloves_of_shaping = {title: "Gloves of Shaping", jsx: <><h2 id="magic-wondrous-gloves_of_shaping-gloves-of-shaping">Gloves of Shaping</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>These soft leather gloves are constantly encrusted with clay between the fingers and allow the reshaping of otherwise durable materials. The wearer can shape objects with hardness 8 or lower (stone, wood, leather, and so on) as if it were soft clay. While it's possible to rapidly make crude shapes (shaping roughly 1 cubic foot of material per round), creating fine detail or moving parts requires additional time and an appropriate <Link to="/skill/craft">Craft</Link> check, at the GM's discretion.</p>
<p>Materials with more than 8 points of hardness are still affected, though not so dramatically. The wearer may treat these materials as having half as much hardness when attempting to damage or reshape them. For instance, a steel bar normally has 10 points of hardness, but the wearer of the gloves may treat it as having hardness 5, and shape it with woodworking tools.</p>
<p>The gloves only affect shaping materials with the wearer's hands or handheld tools, and only when the wearer desires to do so.</p>
<h3 id="magic-wondrous-gloves_of_shaping-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/soften_earth_and_stone">soften earth and stone</Link>, <Link to="/spell/stone_shape">stone shape</Link>, <Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _gloves_of_spell_snaring = {title: "Gloves of Spell Snaring", jsx: <><h2 id="magic-wondrous-gloves_of_spell_snaring-gloves-of-spell-snaring">Gloves of Spell Snaring</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 151</Link><br/><strong>Aura</strong> strong abjuration; <strong>CL</strong> 13th<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>These thin gloves are covered in reflective glyphs and sigils, and the palms are slightly tacky. Like <Link to="/magic-wondrous/gloves_of_arrow_snaring">gloves of arrow snaring</Link>, twice per day the wearer can act as if she had the <Link to="/feat/snatch_arrows">Snatch Arrows</Link> feat, even if she doesn't meet the prerequisites for that feat. In addition, the wearer can expend one of this item's uses per day to use the Snatch Arrows feat on a projectile targeting an ally in a space adjacent to her.</p>
<p>As an immediate action, the wearer can expend one use of mythic power and one of this item's uses per day to block a spell targeting her or an adjacent ally, as the <Link to="/rule/guardian_3">parry spell</Link> guardian path ability.</p>
<h3 id="magic-wondrous-gloves_of_spell_snaring-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/shield">shield</Link>, <Link to="/spell/spell_turning">spell turning</Link>, creator must have the parry spell path ability; <strong>Cost</strong> 4,500 gp</p>
</>};
const _gloves_of_stolen_breath = {title: "Gloves of Stolen Breath", jsx: <><h2 id="magic-wondrous-gloves_of_stolen_breath-gloves-of-stolen-breath">Gloves of Stolen Breath</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 28</Link><br/><strong>Aura</strong> moderate conjuration and necromancy; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 54,000 gp; <strong>Weight</strong> -</p>
<p>These black leather gloves feel like warm, living skin to the touch. When the wearer delivers a <Link to="/misc/coup_de_grace">coup de grace</Link> that kills an opponent, she can target a single creature within 30 feet that has died within the previous 3 rounds as a free action. The target creature is healed as if with a <em>breath of life</em> spell (regaining 5d8+9 hit points), and if the creature's hit point total is then greater than a negative amount equal to its Constitution score, it comes back to life and stabilizes at its new hit point total. As with the <em>breath of life</em> spell, creatures brought back to life gain a temporary <Link to="/rule/negative_level">negative level</Link> that lasts for 1 day, but this effect can save creatures slain by death effects. This effect cannot damage undead creatures. The opponent killed by the <em>coup de grace</em> must have a number of Hit Dice equal to or greater than the target slain creature's Hit Dice or the gloves' ability is not triggered.</p>
<h3 id="magic-wondrous-gloves_of_stolen_breath-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/breath_of_life">breath of life</Link>, <Link to="/spell/death_knell">death knell</Link>; <strong>Cost</strong> 27,000 gp</p>
</>};
const _gloves_of_stolen_unlife = {title: "Gloves of Stolen Unlife", jsx: <><h2 id="magic-wondrous-gloves_of_stolen_unlife-gloves-of-stolen-unlife">Gloves of Stolen Unlife</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 28</Link><br/><strong>Aura</strong> faint necromancy; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,040 gp; <strong>Weight</strong> 1 lb.</p>
<p>These pale gray gauntlets feature cabochons of banded black onyx that slowly shift to white when the gloves are activated. Three times per day, the wearer can activate the gloves as a swift action after successfully affecting an undead creature with an offensive single-target spell. Doing so grants the wearer a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to 10 + the Hit Dice of the affected undead (maximum +10), which last a number of minutes equal to the level of the spell cast. This effect ends immediately if either glove is removed.</p>
<h3 id="magic-wondrous-gloves_of_stolen_unlife-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/false_life">false life</Link>; <strong>Cost</strong> 1,520 gp</p>
</>};
const _gloves_of_swimming_and_climbing = {title: "Gloves of Swimming and Climbing", jsx: <><h2 id="magic-wondrous-gloves_of_swimming_and_climbing-gloves-of-swimming-and-climbing">Gloves of Swimming and Climbing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 515</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 6,250 gp; <strong>Weight</strong> -</p>
<p>These apparently normal lightweight gloves are obviously made for use outdoors. They grant a +5 competence bonus on <Link to="/skill/swim">Swim</Link> checks and <Link to="/skill/climb">Climb</Link> checks. Both gloves must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-gloves_of_swimming_and_climbing-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/cats_grace">cat's grace</Link>; <strong>Cost</strong> 3,125 gp</p>
</>};
const _gloves_of_the_commanding_conjurer = {title: "Gloves of the Commanding Conjurer", jsx: <><h2 id="magic-wondrous-gloves_of_the_commanding_conjurer-gloves-of-the-commanding-conjurer">Gloves of the Commanding Conjurer</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link><br/><strong>Aura</strong> moderate enchantment; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 30,000 gp; <strong>Weight</strong> -</p>
<p>These gloves grant the wearer greater control over his summoned creatures. As long as he wears the gloves, creatures conjured by the wearer can understand him as if they shared a common language. This communication is not two-way and does not grant the wearer the ability to understand the creature.</p>
<p>Three times per day, the wearer can attempt to take control of a summoned creature within 50 feet as if using <em>control summoned creature</em> (Will DC 16).</p>
<h3 id="magic-wondrous-gloves_of_the_commanding_conjurer-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/control_summoned_creature">control summoned creature</Link>; <strong>Cost</strong> 15,000 gp</p>
</>};
const _gloves_of_the_keen_evaluator = {title: "Gloves of the Keen Evaluator", jsx: <><h2 id="magic-wondrous-gloves_of_the_keen_evaluator-gloves-of-the-keen-evaluator">Gloves of the Keen Evaluator</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 18</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,200 gp; <strong>Weight</strong> -</p>
<p>While worn, these white latex gloves provide an impressive grip for studying intricate objects. The wearer gains a +4 competence bonus on <Link to="/skill/appraise">Appraise</Link> checks to determine the value of an item. While involved in negotiations regarding the studied item, the wearer can use the result of her Appraise check as the result of <Link to="/skill/diplomacy">Diplomacy</Link> checks to haggle over the price of the item.</p>
<h3 id="magic-wondrous-gloves_of_the_keen_evaluator-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/eagles_splendor">eagle's splendor</Link>, <Link to="/spell/investigative_mind">investigative mind</Link>; <strong>Cost</strong> 600 gp</p>
</>};
const _gloves_of_the_shortened_path = {title: "Gloves of The Shortened Path", jsx: <><h2 id="magic-wondrous-gloves_of_the_shortened_path-gloves-of-the-shortened-path">Gloves of The Shortened Path</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 237</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 27,000 gp; <strong>Weight</strong> -</p>
<p>Once per day on command, the wearer of these oxblood leather gloves can bend space to extend her reach to a non-adjacent square within line of sight. For the next 10 rounds, she can touch anything in that square as if it were her own square, as long as she has line of effect to the target square. She may change the targeted square as a swift action.</p>
<p>When using the gloves to touch, attack, or manipulate anything in the square, the wearer's arms and hands also appear in that square, allowing creatures and effects to target her as if she were in that square. She cannot use this connection to transfer anything from her square to the target square, or vice versa. If she drops anything, it lands in her square. She can use her hands (including natural attacks from those hands, if any), hand-held objects (such as lockpicks), and melee weapons in that square as if she were there. The square is part of her threatened area, though she cannot use the gloves to provide <Link to="/rule/flanking">flanking</Link> for herself. She cannot use the gloves to <Link to="/rule/grapple">grapple</Link>, make ranged attacks, or make attacks that require her to move out of her actual square (such as a <Link to="/rule/bull_rush">bull rush</Link> combat maneuver).</p>
<p>Interacting with the target square is distracting, and anything that threatens her in her actual square automatically flanks her.</p>
<p>If the wearer or her square is blocked from using teleportation or planar travel effects (such as <Link to="/spell/dimensional_anchor">dimensional anchor</Link>), the gloves do not function. She cannot use the gloves to target a square protected by such an effect.</p>
<h3 id="magic-wondrous-gloves_of_the_shortened_path-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/teleport">teleport</Link>; <strong>Cost</strong> 8,000 gp</p>
</>};
const _gloves_of_unexpected_violence_standard = {title: "Gloves of Unexpected Violence (Standard)", jsx: <><h2 id="magic-wondrous-gloves_of_unexpected_violence_standard-gloves-of-unexpected-violence">Gloves of Unexpected Violence</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 247</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 8th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp (Standard), 30,000 gp (Expert); <strong>Weight</strong> -</p>
<p>This pair of nondescript gloves comes in a great variety of styles. Some are elegant, suitable for pairing with a tuxedo or evening gown. Others are rugged and fingerless, or appear medical in nature. The gloves, when worn, grant the wearer the Catch Off-Guard feat, even if the wearer doesn't qualify for it.</p>
<p>Expert gloves of unexpected violence also grant the Improvised Weapon Mastery feat.</p>
<h3 id="magic-wondrous-gloves_of_unexpected_violence_standard-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/catch_off_guard">Catch Off-Guard</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/improvised_weapon_mastery">Improvised Weapon Mastery</Link>; <strong>Cost</strong> 5,000 gp (Standard), 15,000 gp (Expert)</p>
</>};
const _gloves_of_unfolding_wind = {title: "Gloves of Unfolding Wind", jsx: <><h2 id="magic-wondrous-gloves_of_unfolding_wind-gloves-of-unfolding-wind">Gloves of Unfolding Wind</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These white fingerless gloves are decorated with a spiral on the back of the hand. For the purposes of resolving the effects of <Link to="/rule/winds">high winds</Link>, the wearer is treated as one size larger and his thrown weapons are treated as <Link to="/rule/siege_weapon">siege weapons</Link>. In addition, the wearer can spend 1 ki point to create a <em>gust of wind.</em></p>
<h3 id="magic-wondrous-gloves_of_unfolding_wind-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/gust_of_wind">gust of wind</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _glowing_glove = {title: "Glowing Glove", jsx: <><h2 id="magic-wondrous-glowing_glove-glowing-glove">Glowing Glove</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 305</Link><br/><strong>Aura</strong> faint universal; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,000 gp; <strong>Weight</strong> -</p>
<p>The wearer of this slender white leather glove may, as a standard action, press it against any surface or object and cause a luminous handprint to appear. This print glows any color the wearer wishes, sheds light as a <Link to="/eq-misc/candle">candle</Link>, and is easily visible from a distance of up to 60 feet. Such handprints last for 1 day before fading away. The glowing handprint matches the wearer's hand in terms of size, position of fingers, and so on.</p>
<h3 id="magic-wondrous-glowing_glove-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/arcane_mark">arcane mark</Link>; <strong>Cost</strong> 1,000 gp</p>
</>};
const _glyphbane_gloves = {title: "Glyphbane Gloves", jsx: <><h2 id="magic-wondrous-glyphbane_gloves-glyphbane-gloves">Glyphbane Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> -</p>
<p>These dark-brown, leather gloves are etched over their entire surface with arcane insignia. The wearer gains a +5 competence bonus on <Link to="/skill/disable_device">Disable Device</Link> checks made to disable magical traps. Once per day, if the wearer's check to disarm a <Link to="/main/spell_groupings">glyph, rune,</Link> or similar writing-based magical trap exceeds the DC by 10 or more, she may change the trigger condition of the trap instead of disabling it. The new trigger condition must be one allowed by the magical trap; for example, a <Link to="/spell/glyph_of_warding">glyph of warding</Link> cannot be set according to class, HD, or level, even when manipulated by the gloves.</p>
<h3 id="magic-wondrous-glyphbane_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/find_traps">find traps</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _grasp_of_droskar = {title: "Grasp of Droskar", jsx: <><h2 id="magic-wondrous-grasp_of_droskar-grasp-of-droskar">Grasp of Droskar</h2>
<p><strong>Sources</strong> <Link to="/source/crown_of_the_kobold_king">Crown of the Kobold King pg. 12</Link><br/><strong>Aura</strong> moderate transmutation and divination; <strong>CL</strong> 10th<br/><strong>Slot</strong> hands; <strong>Price</strong> 12,302 gp; <strong>Weight</strong> -</p>
<p>This left-handed black iron gauntlet appears little more than a dull soot-stained plated glove at first glance, but in truth it is a powerful boon granted by <Link to="/faith/droskar">Droskar</Link> to his most faithful subjects. Placing the glove on your left hand causes excruciating pain as your appendage curls into a tight fist and then slowly transforms to supernaturally hard black stone. You cannot use your left hand for anything beyond smashing it into objects or creatures (you cannot carry a shield or secondary weapon and you take a -4 on skill checks that usually require two hands). The gauntlet cannot be removed without a successful casting of <Link to="/spell/remove_curse">remove curse</Link>, <Link to="/spell/break_enchantment">break enchantment</Link>, or similar spell.</p>
<p>The gauntlet grants you a +2 enhancement bonus to Strength and acts as a +1 <Link to="/eq-material/adamantine">adamantine</Link> <Link to="/eq-weapon/gauntlet">gauntlet</Link>. The item also grants you the ability to use the gauntlet as a secondary <Link to="/rule/natural_weapon">natural weapon</Link>. In addition, the Grasp of Droskar allows its wearer to use <em>stone shape</em> once per day.</p>
<h3 id="magic-wondrous-grasp_of_droskar-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/magic_fang">magic fang</Link>, <Link to="/spell/stone_shape">stone shape</Link>; <strong>Cost</strong> 7,802 gp</p>
</>};
const _hand_of_hoarded_deaths = {title: "Hand of Hoarded Deaths", jsx: <><h2 id="magic-wondrous-hand_of_hoarded_deaths-hand-of-hoarded-deaths">Hand of Hoarded Deaths</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 31</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 25,000 gp; <strong>Weight</strong> -</p>
<p>The wearer of this single, black silk glove can use <em>death knell</em> on command. The target of <em>death knell</em> dies if it fails a DC 13 Fortitude save as normal, but the glove's wearer does not immediately benefit from the death; instead the siphoned life energy is stored inside the glove. The glove indefinitely holds a reservoir of up to five deaths. The wearer can tap into these deaths anytime thereafter by touching herself with the glove as a swift action, granting her <em>death knell's</em> benefits with a duration of 10 minutes. She can spend more than one death at a time, if she wishes. <Link to="/rule/temporary_hit_points">Temporary hit points</Link> from multiple deaths stack, but the bonuses to caster level and Strength do not. If multiple deaths are spent at the same time, add their durations together.</p>
<h3 id="magic-wondrous-hand_of_hoarded_deaths-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/death_knell">death knell</Link>, <Link to="/spell/false_life">false life</Link>; <strong>Cost</strong> 12,500 gp</p>
</>};
const _hand_wraps_of_blinding_ki = {title: "Hand Wraps of Blinding Ki", jsx: <><h2 id="magic-wondrous-hand_wraps_of_blinding_ki-hand-wraps-of-blinding-ki">Hand Wraps of Blinding Ki</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 30</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These fine silk wrappings - covered in mystic symbols and diagrams of the wearer's pressure points - wind around the wearer's hands and wrists. When the wearer spends ki to make an additional attack, he can spend 1 additional point of ki to use the <Link to="/feat/stunning_fist">Stunning Fist</Link> feat with the attack, even if he has already used the feat that round.</p>
<p>If the wearer is a monk using an archetype that replaces Stunning Fist with a different feat that's usable a number times per day equal to his monk level, hand wraps of blinding ki allow that feat to be used a second time instead of allowing him to use Stunning Fist.</p>
<h3 id="magic-wondrous-hand_wraps_of_blinding_ki-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, ki pool class ability; <strong>Cost</strong> 5,000 gp</p>
</>};
const _healers_gloves = {title: "Healer's Gloves", jsx: <><h2 id="magic-wondrous-healers_gloves-healers-gloves">Healer's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>These pure-white leather gloves bear symbols of healing and faith on the back of the hands. The wearer gains a +5 competence bonus on <Link to="/skill/heal">Heal</Link> checks.</p>
<h3 id="magic-wondrous-healers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must have 5 ranks in Heal; <strong>Cost</strong> 1,250 gp</p>
</>};
const _impact_gauntlets = {title: "Impact Gauntlets", jsx: <><h2 id="magic-wondrous-impact_gauntlets-impact-gauntlets">Impact Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,500 gp; <strong>Weight</strong> 1 lb.</p>
<p>These gauntlets are made of worn leather; the palms are smooth, but the wrists and backs of the gauntlets are covered in rough pebbles of various shapes and colors. The wearer can catch Small, Medium, or Large rocks and similar projectiles as if she possessed the <Link to="/umr/rock_catching">rock catching</Link> monster ability, as long as she has at least one hand free. A rock caught by the wearer shrinks and is permanently absorbed into the gauntlets. A wearer who also possesses the rock catching ability can catch rocks twice per round instead of once.</p>
<h3 id="magic-wondrous-impact_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shrink_item">shrink item</Link>; <strong>Cost</strong> 2,250 gp</p>
</>};
const _inescapable_gloves = {title: "Inescapable Gloves", jsx: <><h2 id="magic-wondrous-inescapable_gloves-inescapable-gloves">Inescapable Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 153</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>The palms of these light doeskin gloves are covered with supple ripples to augment the wearer's grip. The wearer gains a +4 competence bonus on combat maneuver checks to <Link to="/rule/grapple">grapple</Link>. The wearer can expend one use of mythic power when a creature subject to <Link to="/spell/freedom_of_movement">freedom of movement</Link> or a similar effect attempts to escape the wearer's grapple with a combat maneuver check or <Link to="/skill/escape_artist">Escape Artist</Link> check. That creature must attempt the check as normal instead of automatically succeeding at it. If a creature attempts use a non-mythic teleportation effect to escape the grapple, the wearer can expend two uses of mythic power to negate that effect.</p>
<h3 id="magic-wondrous-inescapable_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/dimensional_anchor">dimensional anchor</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _inheritors_gauntlet = {title: "Inheritor's Gauntlet", jsx: <><h2 id="magic-wondrous-inheritors_gauntlet-inheritors-gauntlet">Inheritor's Gauntlet</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 265</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 58</Link><br/><strong>Aura</strong> faint evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,700 gp; <strong>Weight</strong> 1 lb.</p>
<p>This metal gauntlet is the sort appropriate for wearing with <Link to="/eq-armor/chainmail">chainmail</Link>, though versions suited for <Link to="/eq-armor/leather">leather</Link> or <Link to="/eq-armor/full_plate">full plate</Link> exist. Affixed to the wrist is a white cloth with a longsword embroidered in gold thread. Once per day, the wearer can speak a command word to give a weapon the wearer holds in that hand (or the gauntlet itself) a +1 enhancement bonus on attack and damage rolls for 1 minute. An Inheritor's gauntlet uses up the wearer's entire hands slot; the wearer can not use another item (even another Inheritor's gauntlet) that also uses the hands slot, though a matching nonmagical gauntlet is often worn on the other hand.</p>
<p>If <Link to="/faith/iomedae">Iomedae</Link> is the wearer's patron, the gauntlet lets the wearer use any sword he holds in that hand as a holy symbol. Once per day, the wearer can speak a command word and give any sword he holds the powers of an evil outsider-<Link to="/magic-enh/bane">bane</Link> weapon for 1 minute; this effect ends if the wearer drops the sword or removes the gauntlet. If the wearer uses a finger to draw Iomedae's symbol on any solid surface, the symbol glows as brightly as a <Link to="/eq-misc/candle">candle</Link> for 1 hour or until the wearer draws the symbol elsewhere (whichever comes first).</p>
<h3 id="magic-wondrous-inheritors_gauntlet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/magic_weapon">magic weapon</Link>, <Link to="/spell/summon_monster_i">summon monster I</Link>; <strong>Cost</strong> 1,350 gp</p>
</>};
const _ioun_gauntlet = {title: "Ioun Gauntlet", jsx: <><h2 id="magic-wondrous-ioun_gauntlet-ioun-gauntlet">Ioun Gauntlet</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_122_into_the_shattered_continent">Pathfinder #122: Into the Shattered Continent pg. 23</Link><br/><strong>Aura</strong> faint divination and evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,600 gp; <strong>Weight</strong> 5 lbs.</p>
<p>Much like <Link to="/magic-wondrous/wayfinder">wayfinders</Link>, an ioun gauntlet grants enhanced or altogether new abilities depending on the type of <Link to="/magic-wondrous/ioun_stone">ioun stone</Link> inserted into its matrix. In its base form, an ioun gauntlet grants its wearer the ability to cast <em>detect magic</em> as a spell-like ability once per day. When the <em>detect magic</em> effect is active, the gauntlet also sheds illumination as <em>light</em> in the 60-foot cone of the <em>detect magic</em> effect.</p>
<p>An ioun gauntlet features a single matrix in the back of the hand, suitable for one ioun stone. When an ioun stone is inserted into the matrix as a standard action, the wearer gains the associated bonus from the ioun stone as well an additional effect based on the shape of the ioun stone inserted, as listed below. While a creature can put on two ioun gauntlets, the wearer gains the additional benefit from only one inserted ioun stone.</p>
<blockquote>
<p><strong className="hl">Cabochon:</strong> +1 enhancement bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks.</p>
<p><strong className="hl">Disk:</strong> +1 enhancement bonus on <Link to="/skill/linguistics">Linguistics</Link> checks.</p>
<p><strong className="hl">Ellipsoid:</strong> +1 enhancement bonus on <Link to="/skill/knowledge_arcana">Knowledge (arcana)</Link> checks.</p>
<p><strong className="hl">Nodule:</strong> +1 enhancement bonus on <Link to="/skill/knowledge_geography">Knowledge (geography)</Link> checks.</p>
<p><strong className="hl">Pentacle:</strong> +1 enhancement bonus on <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> checks.</p>
<p><strong className="hl">Prism:</strong> +1 enhancement bonus on <Link to="/skill/perception">Perception</Link> checks.</p>
<p><strong className="hl">Pyramid:</strong> +1 enhancement bonus on <Link to="/skill/appraise">Appraise</Link> checks.</p>
<p><strong className="hl">Rhomboid:</strong> +1 enhancement bonus on <Link to="/skill/stealth">Stealth</Link> checks.</p>
<p><strong className="hl">Sphere:</strong> +1 enhancement bonus on <Link to="/skill/sense_motive">Sense Motive</Link> checks.</p>
<p><strong className="hl">Spindle:</strong> Bonus language (Aboleth).</p>
<p><strong className="hl">Star:</strong> +1 enhancement bonus on <Link to="/skill/knowledge_nobility">Knowledge (nobility)</Link> checks.</p>
<p><strong className="hl">Trillian:</strong> +1 enhancement bonus on <Link to="/skill/bluff">Bluff</Link> checks.</p>
</blockquote>
<h3 id="magic-wondrous-ioun_gauntlet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/light">light</Link>; <strong>Cost</strong> 800 gp</p>
</>};
const _iron_cobra_gauntlet = {title: "Iron Cobra Gauntlet", jsx: <><h2 id="magic-wondrous-iron_cobra_gauntlet-iron-cobra-gauntlet">Iron Cobra Gauntlet</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 Lb.</p>
<p>This elbow-length scaled metal gauntlet flares at the wrist like a cobra's hood. Up to three times per day, the wearer way transform the gauntlet into an iron cobra, which crawls from the wearer's wrist and obeys his commands, leaving behind a simple bracelet of linked scales. Whoever wears the bracelet is the iron cobra's master. The iron cobra can remain animated for a total of 1 hour per day.</p>
<p>If the snake is within hearing range of the master and commanded to revert to gauntlet form (a standard action), it travels to its master as fast as possible, crawls onto its master's arm, and as a free action reverts to its inactive shape. If the snake's duration expires before it can reach its master, it reverts to gauntlet form, but automatically melds with the bracelet if the two touch.</p>
<p>If slain in cobra form, the snake reverts to gauntlet form and cannot be used again for 24 hours. If destroyed in gauntlet form, the item is destroyed. The wearer can refill the iron cobra's poison reservoir in snake form or gauntlet form.</p>
<h3 id="magic-wondrous-iron_cobra_gauntlet-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/discern_location">discern location</Link>, <Link to="/spell/geas_quest">geas/quest</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _irongrip_gauntlets = {title: "Irongrip Gauntlets", jsx: <><h2 id="magic-wondrous-irongrip_gauntlets-irongrip-gauntlets">Irongrip Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 69</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 2 lbs.</p>
<p>These gloves are made of goatskin reinforced with heavy iron strips. They provide a sure, strengthened grip on large or awkwardly shaped items. When the wearer wields an <Link to="/misc/improvised_weapon">improvised melee weapon</Link> or <Link to="/misc/inappropriately_sized_weapon">inappropriately sized weapon</Link>, reduce the penalty for doing so by 2 (minimum 0). The gloves don't change the number of hands required to wield such a weapon.</p>
<h3 id="magic-wondrous-irongrip_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>, <Link to="/spell/enlarge_person">enlarge person</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _kalistocrats_gloves = {title: "Kalistocrat's Gloves", jsx: <><h2 id="magic-wondrous-kalistocrats_gloves-kalistocrats-gloves">Kalistocrat's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 61</Link><br/><strong>Aura</strong> faint abjuration and evocation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,600 gp; <strong>Weight</strong> 1 lb.</p>
<p>Wealthy Kalistocrats wear these elegant, full-length white gloves. Twice per day as a move action, the wearer of these gloves can repel an unwanted creature for 1 minute or until the wearer touches another creature, whichever comes first. Any creature attempting to attack or touch the wearer during this time must succeed at a DC 11 Will save to do so (as the <em>sanctuary</em> spell).</p>
<p>Once per day, the wearer can summon a surge of invisible force to knock back a single target within 40 feet. The wearer attempts a combat maneuver check to <Link to="/rule/bull_rush">bull rush</Link> one creature or object with a +5 bonus. This bull rush combat maneuver doesn't provoke an attack of opportunity.</p>
<h3 id="magic-wondrous-kalistocrats_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/hydraulic_push">hydraulic push</Link>, <Link to="/spell/sanctuary">sanctuary</Link>; <strong>Cost</strong> 1,800 gp</p>
</>};
const _kleptomaniacs_gloves = {title: "Kleptomaniac's Gloves", jsx: <><h2 id="magic-wondrous-kleptomaniacs_gloves-kleptomaniacs-gloves">Kleptomaniac's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook pg. 31</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Weight</strong> 1 lb.</p>
<p>These simple calfskin gloves intensify the avaricious inclinations of their wearer. Kleptomaniac's gloves confer the same +5 competence bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks as <em>gloves of larceny,</em> but the first time the wearer attempts to take something from a given creature with a Sleight of Hand check, she must attempt another such check against that creature at the first available opportunity, whether or not the first attempt was successful. This increases the DC of the check by 10, as though the first attempt were a failure, and it imparts a -20 penalty on the check. Kleptomaniac's gloves can be removed only after the wearer benefits from a <Link to="/spell/remove_curse">remove curse</Link> spell or similar effect.</p>
<h3 id="magic-wondrous-kleptomaniacs_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/magic-wondrous/gloves_of_larceny">gloves of larceny</Link>; <strong>Cost</strong> -</p>
</>};
const _magnetists_gloves = {title: "Magnetist's Gloves", jsx: <><h2 id="magic-wondrous-magnetists_gloves-magnetists-gloves">Magnetist's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link><br/><strong>Aura</strong> faint conjuration; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 6,000 gp; <strong>Weight</strong> -</p>
<p>These thin leather gloves have delicate steel wires running through them. Three times per day as a standard action, the wearer of these gloves may attempt a <Link to="/rule/disarm">disarm</Link> combat maneuver on a target within 30 feet. The target's item must be mostly made of metal. If the combat maneuver check is successful, the target is disarmed and the item falls to the ground in the target's square. For every 5 by which the check exceeds the DC, the item lands 1 square closer to the wearer. If this would place the item in the wearer's square, the wearer may attempt to catch the item with a DC 10 Dexterity check; otherwise it lands in the wearer's square. The wearer can only use this ability if she has at least one hand free. If the wearer fails the combat maneuver check, she is not disarmed.</p>
<h3 id="magic-wondrous-magnetists_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 3,000 gp</p>
</>};
const _mantis_embrace = {title: "Mantis Embrace", jsx: <><h2 id="magic-wondrous-mantis_embrace-mantis-embrace">Mantis Embrace</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 159</Link>, <Link to="/source/agents_of_evil">Agents of Evil pg. 29</Link><br/><strong>Aura</strong> strong evocation and necromancy; <strong>CL</strong> 13th<br/><strong>Slot</strong> hands; <strong>Price</strong> 50,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These stylized red gloves are often employed by agents of the <Link to="/rule/red_mantis">Red Mantis</Link> for stealthy assassinations. If the wearer successfully <Link to="/rule/pin">pins</Link> an opponent with a <Link to="/rule/grapple">grapple</Link> combat maneuver, she can perform a special <Link to="/misc/coup_de_grace">coup de grace</Link> attack the next round with the gloves, treating them as if they were <Link to="/eq-weapon/sawtooth_sabre">sawtooth sabres</Link> (1d8 points of slashing damage, critical threat range of 19-20) for the purpose of this attack. Should the wearer of these gloves slay her opponent with this attack, the target's head erupts in a geyser of blood, preventing life-restoring spells that require an intact body. A creature that survives this <em>coup de grace</em> attack is immune to subsequent attempts from any mantis embrace for 24 hours.</p>
<h3 id="magic-wondrous-mantis_embrace-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/explode_head">explode head</Link>, <Link to="/spell/suffocation">suffocation</Link>; <strong>Cost</strong> 25,000 gp</p>
</>};
const _masterful_gray_gloves = {title: "Masterful Gray Gloves", jsx: <><h2 id="magic-wondrous-masterful_gray_gloves-masterful-gray-gloves">Masterful Gray Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 55</Link><br/><strong>Aura</strong> faint illusion; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,400 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These dark-gray leather gloves are extremely supple and are popular among the worshipers of <Link to="/faith/norgorber">Norgorber</Link>. They grant a +10 bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to take something from a creature unnoticed.</p>
<p>Additionally, three times per day, when a creature notices the wearer's Sleight of Hand check to take something from it, the wearer can cause the object to become invisible as an immediate action, allowing the wearer to disavow the theft.</p>
<h3 id="magic-wondrous-masterful_gray_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 2,700 gp</p>
</>};
const _perilous_gloves = {title: "Perilous Gloves", jsx: <><h2 id="magic-wondrous-perilous_gloves-perilous-gloves">Perilous Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 31</Link><br/><strong>Aura</strong> faint transmutation and necromancy; <strong>CL</strong> 1st<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These black gloves glow slightly during combat. Once per day, if the wearer's unarmed attack threatens a critical hit, the critical confirmation roll gains a +2 bonus. Regardless of whether the critical is confirmed, the attack does an additional 1d8 points of damage.</p>
<h3 id="magic-wondrous-perilous_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/inflict_light_wounds">inflict light wounds</Link>, <Link to="/spell/unerring_weapon">unerring weapon</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _pliant_gloves = {title: "Pliant Gloves", jsx: <><h2 id="magic-wondrous-pliant_gloves-pliant-gloves">Pliant Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 238</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> -</p>
<p>Wearing these form-fitting fingerless black gloves makes the wearer's arms and body more flexible. As a swift action, the wearer can lengthen his arms for up to 10 rounds per day, gaining an additional 5 feet of reach. These rounds need not be consecutive. Attacking with these extended arms is unwieldy, and the wearer takes a -2 penalty on attack rolls, increasing to -4 if he is using two-handed weapons. Even when his limbs aren't extended, the wearer gains a +5 enhancement bonus on <Link to="/skill/escape_artist">Escape Artist</Link> checks and <Link to="/skill/acrobatics">Acrobatics</Link> checks to avoid falling damage. The wearer is still able to use hand-based natural attacks such as claws while wearing the gloves.</p>
<h3 id="magic-wondrous-pliant_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/fluid_form">fluid form</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _poisoners_gloves = {title: "Poisoner's Gloves", jsx: <><h2 id="magic-wondrous-poisoners_gloves-poisoners-gloves">Poisoner's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 5,000 gp; <strong>Weight</strong> -</p>
<p>These black, rubbery gloves have sharpened digits. Fine channels lead to the tip of each finger, which are often stained with foul chemicals. The gloves are used primarily by <Link to="/pclass/assassin">assassins</Link> to deliver poisons while in combat. Each glove may be filled with a single dose of poison, a potion, alchemist <Link to="/discovery/infusion">infusion</Link>, <Link to="/eq-weapon/holy_water">holy water</Link>, or similar liquid as long as the liquid would not harm the gloves (for example, <Link to="/eq-weapon/alchemists_fire">alchemist's fire</Link> and <Link to="/eq-weapon/acid">acid</Link> cannot be used). The wearer can deliver the dose to a target as a melee touch attack or as part of an unarmed strike or natural attack with the hands (such as a claw or slam attack). In the case of a personal infused extract, the opponent receives both a Fortitude save and spell resistance. The wearer can use both gloves in the same round using <Link to="/rule/two_weapon_fighting">two-weapon fighting</Link> or multiple <Link to="/rule/natural_attacks">natural attacks</Link> (such as 2 slams or 2 claws). Each glove can be used once per day. Filling a glove is a full-round action that provokes attacks of opportunity.</p>
<h3 id="magic-wondrous-poisoners_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/touch_injection">touch injection</Link>; <strong>Cost</strong> 2,500 gp</p>
</>};
const _quickfingers_gloves = {title: "Quickfingers Gloves", jsx: <><h2 id="magic-wondrous-quickfingers_gloves-quickfingers-gloves">Quickfingers Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 67</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>These dark-colored, skin-tight gloves are typically made of either supple calfskin or silk. A wearer of these gloves with at least 1 rank in <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> can perform such a check as a move action by taking a -10 penalty on the check rather than the normal -20. Both gloves must be worn for the magic to be effective.</p>
<h3 id="magic-wondrous-quickfingers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/cats_grace">cat's grace</Link>, <Link to="/spell/haste">haste</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _quicksilver_gloves = {title: "Quicksilver Gloves", jsx: <><h2 id="magic-wondrous-quicksilver_gloves-quicksilver-gloves">Quicksilver Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 62</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 7,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These tight-fitting gloves have silver tips at the end of each finger. When worn, the silver spreads to cover the gloves so they appear to be covered in liquid metal.</p>
<p>As a swift action, the wearer can command the gloves to coat a held weapon with silver. The affected weapon is treated as silver for the purpose of overcoming damage reduction. The effect can be applied only to light or one-handed weapons made primarily of metal. This ability can be used for up to 10 rounds each day, though these rounds need not be consecutive.</p>
<p>Once per day, the gloves' wearer can make an extra attack with a melee weapon as if using a <Link to="/magic-enh/speed">speed</Link> weapon. This benefit does not stack with similar effects, such as a <em>haste</em> spell.</p>
<h3 id="magic-wondrous-quicksilver_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/haste">haste</Link>, <Link to="/spell/versatile_weapon">versatile weapon</Link>; <strong>Cost</strong> 3,500 gp</p>
</>};
const _ratcheting_gauntlets = {title: "Ratcheting Gauntlets", jsx: <><h2 id="magic-wondrous-ratcheting_gauntlets-ratcheting-gauntlets">Ratcheting Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 29</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 12,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>This set of <Link to="/eq-material/cold_iron">cold iron</Link> gauntlets has pistons, gears, and hinges connecting all the joints and plates. As a swift action, the wearer can command one or both of the gauntlets to lock into position or unlock and move normally. If a gauntlet locks while holding a weapon, it acts as a <Link to="/eq-armorenh/locked_gauntlet">locked gauntlet</Link>, providing the wearer a +10 bonus to his Combat Maneuver Defense against being <Link to="/rule/disarm">disarmed</Link>. Locking the gauntlets also grants the wearer a +4 bonus on combat maneuver checks to pin a <Link to="/rule/grapple">grappled</Link> foe and <Link to="/skill/climb">Climb</Link> checks to catch himself while falling. They can also allow other uses at the GM's discretion, such as hanging from a ledge or similar position without having to attempt a Climb check or becoming <Link to="/misc/fatigued">fatigued</Link>.</p>
<h3 id="magic-wondrous-ratcheting_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bears_endurance">bear's endurance</Link>, <Link to="/spell/bulls_strength">bull's strength</Link>; <strong>Cost</strong> 6,000 gp</p>
</>};
const _raven_bracers = {title: "Raven Bracers", jsx: <><h2 id="magic-wondrous-raven_bracers-raven-bracers">Raven Bracers</h2>
<p><strong>Sources</strong> <Link to="/source/dungeons_of_golarion">Dungeons of Golarion pg. 62</Link><br/><strong>Aura</strong> moderate divination and transmutation; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 16,600 gp; <strong>Weight</strong> 4 lbs.</p>
<p>This pair of magnificent dark metal bracers is forged to depict the shape of a raven stretched over the wearer's forearm. Once prized by the last king of Zolurket, several additional raven bracers were created in the mines' final days to aid the king's bodyguards in defending him and maintaining communications throughout the mine.</p>
<p>While worn, these bracers can be used as a swift action to grant the <Link to="/magic-enh/throwing">throwing</Link> and <Link to="/magic-enh/returning">returning</Link> magic weapon qualities to any held melee weapon; these qualities persist for 1 round. This ability can be used three times a day.</p>
<p>In addition, the bracers may be removed and tossed into the air as a standard action, where they transform into a pair of identical black metallic ravens similar to <Link to="/magic-wondrous/silver_raven_figurine_of_wondrous_power">silver raven figurines of wondrous power</Link>. Like those items, these ravens obey the wearer, and may each bear a message as if affected by the <em>animal messenger</em> spell. The ravens can only take this shape once per week, retaining the form continuously for up to 24 hours.</p>
<p>Once both of these ravens have delivered their messages (or once the 24-hour limt is reached), they both vanish in a cloud of smoke and return unerringly to the owner's hands via teleportation. If the item's owner is no longer on the same plane as the bracers when this event occurs, they merely revert to bracer form and fall to the ground, awaiting a new owner to find and claim them for their own use.</p>
<h3 id="magic-wondrous-raven_bracers-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/animal_messenger">animal messenger</Link>, <Link to="/spell/animate_objects">animate objects</Link>, <Link to="/spell/teleport_object">teleport object</Link>, <Link to="/spell/telekinesis">telekinesis</Link>; <strong>Cost</strong> 8,300 gp</p>
</>};
const _rimeshaper_gloves = {title: "Rimeshaper Gloves", jsx: <><h2 id="magic-wondrous-rimeshaper_gloves-rimeshaper-gloves">Rimeshaper Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 13</Link><br/><strong>Aura</strong> faint abjuration and transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 3,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These sleek gloves bear a faint scaled pattern and shimmer slightly, as if they were covered in ice crystals. While in cold or colder weather, rimeshaper gloves allow the wearer to solidify nearby snow or ice into a light or one-handed weapon of normal quality with a hardness of 2. Creating such a weapon takes the same amount of time that it would take to draw it from a sheath - a move action for most, but faster for a wearer with the <Link to="/feat/quick_draw">Quick Draw</Link> feat or a similar ability, for example. These weapons evaporate if left unattended for 1 round; otherwise, they last for 1 minute, after which they melt into pure liquid. Alternatively, as a move action, the wearer can cause actual ice crystals to form over the gloves, causing them to act as <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-weapon/spiked_gauntlet">spiked gauntlets</Link> that also grant a +2 competence bonus on <Link to="/skill/climb">Climb</Link> checks. This effect lasts until it is dismissed as a standard action. Finally, the gloves grant the wearer cold resistance 5.</p>
<h3 id="magic-wondrous-rimeshaper_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/resist_energy">resist energy</Link>, <Link to="/spell/chill_metal">chill metal</Link> or <Link to="/spell/icicle_dagger">icicle dagger</Link>; <strong>Cost</strong> 1,500 gp</p>
</>};
const _rubble_gloves = {title: "Rubble Gloves", jsx: <><h2 id="magic-wondrous-rubble_gloves-rubble-gloves">Rubble Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 137</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These gloves are made of a fine metal mesh. If a creature wearing rubble gloves touches a 5-foot square of stone or earth floor, rubble roils to the surface, making the square <Link to="/rule/difficult_terrain">difficult terrain</Link>. Using the gloves is a standard action that does not provoke attacks of opportunity. The wearer can use the gloves to create up to 20 squares of difficult terrain per day.</p>
<h3 id="magic-wondrous-rubble_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/expeditious_excavation">expeditious excavation</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _saboteurs_gloves = {title: "Saboteur's Gloves", jsx: <><h2 id="magic-wondrous-saboteurs_gloves-saboteurs-gloves">Saboteur's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 55</Link><br/><strong>Aura</strong> moderate abjuration; <strong>CL</strong> 8th<br/><strong>Slot</strong> hands; <strong>Price</strong> 15,240 gp; <strong>Weight</strong> 1/2 lb.</p>
<p>These gloves of thick leather do not impair delicate work and grant a +4 competence bonus on <Link to="/skill/disable_device">Disable Device</Link> checks to disable magic traps. Once per day, a wearer trained in Disable Device can command the gloves to alter an unattended magic item she touches to incorporate a trap. The wearer attempts a caster level check using the higher of her caster level or the gloves' caster level (DC = 11 + the target item's caster level). If the check is successful, the target item is marked with a <em>glyph of warding</em> (blast glyph only) that lasts for up to 1 day.</p>
<h3 id="magic-wondrous-saboteurs_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/glyph_of_warding">glyph of warding</Link>; <strong>Cost</strong> 7,620 gp</p>
</>};
const _shadow_falconers_glove = {title: "Shadow Falconer's Glove", jsx: <><h2 id="magic-wondrous-shadow_falconers_glove-shadow-falconers-glove">Shadow Falconer's Glove</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link><br/><strong>Aura</strong> moderate conjuration; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>This elbow-length, heavy leather glove's fine embroidery is marred by dozens of claw marks. Once per day on command, its wearer can gesture toward a creature within 30 feet. When he does, a featureless silhouette of a bird of prey appears, swoops toward the target, and performs a <Link to="/rule/disarm">disarm</Link> or <Link to="/rule/steal">steal</Link> combat maneuver (wearer's choice, CMB +16). The shadow falcon is a magical effect, not a creature, and this action does not provoke attacks of opportunity. If the hand wearing the glove is empty, the shadow falcon brings the item to the wearer's hand. If the gloved hand is occupied, the shadow falcon deposits the item on the ground in an unoccupied space adjacent to the wearer. The shadow falcon then disappears.</p>
<h3 id="magic-wondrous-shadow_falconers_glove-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/shadow_conjuration">shadow conjuration</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _skullcrusher_gauntlets = {title: "Skullcrusher Gauntlets", jsx: <><h2 id="magic-wondrous-skullcrusher_gauntlets-skullcrusher-gauntlets">Skullcrusher Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 235</Link><br/><strong>Aura</strong> moderate evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> hands; <strong>Price</strong> 15,302 gp; <strong>Weight</strong> 6 lbs.</p>
<p>These bloodstained gauntlets are made of a combination of blackened steel and polished white stone. They are slightly oversized and somewhat bulky, though still suitable for combat. They function as +1 <Link to="/eq-weapon/gauntlet">gauntlets</Link>.</p>
<p>Once per day, the wearer can unleash a devastating attack with the gauntlets that can instantly knock a target unconscious. The wearer must announce her intent before making her attack roll, and creatures immune to critical hits can't be affected. To make the attack, the wearer makes a single melee attack at her highest base attack bonus as a full-round action. If the strike hits, the target takes 4d6 points of force damage and must succeed at a DC 15 Fortitude save or fall <Link to="/misc/unconscious">unconscious</Link> until the end of its next turn. Even if the target succeeds at the Fortitude save, it is <Link to="/misc/staggered">staggered</Link> until the end of its next turn.</p>
<p>When worn by a <Link to="/class/brawler">brawler</Link> with the knockout class feature, the DC to resist the brawler's knockout increases by 2.</p>
<h3 id="magic-wondrous-skullcrusher_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/deep_slumber">deep slumber</Link>, <Link to="/spell/stone_fist">stone fist</Link>; <strong>Cost</strong> 7,802 gp</p>
</>};
const _spellstrike_gloves = {title: "Spellstrike Gloves", jsx: <><h2 id="magic-wondrous-spellstrike_gloves-spellstrike-gloves">Spellstrike Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link><br/><strong>Aura</strong> strong (no school); <strong>CL</strong> 17th<br/><strong>Slot</strong> hands; <strong>Price</strong> 8,000 gp; <strong>Weight</strong> -</p>
<p>These black leather gloves are lined with soft black velveteen and have silver buckles that run from the wrist to the elbow. Three times per day, the gloves allow the wearer to treat a ranged magus spell as a spell with a range of "touch," allowing him to deliver the spell with his spellstrike ability. The glove can only affect spells that normally affect one or more creatures at a range greater than "touch" (such as <Link to="/spell/slow">slow</Link>), not rays or other created effects. The altered spell only affects the creature attacked (any other targets normally allowed by the spell are lost).</p>
<h3 id="magic-wondrous-spellstrike_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, creator must be a <Link to="/class/magus">magus</Link>; <strong>Cost</strong> 4,000 gp</p>
</>};
const _stonefist_gloves = {title: "Stonefist Gloves", jsx: <><h2 id="magic-wondrous-stonefist_gloves-stonefist-gloves">Stonefist Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 157</Link><br/><strong>Aura</strong> moderate transmutation; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 10,000 gp; <strong>Weight</strong> 3 lbs.</p>
<p>These heavy, stone gloves feel surprisingly supple to anyone who puts them on. While a creature wears stonefist gloves, his <Link to="/rule/melee_and_ranged_attacks">unarmed strike damage</Link> is treated as if he were <Link to="/misc/one_size_category_larger">one size category larger</Link>, and bypasses hardness of 8 or lower. When a mythic creature uses these gloves to make a <Link to="/rule/sunder">sunder</Link> combat maneuver, he adds half his tier as a bonus on the combat maneuver check.</p>
<h3 id="magic-wondrous-stonefist_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/stoneskin">stoneskin</Link>; <strong>Cost</strong> 5,000 gp</p>
</>};
const _stormcrusher_gauntlets = {title: "Stormcrusher Gauntlets", jsx: <><h2 id="magic-wondrous-stormcrusher_gauntlets-stormcrusher-gauntlets">Stormcrusher Gauntlets</h2>
<p><strong>Sources</strong> <Link to="/source/daughters_of_fury">Daughters of Fury pg. 63</Link><br/><strong>Aura</strong> moderate abjuration and evocation; <strong>CL</strong> 10th<br/><strong>Slot</strong> hands; <strong>Price</strong> 45,000 gp; <strong>Weight</strong> 5 lbs.</p>
<p>These speckled metal gauntlets provide a noticeable prickling sensation when donned. Three times per day when the wearer would take electricity damage, she can attempt a Strength check as an immediate action to catch the electricity and crush it into harmless sparks that deal no damage (DC = 10 + 1 per 10 points of damage).</p>
<p>If the wearer possesses mythic tiers, she can also expend one use of her mythic power to reshape the crushed lightning into a variety of forms: blasts of electric force, blinding showers of sparks, or even lassos. This allows the wearer to perform a bull rush, dirty trick, grapple, reposition, or trip combat maneuver on her next turn against any opponent within range (10 feet per mythic tier she possesses). If the wearer succeeds at this combat maneuver check, her opponent also takes an amount of electricity damage equal to the wearer's combat maneuver check result (up to a maximum of the original electricity effect's damage). Creatures immune to electricity damage are immune to this ability. If the wearer expends the mythic power but doesn't attempt to use the crushed lightning by her next turn, the energy surges out, dealing the original effect's electricity damage to the wearer with no save granted.</p>
<h3 id="magic-wondrous-stormcrusher_gauntlets-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/feat/mythic_crafter">Mythic Crafter</Link>, <Link to="/spell/lightning_bolt">lightning bolt</Link>, <Link to="/spell/shock_shield">shock shield</Link>; <strong>Cost</strong> 22,500 gp</p>
</>};
const _swindlers_gloves = {title: "Swindler's Gloves", jsx: <><h2 id="magic-wondrous-swindlers_gloves-swindlers-gloves">Swindler's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/seers_of_the_drowned_city">Seers of the Drowned City pg. 55</Link><br/><strong>Aura</strong> moderate illusion; <strong>CL</strong> 9th<br/><strong>Slot</strong> hands; <strong>Price</strong> 9,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>When the wearer of these jet-black leather gloves reaches for an item carried by another creature, inky strands of gloom swirl around the gloves, making the wearer's hand movements difficult to follow. The wearer does not provoke an attack of opportunity when attempting a <Link to="/rule/disarm">disarm</Link> or <Link to="/rule/steal">steal</Link> combat maneuver check while wearing a pair of swindler's gloves. She also ignores the penalty on her combat maneuver check for attempting to disarm a foe while she is unarmed.</p>
<p>Once per day as a swift action, upon using the swindler's gloves to steal from or disarm a foe, the wearer can activate an illusion that causes the enemy to believe the maneuver failed. The item taken via the maneuver becomes invisible and an illusory duplicate of the item appears in the target's possession for 1 minute. This illusory item looks and feels like the original, but the target can attempt a DC 14 Will saving throw to realize the item he now holds is an illusory duplicate. In any event, when the user drops the item or attempts to use it, the shadow item fades away into shadows and is gone. The illusory duplicate is a shadow effect.</p>
<h3 id="magic-wondrous-swindlers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/darkness">darkness</Link>, <Link to="/spell/invisibility">invisibility</Link>; <strong>Cost</strong> 4,500 gp</p>
</>};
const _talons_of_leng = {title: "Talons of Leng", jsx: <><h2 id="magic-wondrous-talons_of_leng-talons-of-leng">Talons of Leng</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link>, <Link to="/source/pathfinder_6_spires_of_xin_shalast">Pathfinder #6: Spires of Xin-Shalast pg. 65</Link>, <Link to="/source/rise_of_the_runelords_anniversary_edition">Rise of the Runelords Anniversary Edition pg. 427</Link><br/><strong>Aura</strong> strong transmutation; <strong>CL</strong> 15th<br/><strong>Slot</strong> hands; <strong>Price</strong> 67,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>Finely laid gold filigree lines these ornately worked talons. Once donned, the talons of Leng grant the wearer a natural claw attack with each hand that deal 1d4 points of damage for a Medium wearer, or 1d3 points of damage for a Small wearer. These claw attacks have a +3 enhancement bonus on attack and damage rolls. On a critical hit, the target must succeed at a DC 20 Will save or become permanently confused as per the <em>insanity</em> spell. This is a mind-affecting effect.</p>
<p>The wearer of the talons of Leng is immune to effects that grant the <Link to="/misc/confused">confused</Link> condition. For as long as she wears the talons, however, her Wisdom is reduced by 2, as alien voices constantly whisper through her head. The talons of Leng do not interfere with spellcasting, the use of handheld items, or wielding weapons.</p>
<h3 id="magic-wondrous-talons_of_leng-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_magic_arms_and_armor">Craft Magic Arms and Armor</Link>, <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/greater_magic_fang">greater magic fang</Link>, <Link to="/spell/insanity">insanity</Link>; <strong>Cost</strong> 33,500 gp</p>
</>};
const _touch_of_avolition = {title: "Touch of Avolition", jsx: <><h2 id="magic-wondrous-touch_of_avolition-touch-of-avolition">Touch of Avolition</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_88_valley_of_the_brain_collectors">Pathfinder #88: Valley of the Brain Collectors pg. 63</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 7th<br/><strong>Slot</strong> hands; <strong>Price</strong> 2,500 gp; <strong>Weight</strong> -</p>
<p>This thin disk of woven material is 2-1/2 inches in diameter. From its edges protrude fine, hair-like fibers about half an inch long. A touch of avolition is in fact an example of <Link to="/monster/mi_go">mi-go</Link> technology - as much fungus as anything else. Creatures like mi-go can handle a touch of avolition with ease, but humanoids and other fleshy users must wear gloves to avoid becoming the target of the item's effect. Applying a touch of avolition requires a successful touch attack. When placed against flesh (any living, corporeal, non-plant or non-ooze creature), a touch of avolition's fibers swiftly merge with the target unless the creature succeeds at a DC 15 Fortitude save. On a failed save, the victim becomes <Link to="/rule/paralyzed">paralyzed</Link> for 7 rounds. It can attempt a new Fortitude as a standard action after the first round to end the effect early.</p>
<p>Once a victim recovers from the paralysis effect, the touch of avolition saps the user's willpower and dulls the senses, making creatures under these effects easier to mentally manipulate. The victim's Wisdom is reduced by 6 (minimum 1) as long as the touch of avolition remains attached. The fungal filaments of a touch of avolition dig deep, and merely ripping the patch free from the skin doesn't remove this Wisdom penalty, though the removal itself deals 1d4 points of damage to the victim. The effect is a curse effect, and it (and the paralysis) can be removed as such via <Link to="/spell/remove_curse">remove curse</Link> or similar spells.</p>
<p>A touch of avolition works best when damp. The save DC to resist a dry touch of avolition is 10, its paralysis effect lasts for only 2 rounds, and its Wisdom penalty is reduced to 2. The effects of multiple touches of avolition do not stack.</p>
<h3 id="magic-wondrous-touch_of_avolition-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bestow_curse">bestow curse</Link>, <Link to="/spell/hold_person">hold person</Link>; <strong>Cost</strong> 1,250 gp</p>
</>};
const _trapspringers_gloves = {title: "Trapspringer's Gloves", jsx: <><h2 id="magic-wondrous-trapspringers_gloves-trapspringers-gloves">Trapspringer's Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 54</Link><br/><strong>Aura</strong> faint divination; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 4,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These studded leather gloves look similar to workman's gloves, though they are reinforced with numerous metal strips that the user can extend or retract as she wills, turning the tip of each finger into a customizable tool useful in examining and disarming traps. While worn, these gloves grant a +5 competence bonus on all <Link to="/skill/disable_device">Disable Device</Link> checks made to disarm traps. In addition, the gloves grant the user a +1 luck bonus on all saving throws made against traps.</p>
<h3 id="magic-wondrous-trapspringers_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/find_traps">find traps</Link>; <strong>Cost</strong> 2,000 gp</p>
</>};
const _vampiric_gloves = {title: "Vampiric Gloves", jsx: <><h2 id="magic-wondrous-vampiric_gloves-vampiric-gloves">Vampiric Gloves</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 239</Link><br/><strong>Aura</strong> moderate necromancy; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 18,000 gp; <strong>Weight</strong> -</p>
<p>These pale, elegant-looking leather gloves have blood red stitching on the fingers - which bears a startling resemblance to blood-encrusted fingernails. Three times per day, the wearer can use <em>vampiric touch</em> and <em>bleed.</em> If the wearer uses <em>vampiric touch</em> and holds the charge, the charge dissipates if the gloves are removed.</p>
<p>Though <em>vampiric touch</em> is normally a touch attack, the wearer may instead use that ability as a ranged touch attack with a range of 30 feet, but only against a <Link to="/misc/dying">dying</Link> target or a target suffering from a <Link to="/rule/bleed">bleed</Link> effect. When using <em>vampiric touch</em> in this way, the wearer may hold the charge on a missed ranged touch attack.</p>
<p>If the wearer is suffering from a bleed effect, he may expend one use of <em>vampiric touch</em> to end the bleed effect.</p>
<h3 id="magic-wondrous-vampiric_gloves-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/bleed">bleed</Link>, <Link to="/spell/vampiric_touch">vampiric touch</Link>; <strong>Cost</strong> 9,000 gp</p>
</>};
const _whispering_gloves_lotfw = {title: "Whispering Gloves (LotFW)", jsx: <><h2 id="magic-wondrous-whispering_gloves_lotfw-whispering-gloves-lotfw">Whispering Gloves (LotFW)</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 27</Link><br/><strong>Aura</strong> faint transmutation; <strong>CL</strong> 3rd<br/><strong>Slot</strong> hands; <strong>Price</strong> 1,000 gp; <strong>Weight</strong> 1 lb.</p>
<p>These supple silk gloves are skintight. As a standard action, the wearer can deliver a complex secret message to a single target that can see the wearer as if she had succeeded at a DC 20 <Link to="/skill/bluff">Bluff</Link> check. This message is conveyed in a series of rapid, complicated hand gestures that the target automatically understands. Creatures that see the wearer send a message can attempt a DC 20 <Link to="/skill/sense_motive">Sense Motive</Link> check to notice that the wearer is delivering a secret message and decipher it.</p>
<h3 id="magic-wondrous-whispering_gloves_lotfw-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/message">message</Link>; <strong>Cost</strong> 500 gp</p>
</>};
const _whispering_gloves_tobm = {title: "Whispering Gloves (ToBM)", jsx: <><h2 id="magic-wondrous-whispering_gloves_tobm-whispering-gloves-tobm">Whispering Gloves (ToBM)</h2>
<p><strong>Sources</strong> <Link to="/source/tears_at_bitter_manor">Tears at Bitter Manor pg. 55</Link><br/><strong>Aura</strong> faint illusion and transmutation; <strong>CL</strong> 5th<br/><strong>Slot</strong> hands; <strong>Price</strong> 15,400 gp; <strong>Weight</strong> -</p>
<p>These gloves constantly project a very short-range <em>silence</em> spell, so that anything touched or held by the wearer's hands makes no sound. Thus picking a locked door wouldn't make a clicking noise audible to those on the other side, and holding a hand over a victim's mouth would silence his scream. The silence extends only a few inches, so knocking on a door produces no sound but hammering it down still does.</p>
<p>If the wearer presses a finger to her lips and speaks, no sound comes out, but the words are audible to anyone she chooses in her line of sight (as the <em>message</em> spell).</p>
<h3 id="magic-wondrous-whispering_gloves_tobm-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/message">message</Link>, <Link to="/spell/silence">silence</Link>; <strong>Cost</strong> 7,700 gp</p>
</>};
const _sniper_goggles_greater = {..._sniper_goggles, title: "Sniper Goggles (Greater)"};
